-- Poems batch 469
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-43','古別離','陸龜蒙','唐','御定全唐诗','yuding','','[]','仙人左手把長箭，欲射日烏烏不棲。',32,'御定全唐詩/json/629.json','["仙人左手把長箭，欲射日烏烏不棲。", "何事離情畏明發，一心唯恨汝南雞。"]'),
('yuding-44','高道士','陸龜蒙','唐','御定全唐诗','yuding','','[]','峨眉道士風骨峻，手把玉皇書一通。',32,'御定全唐詩/json/629.json','["峨眉道士風骨峻，手把玉皇書一通。", "東游借得琴高鯉，騎入蓬萊清淺中。"]'),
('yuding-45','蔬食','陸龜蒙','唐','御定全唐诗','yuding','','[]','孔融不要留殘膾，庾悅無端吝子鵝。',32,'御定全唐詩/json/629.json','["孔融不要留殘膾，庾悅無端吝子鵝。", "香稻熟來秋菜嫩，伴僧餐了聽雲和。"]'),
('yuding-46','寄遠','陸龜蒙','唐','御定全唐诗','yuding','','[]','縹梨花謝鶯口吃，黃犢少年人未歸。',32,'御定全唐詩/json/629.json','["縹梨花謝鶯口吃，黃犢少年人未歸。", "畫扇紅弦相掩映，獨看斜月下簾衣。"]'),
('yuding-47','山中僧','陸龜蒙','唐','御定全唐诗','yuding','','[]','手關一室翠微裏，日暮白雲棲半間。',32,'御定全唐詩/json/629.json','["手關一室翠微裏，日暮白雲棲半間。", "白雲朝出天際去，若比老僧猶未閑。"]'),
('yuding-48','洞宮秋夕','陸龜蒙','唐','御定全唐诗','yuding','','[]','濃霜打葉落地聲，南溪石泉細泠泠。',32,'御定全唐詩/json/629.json','["濃霜打葉落地聲，南溪石泉細泠泠。", "洞宮寂寞人不去，坐見月生雲母屏。"]'),
('yuding-49','連昌宮詞二首：門','陸龜蒙','唐','御定全唐诗','yuding','','[]','金鋪零落獸鐶空，斜掩雙扉細草中。',32,'御定全唐詩/json/629.json','["金鋪零落獸鐶空，斜掩雙扉細草中。", "日暮鳥歸宮樹綠，不聞鴉軋閉春風。"]'),
('yuding-50','連昌宮詞二首：階','陸龜蒙','唐','御定全唐诗','yuding','','[]','草沒苔封疊翠斜，墜紅千葉擁殘霞。',32,'御定全唐詩/json/629.json','["草沒苔封疊翠斜，墜紅千葉擁殘霞。", "年年直為秋霖苦，滴陷青瑉隱起花。"]'),
('yuding-51','懷宛陵舊游','陸龜蒙','唐','御定全唐诗','yuding','','[]','陵陽佳地昔年游，謝脁青山李白樓。',32,'御定全唐詩/json/629.json','["陵陽佳地昔年游，謝脁青山李白樓。", "唯有日斜溪上思，酒旗風影落春流。"]'),
('yuding-52','松石曉景圖','陸龜蒙','唐','御定全唐诗','yuding','','[]','霜骨雲根慘澹愁，宿煙封著未全收。',32,'御定全唐詩/json/629.json','["霜骨雲根慘澹愁，宿煙封著未全收。", "將歸與說文通後，寫得松江岸上秋。"]'),
('yuding-53','釣車','陸龜蒙','唐','御定全唐诗','yuding','','[]','小輪輕線妙無雙，曾伴幽人酒一缸。',32,'御定全唐詩/json/629.json','["小輪輕線妙無雙，曾伴幽人酒一缸。", "洛客見詩如有問，輾煙沖雨過桐江。"]'),
('yuding-54','漉酒巾','陸龜蒙','唐','御定全唐诗','yuding','','[]','靖節高風不可攀，此巾猶墜凍醪間。',32,'御定全唐詩/json/629.json','["靖節高風不可攀，此巾猶墜凍醪間。", "偏宜雪夜山中戴，認取時情與醉顏。"]'),
('yuding-55','華陽巾','陸龜蒙','唐','御定全唐诗','yuding','','[]','蓮花峰下得佳名，雲褐相兼上鶴翎。',32,'御定全唐詩/json/629.json','["蓮花峰下得佳名，雲褐相兼上鶴翎。", "須是古壇秋霽後，靜焚香炷禮寒星。"]'),
('yuding-56','方響','陸龜蒙','唐','御定全唐诗','yuding','','[]','擊霜寒玉亂丁丁，花底秋風拂坐生。',32,'御定全唐詩/json/629.json','["擊霜寒玉亂丁丁，花底秋風拂坐生。", "王母閑看漢天子，滿猗蘭殿佩環聲。"]'),
('yuding-57','白鷺','陸龜蒙','唐','御定全唐诗','yuding','','[]','雪然飛下立蒼苔，應伴江鷗拒我來。',32,'御定全唐詩/json/629.json','["雪然飛下立蒼苔，應伴江鷗拒我來。", "見欲扁舟搖盪去，倩君先作水雲媒。"]'),
('yuding-58','溪行','陸龜蒙','唐','御定全唐诗','yuding','','[]','晚天寒雨上灘時，他已揚舲我尚遲。',32,'御定全唐詩/json/629.json','["晚天寒雨上灘時，他已揚舲我尚遲。", "自是檣低帆幅少，溪風終不兩般吹。"]'),
('yuding-59','太湖叟','陸龜蒙','唐','御定全唐诗','yuding','','[]','細槳輕船賣石歸，酒痕狼藉遍苔衣。',32,'御定全唐詩/json/629.json','["細槳輕船賣石歸，酒痕狼藉遍苔衣。", "攻車戰艦繁如織，不肯回頭問是非。"]'),
('yuding-60','答友人','陸龜蒙','唐','御定全唐诗','yuding','','[]','荊卿雄骨化為塵，燕市應無共飲人。',32,'御定全唐詩/json/629.json','["荊卿雄骨化為塵，燕市應無共飲人。", "能脫鷫鸘來換酒，五湖賒與一年春。"]'),
('yuding-61','偶作','陸龜蒙','唐','御定全唐诗','yuding','','[]','酒信巧為繰病緒，花音長作嫁愁媒。',32,'御定全唐詩/json/629.json','["酒信巧為繰病緒，花音長作嫁愁媒。", "也知愁病堪回避，爭奈流鶯喚起來。"]'),
('yuding-62','春思二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','竹外麥煙愁漠漠，短翅啼禽飛魄魄。',64,'御定全唐詩/json/629.json','["竹外麥煙愁漠漠，短翅啼禽飛魄魄。", "此時憶著千里人，獨坐支頤看花落。", "江南酒熟清明天，高高綠旆當風懸。", "誰家無事少年子，滿面落花猶醉眠。"]'),
('yuding-63','訪僧不遇','陸龜蒙','唐','御定全唐诗','yuding','','[]','棹倚東林欲問禪，遠公飛錫未應還。',32,'御定全唐詩/json/629.json','["棹倚東林欲問禪，遠公飛錫未應還。", "蒙莊弟子相看笑，何事空門亦有關。"]'),
('yuding-64','謝山泉','陸龜蒙','唐','御定全唐诗','yuding','','[]','決決春泉出洞霞，石壇封寄野人家。',32,'御定全唐詩/json/629.json','["決決春泉出洞霞，石壇封寄野人家。", "草堂盡日留僧坐，自向前溪摘茗芽。"]'),
('yuding-65','洞宮夕','陸龜蒙','唐','御定全唐诗','yuding','','[]','月午山空桂花落，華陽道士雲衣薄。',32,'御定全唐詩/json/629.json','["月午山空桂花落，華陽道士雲衣薄。", "石壇香散步虛聲，杉雲清泠滴棲鶴。"]'),
('yuding-66','峽客行','陸龜蒙','唐','御定全唐诗','yuding','','[]','萬仞峰排千劍束，孤舟夜系峰頭宿。',32,'御定全唐詩/json/629.json','["萬仞峰排千劍束，孤舟夜系峰頭宿。", "蠻溪雪壞蜀江傾，灩澦朝來大如屋。"]'),
('yuding-67','江邊','陸龜蒙','唐','御定全唐诗','yuding','','[]','江邊日晚潮煙上，樹裏鴉鴉桔槔響。',32,'御定全唐詩/json/629.json','["江邊日晚潮煙上，樹裏鴉鴉桔槔響。", "無因得似灌園翁，十畝春蔬一藜杖。"]'),
('yuding-68','簾','陸龜蒙','唐','御定全唐诗','yuding','','[]','枕映疏容晚向欹，秋煙脈脈雨微微。',32,'御定全唐詩/json/629.json','["枕映疏容晚向欹，秋煙脈脈雨微微。", "逆風障燕尋常事，不學人前當妓衣。"]'),
('yuding-69','開元雜題七首：玉龍子','陸龜蒙','唐','御定全唐诗','yuding','','[]','何代奇工碾玉英，細髯纖角盡雕成。',32,'御定全唐詩/json/629.json','["何代奇工碾玉英，細髯纖角盡雕成。", "煙幹霧悄君心苦，風雨長隨一擲聲。"]'),
('yuding-70','開元雜題七首：照夜白','陸龜蒙','唐','御定全唐诗','yuding','','[]','雪虯輕駿步如飛，一練騰光透月旗。',32,'御定全唐詩/json/629.json','["雪虯輕駿步如飛，一練騰光透月旗。", "應笑穆王拋萬乘，踏風鞭露向瑤池。"]'),
('yuding-71','開元雜題七首：舞馬','陸龜蒙','唐','御定全唐诗','yuding','','[]','月窟龍孫四百蹄，驕驤輕步應金鞞。曲終似要君王寵，回望紅樓不敢嘶。',32,'御定全唐詩/json/629.json','["月窟龍孫四百蹄，驕驤輕步應金鞞。曲終似要君王寵，回望紅樓不敢嘶。"]'),
('yuding-72','開元雜題七首：雜伎','陸龜蒙','唐','御定全唐诗','yuding','','[]','拜象馴犀角抵豪，星丸霜劍出花高。',32,'御定全唐詩/json/629.json','["拜象馴犀角抵豪，星丸霜劍出花高。", "六宮爭近乘輿望，珠翠三千擁赭袍。"]'),
('yuding-73','開元雜題七首：雪衣女','陸龜蒙','唐','御定全唐诗','yuding','','[]','嫩紅鉤曲雪花攢，月殿棲時片影殘。',32,'御定全唐詩/json/629.json','["嫩紅鉤曲雪花攢，月殿棲時片影殘。", "自說夜來春夢惡，學持金偈玉欄幹。"]'),
('yuding-74','開元雜題七首：繡嶺宮','陸龜蒙','唐','御定全唐诗','yuding','','[]','繡嶺花殘翠倚空，碧窗瑤砌舊行宮。',32,'御定全唐詩/json/629.json','["繡嶺花殘翠倚空，碧窗瑤砌舊行宮。", "閑乘小駟濃陰下，時舉金鞭半袖風。"]'),
('yuding-75','開元雜題七首：湯泉','陸龜蒙','唐','御定全唐诗','yuding','','[]','暖殿流湯數十間，玉渠香細浪回環。',32,'御定全唐詩/json/629.json','["暖殿流湯數十間，玉渠香細浪回環。", "上皇初解雲衣浴，珠棹時敲瑟瑟山。"]'),
('yuding-76','題杜秀才水亭','陸龜蒙','唐','御定全唐诗','yuding','','[]','曉和風露立晴煙，只恐腥魂涴洞天。',32,'御定全唐詩/json/629.json','["曉和風露立晴煙，只恐腥魂涴洞天。", "雲肆有龍君若買，便敲初日鑄金錢。"]'),
('yuding-77','翠碧','陸龜蒙','唐','御定全唐诗','yuding','','[]','紅襟翠翰兩參差，徑拂煙華上細枝。',32,'御定全唐詩/json/629.json','["紅襟翠翰兩參差，徑拂煙華上細枝。", "春水漸生魚易得，莫辭風雨坐多時。"]'),
('yuding-0','水國詩','陸龜蒙','唐','御定全唐诗','yuding','','[]','水國不堪旱，斯民生甚微。直至葭菼少，敢言魚蟹肥。',48,'御定全唐詩/json/630.json','["水國不堪旱，斯民生甚微。直至葭菼少，敢言魚蟹肥。", "我到荒村無食啖，對案又非梁謝覽。況是幹苗結子疏，"]'),
('yuding-1','井上桐','陸龜蒙','唐','御定全唐诗','yuding','','[]','美人傷別離，汲井長待曉。愁因轆轤轉，驚起雙棲鳥。',36,'御定全唐詩/json/630.json','["美人傷別離，汲井長待曉。愁因轆轤轉，驚起雙棲鳥。", "獨立傍銀床，碧桐風嫋嫋。"]'),
('yuding-2','門前路','陸龜蒙','唐','御定全唐诗','yuding','','[]','門前向城路，一直複一曲。曲去日中還，直行日暮宿。',36,'御定全唐詩/json/630.json','["門前向城路，一直複一曲。曲去日中還，直行日暮宿。", "何必日中還，曲途荊棘間。"]'),
('yuding-3','彼農二章','陸龜蒙','唐','御定全唐诗','yuding','','[]','世路澆險，淳風蕩除。彼農家流，猶存厥初。槁焉而席，',110,'御定全唐詩/json/630.json','["世路澆險，淳風蕩除。彼農家流，猶存厥初。槁焉而席，", "以負以載，悉薅悉鉏，我慕聖道，我耽古書。小倦于學，", "所謂饑寒，汝何逭歟。", "禹貢厥田，上下各異。善人為邦，民受其賜。去年西成，", "退輸弗供，進訴弗視。號於旻天，以血為淚。孟子有言，"]'),
('yuding-4','奉酬襲美苦雨見寄','陸龜蒙','唐','御定全唐诗','yuding','','[]','松篁交加午陰黑，別是江南煙靄國。頑雲猛雨更相欺，',217,'御定全唐詩/json/630.json','["松篁交加午陰黑，別是江南煙靄國。頑雲猛雨更相欺，", "螢飛漸多屋漸薄，一注愁霖當面落。愁霖愁霖爾何錯，", "昔年嘗過杜子美，亦得高歌破印紙。慣曾掀攪大筆多，", "哀弦怨柱合為吟，cL我窮棲蓬藋裏。初悲濕翼何由起，", "我本曾無一棱田，平生嘯傲空漁船。有時赤腳弄明月，", "伊予不戰不耕人，敢怨烝黎無糝粒。不然受性圓如規，", "有頭強方心強直，撐拄頹風不量力。自愛垂名野史中，", "橫眠木榻忘華薦，對食露葵輕八珍。欲窮玄，鳳未白。", "欲懷仙，鯨尚隔。不如驅入醉鄉中，只恐醉鄉田地窄。"]'),
('yuding-5','夏日閒居作四聲詩寄襲美：平聲','陸龜蒙','唐','御定全唐诗','yuding','','[]','荒池菰蒲深，閑階莓苔平。江邊松篁多，人家簾櫳清。',48,'御定全唐詩/json/630.json','["荒池菰蒲深，閑階莓苔平。江邊松篁多，人家簾櫳清。", "為書淩遺編，調弦誇新聲。求歡雖殊途，探幽聊怡情。"]'),
('yuding-6','夏日閒居作四聲詩寄襲美：平上聲','陸龜蒙','唐','御定全唐诗','yuding','','[]','朝煙涵樓臺，晚雨染島嶼。漁童驚狂歌，艇子喜野語。',48,'御定全唐詩/json/630.json','["朝煙涵樓臺，晚雨染島嶼。漁童驚狂歌，艇子喜野語。", "山容堪停杯，柳影好隱暑。年華如飛鴻，鬥酒幸且舉。"]'),
('yuding-7','夏日閒居作四聲詩寄襲美：平去聲','陸龜蒙','唐','御定全唐诗','yuding','','[]','新開窗猶偏，自種蕙未遍。書簽風搖聞，釣榭霧破見。',48,'御定全唐詩/json/630.json','["新開窗猶偏，自種蕙未遍。書簽風搖聞，釣榭霧破見。", "耕耘閑之資，嘯詠性最便。希夷全天真，詎要問貴賤。"]'),
('yuding-8','夏日閒居作四聲詩寄襲美：平入聲','陸龜蒙','唐','御定全唐诗','yuding','','[]','端居愁無涯，一夕發欲白。因為鸞章吟，忽憶鶴骨客。',48,'御定全唐詩/json/630.json','["端居愁無涯，一夕發欲白。因為鸞章吟，忽憶鶴骨客。", "手披丹台文，腳著赤玉舄。如蒙清音酬，若渴吸月液。"]'),
('yuding-9','奉酬襲美苦雨四聲重寄三十二句：平聲','陸龜蒙','唐','御定全唐诗','yuding','','[]','幽棲眠疏窗，豪居憑高樓。浮漚驚跳丸，寒聲思重裘。',48,'御定全唐詩/json/630.json','["幽棲眠疏窗，豪居憑高樓。浮漚驚跳丸，寒聲思重裘。", "床前垂文竿，巢邊登輕舟。雖無東皋田，還生魚乎憂。"]'),
('yuding-10','奉酬襲美苦雨四聲重寄三十二句：平上聲','陸龜蒙','唐','御定全唐诗','yuding','','[]','層雲愁天低，久雨倚檻冷。絲禽藏荷香，錦鯉繞島影。',48,'御定全唐詩/json/630.json','["層雲愁天低，久雨倚檻冷。絲禽藏荷香，錦鯉繞島影。", "心將時人乖，道與隱者靜。桐陰無深泉，所以逞短綆。"]'),
('yuding-11','奉酬襲美苦雨四聲重寄三十二句：平去聲','陸龜蒙','唐','御定全唐诗','yuding','','[]','烏蟾俱沈光，晝夜恨暗度。何當乘雲螭，面見上帝訴。',48,'御定全唐詩/json/630.json','["烏蟾俱沈光，晝夜恨暗度。何當乘雲螭，面見上帝訴。", "臣言陰雲欺，詔用利劍付。回車誅群奸，自散萬籟怒。"]'),
('yuding-12','奉酬襲美苦雨四聲重寄三十二句：平入聲','陸龜蒙','唐','御定全唐诗','yuding','','[]','危簷仍空階，十日滴不歇。青莎看成狂，白菊即欲沒。',48,'御定全唐詩/json/630.json','["危簷仍空階，十日滴不歇。青莎看成狂，白菊即欲沒。", "吳王荒金尊，越妾挾玉瑟。當時雖愁霖，亦若惜落月。"]'),
('yuding-13','曉起即事因成回文寄襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','平波落月吟閑景，暗幌浮煙思起人。清露曉垂花謝半，',40,'御定全唐詩/json/630.json','["平波落月吟閑景，暗幌浮煙思起人。清露曉垂花謝半，", "晴寺野尋同去好，古碑苔字細書勻。"]'),
('yuding-14','回文','陸龜蒙','唐','御定全唐诗','yuding','','[]','靜煙臨碧樹，殘雪背晴樓。冷天侵極戍，寒月對行舟。',24,'御定全唐詩/json/630.json','["靜煙臨碧樹，殘雪背晴樓。冷天侵極戍，寒月對行舟。"]'),
('yuding-15','疊韻山中吟','陸龜蒙','唐','御定全唐诗','yuding','','[]','瓊英輕明生，石脈滴瀝碧。玄鉛仙偏憐，白幘客亦惜。',24,'御定全唐詩/json/630.json','["瓊英輕明生，石脈滴瀝碧。玄鉛仙偏憐，白幘客亦惜。"]'),
('yuding-16','雙聲溪上思','陸龜蒙','唐','御定全唐诗','yuding','','[]','溪空唯容雲，木密不隕雨。迎漁隱映間，安問謳雅櫓。',24,'御定全唐詩/json/630.json','["溪空唯容雲，木密不隕雨。迎漁隱映間，安問謳雅櫓。"]'),
('yuding-17','疊韻吳宮詞二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','膚愉吳都姝，眷戀便殿宴。逡巡新春人，轉面見戰箭。',48,'御定全唐詩/json/630.json','["膚愉吳都姝，眷戀便殿宴。逡巡新春人，轉面見戰箭。", "紅櫳通東風，翠珥醉易墜。平明兵盈城，棄置遂至地。"]'),
('yuding-18','和胥口即事','陸龜蒙','唐','御定全唐诗','yuding','','[]','雨後山容若動，天寒樹色如消。目送回汀隱隱，',70,'御定全唐詩/json/630.json','["雨後山容若動，天寒樹色如消。目送回汀隱隱，", "莫問吳趨行樂，酒旗竿倚河橋。", "把釣絲隨浪遠，採蓮衣染香濃。綠倒紅飄欲盡，", "即是清霜剖野，乘閑莫厭來重。"]'),
('yuding-19','齊梁怨別','陸龜蒙','唐','御定全唐诗','yuding','','[]','寥寥缺月看將落，簷外霜華染羅幕。',32,'御定全唐詩/json/630.json','["寥寥缺月看將落，簷外霜華染羅幕。", "不知蘭棹到何山，應倚相思樹邊泊。"]'),
('yuding-20','閒居雜題五首：鳴蜩早','陸龜蒙','唐','御定全唐诗','yuding','','[]','閑來倚杖柴門口，鳥下深枝啄晚蟲。',32,'御定全唐詩/json/630.json','["閑來倚杖柴門口，鳥下深枝啄晚蟲。", "周步一池銷半日，十年聽此鬢如蓬。"]'),
('yuding-21','閒居雜題五首：野態真','陸龜蒙','唐','御定全唐诗','yuding','','[]','君如有意耽田裏，予亦無機向藝能。',32,'御定全唐詩/json/630.json','["君如有意耽田裏，予亦無機向藝能。", "心跡所便唯是直，人間聞道最先憎。"]'),
('yuding-22','閒居雜題五首：松間斟','陸龜蒙','唐','御定全唐诗','yuding','','[]','子山園靜憐幽木，公幹詞清詠蓽門。',32,'御定全唐詩/json/630.json','["子山園靜憐幽木，公幹詞清詠蓽門。", "月上風微蕭灑甚，鬥醪何惜置盈尊。"]'),
('yuding-23','閒居雜題五首：飲岩泉','陸龜蒙','唐','御定全唐诗','yuding','','[]','已甘茅洞三君食，欠買桐江一朵山。',32,'御定全唐詩/json/630.json','["已甘茅洞三君食，欠買桐江一朵山。", "嚴子瀨高秋浪白，水禽飛盡釣舟還。"]'),
('yuding-24','閒居雜題五首：當軒鶴','陸龜蒙','唐','御定全唐诗','yuding','','[]','自笑與人乖好尚，田家山客共柴車。',32,'御定全唐詩/json/630.json','["自笑與人乖好尚，田家山客共柴車。", "幹時未似棲廬雀，鳥道閑攜相爾書。"]'),
('yuding-25','藥名離合夏日即事三首','陸龜蒙','唐','御定全唐诗','yuding','','[]','乘屐著來幽砌滑，石罌煎得遠泉甘。',96,'御定全唐詩/json/630.json','["乘屐著來幽砌滑，石罌煎得遠泉甘。", "草堂只待新秋景，天色微涼酒半酣。", "避暑最須從朴野，葛巾筠席更相當。", "歸來又好乘涼釣，藤蔓陰陰著雨香。", "窗外曉簾還自卷，柏煙蘭露思晴空。", "青箱有意終須續，斷簡遺編一半通。"]'),
('yuding-26','和襲美懷錫山藥名離合二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','鶴伴前溪栽白杏，人來陰洞寫枯松。',64,'御定全唐詩/json/630.json','["鶴伴前溪栽白杏，人來陰洞寫枯松。", "蘿深境靜日欲落，石上未眠聞遠鐘。", "佳句成來誰不伏，神丹偷去亦須防。", "風前莫怪攜詩槁，本是吳吟蕩槳郎。"]'),
('yuding-27','和襲美懷鹿門縣名離合二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','雲容覆枕無非白，水色侵磯直是藍。',64,'御定全唐詩/json/630.json','["雲容覆枕無非白，水色侵磯直是藍。", "田種紫芝餐可壽，春來何事戀江南。", "竹溪深處猿同宿，松閣秋來客共登。", "封徑古苔侵石鹿，城中誰解訪山僧。"]'),
('yuding-28','寒日古人名','陸龜蒙','唐','御定全唐诗','yuding','','[]','初寒朗詠裴回立，欲謝玄關早晚開。',32,'御定全唐詩/json/630.json','["初寒朗詠裴回立，欲謝玄關早晚開。", "昨日登樓望江色，魚梁鴻雁幾多來。"]'),
('yuding-29','句','陸龜蒙','唐','御定全唐诗','yuding','','[]','幾點社翁雨，一番花信風。',104,'御定全唐詩/json/630.json','["幾點社翁雨，一番花信風。", "水鳥歌婦女，衣襟便佞舌。", "溪山自是清涼國，松竹合封蕭灑侯。", "山上花明水上曛，一橈青翰破霞文。", "白帝霜輿欲禦秋。", "但說漱流並枕石，不辭蟬腹與龜腸。", "頭方不會王門事，塵土空緇白苧衣。", "秋來懶上向吳亭。"]'),
('yuding-0','旅泊吳門','張賁','唐','御定全唐诗','yuding','','[]','一舸吳江晚，堪憂病廣文。鱸魚誰與伴，鷗鳥自成群。',48,'御定全唐詩/json/631.json','["一舸吳江晚，堪憂病廣文。鱸魚誰與伴，鷗鳥自成群。", "反照縱橫水，斜空斷續雲。異鄉無限思，盡付酒醺醺。"]'),
('yuding-1','賁中間有吳門旅泊之什蒙魯望垂和更作一章以伸酬謝','張賁','唐','御定全唐诗','yuding','','[]','偶發陶匏響，皆蒙組繡文。清秋將落帽，子夏正離群。',48,'御定全唐詩/json/631.json','["偶發陶匏響，皆蒙組繡文。清秋將落帽，子夏正離群。", "有恨書燕雁，無聊賦郢雲。遍看心自醉，不是酒能醺。"]'),
('yuding-2','酬襲美先見寄倒來韻','張賁','唐','御定全唐诗','yuding','','[]','尋疑天意喪斯文，故選茅峰寄白雲。酒後只留滄海客，',40,'御定全唐詩/json/631.json','["尋疑天意喪斯文，故選茅峰寄白雲。酒後只留滄海客，", "為有此身猶苦患，不知何者是玄纁。"]'),
('yuding-3','奉和襲美醉中即席見贈次韻','張賁','唐','御定全唐诗','yuding','','[]','桂枝新下月中仙，學海詞鋒譽藹然。文陣已推忠信甲，',40,'御定全唐詩/json/631.json','["桂枝新下月中仙，學海詞鋒譽藹然。文陣已推忠信甲，", "共許逢蒙快弓箭，再穿楊葉在明年。"]'),
('yuding-4','奉和襲美題褚家林亭','張賁','唐','御定全唐诗','yuding','','[]','疏野林亭震澤西，朗吟閒步喜相攜。時時風折蘆花亂，',40,'御定全唐詩/json/631.json','["疏野林亭震澤西，朗吟閒步喜相攜。時時風折蘆花亂，", "今朝偶得高陽伴，從放山翁醉似泥。"]'),
('yuding-5','奉和襲美傷開元觀顧道士','張賁','唐','御定全唐诗','yuding','','[]','鳳麟膠盡夜如何，共歎先生劍解多。幾度吊來唯白鶴，',40,'御定全唐詩/json/631.json','["鳳麟膠盡夜如何，共歎先生劍解多。幾度吊來唯白鶴，", "惆悵真靈又空返，玉書誰授紫微歌。"]'),
('yuding-6','和魯望白菊','張賁','唐','御定全唐诗','yuding','','[]','雪彩冰姿號女華，寄身多是地仙家。有時南國和霜立，',40,'御定全唐詩/json/631.json','["雪彩冰姿號女華，寄身多是地仙家。有時南國和霜立，", "自知終古清香在，更出梅妝弄晚霞。"]'),
('yuding-7','奉和襲美先輩悼鶴','張賁','唐','御定全唐诗','yuding','','[]','池塘蕭索掩空籠，玉樹同嗟一土中。莎徑罷鳴唯泣露，',40,'御定全唐詩/json/631.json','["池塘蕭索掩空籠，玉樹同嗟一土中。莎徑罷鳴唯泣露，", "雲減霧消無處問，只留華髮與衰翁。"]'),
('yuding-8','偶約道流終乖文會答皮陸','張賁','唐','御定全唐诗','yuding','','[]','仙侶無何訪蔡經，兩煩韶濩出彤庭。',32,'御定全唐詩/json/631.json','["仙侶無何訪蔡經，兩煩韶濩出彤庭。", "人間若有登樓望，應怪文星近客星。"]'),
('yuding-9','和襲美寒夜見訪','張賁','唐','御定全唐诗','yuding','','[]','雲孤鶴獨且相親，仿效從它折角巾。',32,'御定全唐詩/json/631.json','["雲孤鶴獨且相親，仿效從它折角巾。", "不用吳江歎留滯，風姿俱是玉清人。"]'),
('yuding-10','和襲美醉中先起次韻','張賁','唐','御定全唐诗','yuding','','[]','何事桃源路忽迷，惟留雲雨怨空閨。',32,'御定全唐詩/json/631.json','["何事桃源路忽迷，惟留雲雨怨空閨。", "仙郎共許多情調，莫遣重歌濁水泥。"]'),
('yuding-11','和皮陸酒病偶作','張賁','唐','御定全唐诗','yuding','','[]','白編椰席鏤冰明，應助楊青解宿酲。',32,'御定全唐詩/json/631.json','["白編椰席鏤冰明，應助楊青解宿酲。", "難繼二賢金玉唱，可憐空作斷猿聲。"]'),
('yuding-12','送浙東德師侍禦罷府西歸','張賁','唐','御定全唐诗','yuding','','[]','孤雲獨鳥本無依，江海重逢故舊稀。',32,'御定全唐詩/json/631.json','["孤雲獨鳥本無依，江海重逢故舊稀。", "楊柳漸疏蘆葦白，可憐斜日送君歸。"]'),
('yuding-13','以青z3飯分送襲美魯望因成一絕','張賁','唐','御定全唐诗','yuding','','[]','誰屑瓊瑤事青z3，舊傳名品出華陽。',33,'御定全唐詩/json/631.json','["誰屑瓊瑤事青z3，舊傳名品出華陽。", "應宜仙子胡麻拌，因送劉郎與阮郎。"]'),
('yuding-14','玩金鸂鶒和陸魯望','張賁','唐','御定全唐诗','yuding','','[]','翠羽紅襟鏤彩雲，雙飛常笑白鷗群。',32,'御定全唐詩/json/631.json','["翠羽紅襟鏤彩雲，雙飛常笑白鷗群。", "誰憐化作雕金質，從倩沉檀十裏聞。"]'),
('yuding-15','悼鶴和襲美','張賁','唐','御定全唐诗','yuding','','[]','渥頂鮮毛品格馴，莎庭閒暇重難群。',32,'御定全唐詩/json/631.json','["渥頂鮮毛品格馴，莎庭閒暇重難群。", "無端日暮東風起，飄散春空一片雲。"]'),
('yuding-16','覽皮先輩盛制，因作十韻以寄，用伸款仰','崔璐','唐','御定全唐诗','yuding','','[]','河嶽挺靈異，星辰精氣殊。在人為英傑，與國作禎符。',132,'御定全唐詩/json/631.json','["河嶽挺靈異，星辰精氣殊。在人為英傑，與國作禎符。", "襄陽得奇士，俊邁真龍駒。勇果魯仲由，文賦蜀相如。", "渾浩江海廣，葩華桃李敷。小言入無間，大言塞空虛。", "幾人游赤水，夫子得玄珠。鬼神爭奧秘，天地惜洪爐。", "既有曾參行，仍兼君子儒。吾知上帝意，將使居黃樞。", "好保千金體，須為萬姓謨。"]'),
('yuding-17','浙東罷府西歸酬別張廣文皮先輩陸秀才','李縠','唐','御定全唐诗','yuding','','[]','豈有頭風筆下痊，浪成蠻語向初筵。蘭亭舊趾雖曾見，',40,'御定全唐詩/json/631.json','["豈有頭風筆下痊，浪成蠻語向初筵。蘭亭舊趾雖曾見，", "相逢只恨相知晚，一曲驪歌又幾年。"]'),
('yuding-18','和皮日休悼鶴','李縠','唐','御定全唐诗','yuding','','[]','才子襟期本上清，陸雲家鶴伴閒情。猶憐反顧五六裏，',72,'御定全唐詩/json/631.json','["才子襟期本上清，陸雲家鶴伴閒情。猶憐反顧五六裏，", "人間華表堪留語，剩向秋風寄一聲。", "道林曾放雪翎飛，應悔庭除閉羽衣。", "料得王恭披鶴氅，倚吟猶待月中歸。"]'),
('yuding-19','醉中襲美先月中歸','李縠','唐','御定全唐诗','yuding','','[]','休文雖即逃瓊液，阿鶩還須掩玉閨。',32,'御定全唐詩/json/631.json','["休文雖即逃瓊液，阿鶩還須掩玉閨。", "月落金雞一聲後，不知誰悔醉如泥。"]'),
('yuding-20','奉酬皮先輩霜菊見贈','崔璞','唐','御定全唐诗','yuding','','[]','菊花開晚過秋風，聞道芳香正滿叢。',32,'御定全唐詩/json/631.json','["菊花開晚過秋風，聞道芳香正滿叢。", "爭奈病夫難強飲，應須速自召車公。"]'),
('yuding-21','蒙恩除替將還京洛偶敘所懷因成六韻呈軍事院諸公郡中一二秀才','崔璞','唐','御定全唐诗','yuding','','[]','兩載求人瘼，三春受代歸。務繁多簿籍，才短乏恩威。',72,'御定全唐詩/json/631.json','["兩載求人瘼，三春受代歸。務繁多簿籍，才短乏恩威。", "共理乖天獎，分憂值歲饑。遽蒙交郡印，安敢整朝衣。", "作牧慚為政，思鄉念式微。儻容還故里，高臥掩柴扉。"]'),
('yuding-22','和皮日休悼鶴','魏樸','唐','御定全唐诗','yuding','','[]','直欲裁詩問杳冥，豈教靈化亦浮生。風林月動疑留魄，',72,'御定全唐詩/json/631.json','["直欲裁詩問杳冥，豈教靈化亦浮生。風林月動疑留魄，", "人間飛去猶堪恨，況是泉台遠玉京。", "經秋宋玉已悲傷，況報胎禽昨夜亡。", "霜曉起來無問處，伴僧彈指繞荷塘。"]'),
('yuding-23','皮襲美見留小宴次韻','羊昭業','唐','御定全唐诗','yuding','','[]','澤國春來少遇晴，有花開日且飛觥。王戎似電休推病，',40,'御定全唐詩/json/631.json','["澤國春來少遇晴，有花開日且飛觥。王戎似電休推病，", "知君不肯然官燭，爭得華筵徹夜明。"]'),
('yuding-24','送羊振文歸覲桂陽','顏萱','唐','御定全唐诗','yuding','','[]','高掛吳帆喜動容，問安歸去指湘峰。懸魚庭內芝蘭秀，',40,'御定全唐詩/json/631.json','["高掛吳帆喜動容，問安歸去指湘峰。懸魚庭內芝蘭秀，", "臨岐獨有沾襟戀，南巷當年共化龍。"]'),
('yuding-25','送圓載上人','顏萱','唐','御定全唐诗','yuding','','[]','師來一世恣經行，卻泛滄波問去程。心靜已能防渴鹿，',40,'御定全唐詩/json/631.json','["師來一世恣經行，卻泛滄波問去程。心靜已能防渴鹿，", "料得還鄉無別利，只應先見日華生。"]'),
('yuding-26','過張祜處士丹陽故居','顏萱','唐','御定全唐诗','yuding','','[]','憶昔為兒逐我兄，曾拋竹馬拜先生。書齋已換當時主，',40,'御定全唐詩/json/631.json','["憶昔為兒逐我兄，曾拋竹馬拜先生。書齋已換當時主，", "柴扉草屋無人問，猶向荒田責地征。"]'),
('yuding-27','和襲美傷顧道士','鄭璧','唐','御定全唐诗','yuding','','[]','斜漢銀瀾一夜東，飄飄何處五雲中。空留華表千年約，',40,'御定全唐詩/json/631.json','["斜漢銀瀾一夜東，飄飄何處五雲中。空留華表千年約，", "門人不睹飛升去，猶與浮生哭恨同。"]'),
('yuding-28','奉和陸魯望白菊','鄭璧','唐','御定全唐诗','yuding','','[]','白豔輕明帶露痕，始知佳色重難群。終朝疑笑梁王雪，',40,'御定全唐詩/json/631.json','["白豔輕明帶露痕，始知佳色重難群。終朝疑笑梁王雪，", "瓊妃若會寬裁剪，堪作蟾宮夜舞裙。"]'),
('yuding-29','和襲美索友人酒','鄭璧','唐','御定全唐诗','yuding','','[]','乘興閑來小謝家，便裁詩句乞榴花。',32,'御定全唐詩/json/631.json','["乘興閑來小謝家，便裁詩句乞榴花。", "邴原雖不無端醉，也愛臨風從鹿車。"]'),
('yuding-30','文燕潤卿不至','鄭璧','唐','御定全唐诗','yuding','','[]','已知羽駕朝金闕，不用燒蘭望玉京。',32,'御定全唐詩/json/631.json','["已知羽駕朝金闕，不用燒蘭望玉京。", "應是易遷明月好，玉皇留看舞雙成。"]'),
('yuding-0','塞上','司空圖','唐','御定全唐诗','yuding','','[]','萬里隋城在，三邊虜氣衰。沙填孤障角，燒斷故關碑。',48,'御定全唐詩/json/632.json','["萬里隋城在，三邊虜氣衰。沙填孤障角，燒斷故關碑。", "馬色經寒慘，雕聲帶晚悲。將軍正閒暇，留客換歌辭。"]'),
('yuding-1','寄永嘉崔道融','司空圖','唐','御定全唐诗','yuding','','[]','旅寓雖難定，乘閑是勝遊。碧雲蕭寺霽，紅樹謝村秋。',48,'御定全唐詩/json/632.json','["旅寓雖難定，乘閑是勝遊。碧雲蕭寺霽，紅樹謝村秋。", "戍鼓和潮暗，船燈照島幽。詩家多滯此，風景似相留。"]'),
('yuding-2','下方','司空圖','唐','御定全唐诗','yuding','','[]','三十年來往，中間京洛塵。倦行今白首，歸臥已清神。',48,'御定全唐詩/json/632.json','["三十年來往，中間京洛塵。倦行今白首，歸臥已清神。", "坡暖冬抽筍，松涼夏健人。更慚征詔起，避世跡非真。"]'),
('yuding-3','華下','司空圖','唐','御定全唐诗','yuding','','[]','日炙旱雲裂，迸為千道血。天地沸一鑊，竟自烹妖孽。',48,'御定全唐詩/json/632.json','["日炙旱雲裂，迸為千道血。天地沸一鑊，竟自烹妖孽。", "堯湯遇災數，災數還中輟。何事奸與邪，古來難撲滅。"]'),
('yuding-4','僧舍貽友','司空圖','唐','御定全唐诗','yuding','','[]','笑破人間事，吾徒莫自欺。解吟僧亦俗，愛舞鶴終卑。',48,'御定全唐詩/json/632.json','["笑破人間事，吾徒莫自欺。解吟僧亦俗，愛舞鶴終卑。", "竹上題幽夢，溪邊約敵棋。舊山歸有阻，不是故遲遲。"]'),
('yuding-5','下方','司空圖','唐','御定全唐诗','yuding','','[]','昏旦松軒下，怡然對一瓢。雨微吟思足，花落夢無聊。',48,'御定全唐詩/json/632.json','["昏旦松軒下，怡然對一瓢。雨微吟思足，花落夢無聊。", "細事當棋遣，衰容喜鏡饒。溪僧有深趣，書至又相邀。"]'),
('yuding-6','華下送文浦','司空圖','唐','御定全唐诗','yuding','','[]','郊居謝名利，何事最相親。漸與論詩久，皆知得句新。',48,'御定全唐詩/json/632.json','["郊居謝名利，何事最相親。漸與論詩久，皆知得句新。", "川明虹照雨，樹密鳥沖人。應念從今去，還來嶽下頻。"]'),
('yuding-7','自誡','司空圖','唐','御定全唐诗','yuding','','[]','我祖銘座右，嘉謀貽厥孫。勤此苟不怠，令名日可存。',72,'御定全唐詩/json/632.json','["我祖銘座右，嘉謀貽厥孫。勤此苟不怠，令名日可存。", "媒衒士所恥，慈儉道所尊。松柏豈不茂，桃李亦自繁。", "眾人皆察察，而我獨昏昏。取訓於老氏，大辯欲訥言。"]'),
('yuding-8','效陳拾遺子昂感遇二首','司空圖','唐','御定全唐诗','yuding','','[]','高燕飛何捷，啄害恣群雛。人豈玩其暴，華軒容爾居。',96,'御定全唐詩/json/632.json','["高燕飛何捷，啄害恣群雛。人豈玩其暴，華軒容爾居。", "強欺自天稟，剛吐信吾徒。乃知不平者，矯世道終孤。", "陽和含煦潤，卉木競紛華。當為眾所悅，私已汝何誇。", "北裏秘穠豔，東園鎖名花。豪奪乃常理，笑君徒咄嗟。"]'),
('yuding-9','效陳拾遺子昂','司空圖','唐','御定全唐诗','yuding','','[]','醜婦競簪花，花多映愈醜。鄰女恃其姿，掇之不盈手。',48,'御定全唐詩/json/632.json','["醜婦競簪花，花多映愈醜。鄰女恃其姿，掇之不盈手。", "量已苟自私，招損乃誰咎。寵祿既非安，于吾竟何有。"]'),
('yuding-10','感時','司空圖','唐','御定全唐诗','yuding','','[]','好鳥無惡聲，仁獸肯狂噬。寧教鸚鵡啞，不遣麒麟細。',48,'御定全唐詩/json/632.json','["好鳥無惡聲，仁獸肯狂噬。寧教鸚鵡啞，不遣麒麟細。", "人人語與默，唯觀利與勢。愛毀亦自遭，掩謗終失計。"]'),
('yuding-11','秋思','司空圖','唐','御定全唐诗','yuding','','[]','身病時亦危，逢秋多慟哭。風波一搖盪，天地幾翻覆。',48,'御定全唐詩/json/632.json','["身病時亦危，逢秋多慟哭。風波一搖盪，天地幾翻覆。", "孤螢出荒池，落葉穿破屋。勢利長草草，何人訪幽獨。"]'),
('yuding-12','早春','司空圖','唐','御定全唐诗','yuding','','[]','傷懷同客處，病眼卻花朝。草嫩侵沙短，冰輕著雨消。',48,'御定全唐詩/json/632.json','["傷懷同客處，病眼卻花朝。草嫩侵沙短，冰輕著雨消。", "風光知可愛，容發不相饒。早晚丹丘去，飛書肯見招。"]'),
('yuding-13','上陌梯寺懷舊僧二首','司空圖','唐','御定全唐诗','yuding','','[]','雲根禪客居，皆說舊無廬。松日明金像，山風向木魚。',96,'御定全唐詩/json/632.json','["雲根禪客居，皆說舊無廬。松日明金像，山風向木魚。", "依棲應不阻，名利本來疏。縱有人相問，林間懶拆書。", "高鴉隔谷見，路轉寺西門。塔影蔭泉脈，山苗侵燒痕。", "鐘疏含杳靄，合迥亙黃昏。更待他僧到，長如前信存。"]'),
('yuding-14','寄懷元秀上人','司空圖','唐','御定全唐诗','yuding','','[]','悠悠幹祿利，草草廢漁樵。身世堪惆悵，風騷頓寂寥。',48,'御定全唐詩/json/632.json','["悠悠幹祿利，草草廢漁樵。身世堪惆悵，風騷頓寂寥。", "高秋期步野，積雨放趨朝。得句如相憶，莎齋且見招。"]'),
('yuding-15','次韻和秀上人游南五台','司空圖','唐','御定全唐诗','yuding','','[]','中峰曾到處，題記沒蒼苔。振錫傳深谷，翻經想舊台。',48,'御定全唐詩/json/632.json','["中峰曾到處，題記沒蒼苔。振錫傳深谷，翻經想舊台。", "危松臨砌偃，驚鹿驀溪來。內殿禦詩切，身回心未回。"]'),
('yuding-16','贈圓昉公','司空圖','唐','御定全唐诗','yuding','','[]','天階讓紫衣，冷格鶴猶卑。道勝嫌名出，身閑覺老遲。',48,'御定全唐詩/json/632.json','["天階讓紫衣，冷格鶴猶卑。道勝嫌名出，身閑覺老遲。", "曉香延宿火，寒磬度高枝。每說長松寺，他年與我期。"]'),
('yuding-17','贈信美寺岑上人','司空圖','唐','御定全唐诗','yuding','','[]','巡禮諸方遍，湘南頻有緣。焚香老山寺，乞食向江船。',48,'御定全唐詩/json/632.json','["巡禮諸方遍，湘南頻有緣。焚香老山寺，乞食向江船。", "紗碧籠名畫，燈寒照淨禪。我來能永日，蓮漏滴寒泉。"]'),
('yuding-18','江行二首','司空圖','唐','御定全唐诗','yuding','','[]','地闊分吳塞，楓高映楚天。曲塘春盡雨，方響夜深船。',96,'御定全唐詩/json/632.json','["地闊分吳塞，楓高映楚天。曲塘春盡雨，方響夜深船。", "行紀添新夢，羈愁甚往年。何時京洛路，馬上見人煙。", "初程風信好，回望失津樓。日帶潮聲晚，煙含楚色秋。", "戍旗當遠客，島樹轉驚鷗。此去非名利，孤帆任白頭。"]'),
('yuding-19','長安贈王注','司空圖','唐','御定全唐诗','yuding','','[]','正下搜賢詔，多君獨避名。客來當意愜，花發遇歌成。',48,'御定全唐詩/json/632.json','["正下搜賢詔，多君獨避名。客來當意愜，花發遇歌成。", "樂地留高趣，權門讓後生。東方禦閑駟，園外好同行。"]'),
('yuding-20','贈步寄李員外','司空圖','唐','御定全唐诗','yuding','','[]','危橋轉溪路，經雨石叢荒。幽瀑下仙果，孤巢懸夕陽。',48,'御定全唐詩/json/632.json','["危橋轉溪路，經雨石叢荒。幽瀑下仙果，孤巢懸夕陽。", "病辭青瑣秘，心在紫芝房。更喜諧招隱，詩家有望郎。"]'),
('yuding-21','寄鄭仁規','司空圖','唐','御定全唐诗','yuding','','[]','清才鄭小戎，標的貴遊中。萬里雲無侶，三山鶴不籠。',48,'御定全唐詩/json/632.json','["清才鄭小戎，標的貴遊中。萬里雲無侶，三山鶴不籠。", "香和丹地暖，晚著彩衣風。榮路期經濟，唯應在至公。"]'),
('yuding-22','寄考功王員外','司空圖','唐','御定全唐诗','yuding','','[]','喜聞三字耗，閑客是陪遊。白鳥閑疏索，青山日滯留。',48,'御定全唐詩/json/632.json','["喜聞三字耗，閑客是陪遊。白鳥閑疏索，青山日滯留。", "琴如高韻稱，詩愧逸才酬。更勉匡君志，論思在獻謀。"]'),
('yuding-23','雜言','司空圖','唐','御定全唐诗','yuding','','[]','烏飛飛，兔蹶蹶，朝來暮去驅時節。女媧只解補青天，',24,'御定全唐詩/json/632.json','["烏飛飛，兔蹶蹶，朝來暮去驅時節。女媧只解補青天，"]'),
('yuding-24','陳疾','司空圖','唐','御定全唐诗','yuding','','[]','自憐旅舍亦酣歌，世路無機奈爾何。霄漢逼來心不動，',40,'御定全唐詩/json/632.json','["自憐旅舍亦酣歌，世路無機奈爾何。霄漢逼來心不動，", "閑得此身歸未得，磬聲深夏隔煙蘿。"]'),
('yuding-25','淅上','司空圖','唐','御定全唐诗','yuding','','[]','華下支離已隔河，又來此地避干戈。山田漸廣猿時到，',80,'御定全唐詩/json/632.json','["華下支離已隔河，又來此地避干戈。山田漸廣猿時到，", "兒童栗熟迷歸路，歸得仍隨牧豎歌。", "西北鄉關近帝京，煙塵一片正傷情。愁看地色連空色，", "從他煙棹更南去，休向津頭問去程。"]'),
('yuding-26','山中','司空圖','唐','御定全唐诗','yuding','','[]','全家與我戀孤岑，蹋得蒼苔一徑深。逃難人多分隙地，',40,'御定全唐詩/json/632.json','["全家與我戀孤岑，蹋得蒼苔一徑深。逃難人多分隙地，", "昨夜前溪驟雷雨，晚晴閒步數峰吟。"]'),
('yuding-27','寄贈詩僧秀公','司空圖','唐','御定全唐诗','yuding','','[]','靈一心傳清塞心，可公吟後礎公吟。近來雅道相親少，',40,'御定全唐詩/json/632.json','["靈一心傳清塞心，可公吟後礎公吟。近來雅道相親少，", "冷曹孤宦甘寥落，多謝攜筇數訪尋。"]'),
('yuding-28','重陽日訪元秀上人','司空圖','唐','御定全唐诗','yuding','','[]','紅葉黃花秋景寬，醉吟朝夕在樊川。卻嫌今日登山俗，',40,'御定全唐詩/json/632.json','["紅葉黃花秋景寬，醉吟朝夕在樊川。卻嫌今日登山俗，", "歸來童稚爭相笑，何事無人與酒船。"]'),
('yuding-29','丁未歲歸王官谷','司空圖','唐','御定全唐诗','yuding','','[]','家山牢落戰塵西，匹馬偷歸路已迷。塚上卷旗人簇立，',40,'御定全唐詩/json/632.json','["家山牢落戰塵西，匹馬偷歸路已迷。塚上卷旗人簇立，", "將取一壺閑日月，長歌深入武陵溪。"]'),
('yuding-30','書懷','司空圖','唐','御定全唐诗','yuding','','[]','病來猶強引雛行，力上東原欲試耕。幾處馬嘶春麥長，',40,'御定全唐詩/json/632.json','["病來猶強引雛行，力上東原欲試耕。幾處馬嘶春麥長，", "陶令若能兼不飲，無弦琴亦是沽名。"]'),
('yuding-31','退棲','司空圖','唐','御定全唐诗','yuding','','[]','宦游蕭索為無能，移住中條最上層。得劍乍如添健僕，',40,'御定全唐詩/json/632.json','["宦游蕭索為無能，移住中條最上層。得劍乍如添健僕，", "自此致身繩檢外，肯教世路日兢兢。"]'),
('yuding-32','五十','司空圖','唐','御定全唐诗','yuding','','[]','閑身事少只題詩，五十今來覺陡衰。清秩偶叨非養望，',40,'御定全唐詩/json/632.json','["閑身事少只題詩，五十今來覺陡衰。清秩偶叨非養望，", "漉酒有巾無黍釀，負他黃菊滿東籬。"]'),
('yuding-33','新歲對寫真','司空圖','唐','御定全唐诗','yuding','','[]','得見明時下壽身，須甘歲酒更移巡。生情暗結千重恨，',40,'御定全唐詩/json/632.json','["得見明時下壽身，須甘歲酒更移巡。生情暗結千重恨，", "自傷衰颯慵開鏡，擬與兒童別寫真。"]'),
('yuding-34','華下','司空圖','唐','御定全唐诗','yuding','','[]','籜冠新帶步池塘，逸韻偏宜夏景長。扶起綠荷承早露，',40,'御定全唐詩/json/632.json','["籜冠新帶步池塘，逸韻偏宜夏景長。扶起綠荷承早露，", "不用名山訪真訣，退休便是養生方。"]'),
('yuding-35','重陽山居','司空圖','唐','御定全唐诗','yuding','','[]','詩人自古恨難窮，暮節登臨且喜同。四望交親兵亂後，',40,'御定全唐詩/json/632.json','["詩人自古恨難窮，暮節登臨且喜同。四望交親兵亂後，", "明日更期來此醉，不堪寂寞對衰翁。"]'),
('yuding-36','爭名','司空圖','唐','御定全唐诗','yuding','','[]','爭名豈在更搜奇，不朽才消一句詩。窮辱未甘英氣阻，',40,'御定全唐詩/json/632.json','["爭名豈在更搜奇，不朽才消一句詩。窮辱未甘英氣阻，", "只此共棲塵外境，無妨亦戀好文時。"]'),
('yuding-37','光啟四年春戊申','司空圖','唐','御定全唐诗','yuding','','[]','亂後燒殘數架書，峰前猶自戀吾廬。忘機漸喜逢人少，',40,'御定全唐詩/json/632.json','["亂後燒殘數架書，峰前猶自戀吾廬。忘機漸喜逢人少，", "酣歌自適逃名久，不必門多長者車。"]'),
('yuding-38','丁巳重陽','司空圖','唐','御定全唐诗','yuding','','[]','重陽未到已登臨，探得黃花且獨斟。客舍喜逢連日雨，',40,'御定全唐詩/json/632.json','["重陽未到已登臨，探得黃花且獨斟。客舍喜逢連日雨，", "自賀逢時能自棄，歸鞭唯拍馬韉吟。"]'),
('yuding-39','喜王駕小儀重陽相訪','司空圖','唐','御定全唐诗','yuding','','[]','白菊初開臥內明，聞君相訪病身輕。樽前且撥傷心事，',40,'御定全唐詩/json/632.json','["白菊初開臥內明，聞君相訪病身輕。樽前且撥傷心事，", "擬將寂寞同留住，且勸康時立大名。"]'),
('yuding-40','酬張芬赦後見寄','司空圖','唐','御定全唐诗','yuding','','[]','紫鳳朝銜五色書，陽春忽布網羅除。已將心變寒灰後，',40,'御定全唐詩/json/632.json','["紫鳳朝銜五色書，陽春忽布網羅除。已將心變寒灰後，", "勞君故有詩相贈，欲報瓊瑤愧不如。"]'),
('yuding-41','上元放二雉','司空圖','唐','御定全唐诗','yuding','','[]','嬰網雖皆困，搴籠喜共歸。無心期爾報，相見莫驚飛。',24,'御定全唐詩/json/632.json','["嬰網雖皆困，搴籠喜共歸。無心期爾報，相見莫驚飛。"]'),
('yuding-42','中秋','司空圖','唐','御定全唐诗','yuding','','[]','閑吟秋景外，萬事覺悠悠。此夜若無月，一年虛過秋。',24,'御定全唐詩/json/632.json','["閑吟秋景外，萬事覺悠悠。此夜若無月，一年虛過秋。"]'),
('yuding-43','偶題','司空圖','唐','御定全唐诗','yuding','','[]','水榭花繁處，春晴日午前。鳥窺臨檻鏡，馬過隔牆鞭。',24,'御定全唐詩/json/632.json','["水榭花繁處，春晴日午前。鳥窺臨檻鏡，馬過隔牆鞭。"]'),
('yuding-44','閒步','司空圖','唐','御定全唐诗','yuding','','[]','幾處白煙斷，一川紅樹時。壞橋侵轍水，殘照背村碑。',24,'御定全唐詩/json/632.json','["幾處白煙斷，一川紅樹時。壞橋侵轍水，殘照背村碑。"]'),
('yuding-45','春中','司空圖','唐','御定全唐诗','yuding','','[]','伏溜侵階潤，繁花隔竹香。嬌鶯方曉聽，無事過南塘。',24,'御定全唐詩/json/632.json','["伏溜侵階潤，繁花隔竹香。嬌鶯方曉聽，無事過南塘。"]'),
('yuding-46','獨望','司空圖','唐','御定全唐诗','yuding','','[]','綠樹連村暗，黃花出陌稀。遠陂春草綠，猶有水禽飛。',24,'御定全唐詩/json/632.json','["綠樹連村暗，黃花出陌稀。遠陂春草綠，猶有水禽飛。"]'),
('yuding-47','雜題','司空圖','唐','御定全唐诗','yuding','','[]','孤枕聞鶯起，幽懷獨悄然。地融春力潤，花泛曉光鮮。',24,'御定全唐詩/json/632.json','["孤枕聞鶯起，幽懷獨悄然。地融春力潤，花泛曉光鮮。"]'),
('yuding-48','漫題三首','司空圖','唐','御定全唐诗','yuding','','[]','亂後他鄉節，燒殘故國春。自憐垂白首，猶伴踏青人。',72,'御定全唐詩/json/632.json','["亂後他鄉節，燒殘故國春。自憐垂白首，猶伴踏青人。", "齒落傷情久，心驚健忘頻。蝸廬經歲客，蠶市異鄉人。", "率怕人言謹，閑宜酒韻高。山林若無慮，名利不難逃。"]'),
('yuding-49','河上二首','司空圖','唐','御定全唐诗','yuding','','[]','慘慘日將暮，驅羸獨到莊。沙痕傍墟落，風色入牛羊。',48,'御定全唐詩/json/632.json','["慘慘日將暮，驅羸獨到莊。沙痕傍墟落，風色入牛羊。", "新霽田園處，夕陽禾黍明。沙村平見水，深巷有鷗聲。"]'),
('yuding-50','早朝','司空圖','唐','御定全唐诗','yuding','','[]','白日新年好，青春上國多。街平雙闕近，塵起五雲和。',24,'御定全唐詩/json/632.json','["白日新年好，青春上國多。街平雙闕近，塵起五雲和。"]'),
('yuding-51','即事二首','司空圖','唐','御定全唐诗','yuding','','[]','茶爽添詩句，天清瑩道心。只留鶴一隻，此外是空林。',48,'御定全唐詩/json/632.json','["茶爽添詩句，天清瑩道心。只留鶴一隻，此外是空林。", "禦禮征奇策，人心注盛時。從來留振滯，只待濟臨危。"]'),
('yuding-52','永夜','司空圖','唐','御定全唐诗','yuding','','[]','永夜疑無日，危時只賴山。曠懷休戚外，孤跡是非間。',24,'御定全唐詩/json/632.json','["永夜疑無日，危時只賴山。曠懷休戚外，孤跡是非間。"]'),
('yuding-53','秦關','司空圖','唐','御定全唐诗','yuding','','[]','形勝今雖在，荒涼恨不窮。虎狼秦國破，狐兔漢陵空。',24,'御定全唐詩/json/632.json','["形勝今雖在，荒涼恨不窮。虎狼秦國破，狐兔漢陵空。"]'),
('yuding-54','渡江','司空圖','唐','御定全唐诗','yuding','','[]','秋江共僧渡，鄉淚滴船回。一夜吳船夢，家書立馬開。',24,'御定全唐詩/json/632.json','["秋江共僧渡，鄉淚滴船回。一夜吳船夢，家書立馬開。"]'),
('yuding-55','退居漫題七首','司空圖','唐','御定全唐诗','yuding','','[]','花缺傷難綴，鶯喧奈細聽。惜春春已晚，珍重草青青。',168,'御定全唐詩/json/632.json','["花缺傷難綴，鶯喧奈細聽。惜春春已晚，珍重草青青。", "堤柳自綿綿，幽人無恨牽。只憂詩病發，莫寄校書箋。", "燕語曾來客，花催欲別人。莫愁春又過，看著又新春。", "身外都無事，山中久避喧。破巢看乳燕，留果待啼猿。", "詩家通籍美，工部與司勳。高賈雖難敵，微官偶勝君。", "努力省前非，人生上壽稀。青雲無直道，暗室有危機。", "燕拙營巢苦，魚貪觸網驚。豈緣身外事，亦似我勞形。"]'),
('yuding-56','即事九首','司空圖','唐','御定全唐诗','yuding','','[]','宿雨川原霽，憑高景物新。陂痕侵牧馬，雲影帶耕人。',216,'御定全唐詩/json/632.json','["宿雨川原霽，憑高景物新。陂痕侵牧馬，雲影帶耕人。", "十年深隱地，一雨太平心。匣澀休看劍，窗明複上琴。", "明時那棄置，多病自遲留。疏磬和吟斷，殘燈照臥幽。", "衰鬢閑生少，丹梯望覺危。松須依石長，鶴不傍人卑。", "落葉頻驚鹿，連峰欲映雕。此生詩病苦，此病更蕭條。", "旅思又驚夏，庭前長小松。遠峰生貴氣，殘月斂衰容。", "林鳥頻窺靜，家人亦笑慵。舊居留穩枕，歸臥聽秋鐘。", "華宇知難保，燒來又卻修。只應巢燕惜，未必主人留。", "幽鳥穿籬去，鄰翁采藥回。雲從潭底出，花向佛前開。"]'),
('yuding-57','松滋渡二首','司空圖','唐','御定全唐诗','yuding','','[]','步上短亭久，看回官渡船。江鄉宜晚霽，楚老語豐年。',48,'御定全唐詩/json/632.json','["步上短亭久，看回官渡船。江鄉宜晚霽，楚老語豐年。", "楚岫接鄉思，茫茫歸路迷。更堪斑竹驛，初聽鷓鴣啼。"]'),
('yuding-58','華清宮','司空圖','唐','御定全唐诗','yuding','','[]','帝業山河固，離宮宴幸頻。豈知驅戰馬，只是太平人。',24,'御定全唐詩/json/632.json','["帝業山河固，離宮宴幸頻。豈知驅戰馬，只是太平人。"]'),
('yuding-59','牛頭寺','司空圖','唐','御定全唐诗','yuding','','[]','終南最佳處，禪誦出青霄。群木澄幽寂，疏煙泛泬寥。',24,'御定全唐詩/json/632.json','["終南最佳處，禪誦出青霄。群木澄幽寂，疏煙泛泬寥。"]'),
('yuding-60','感時上盧相','司空圖','唐','御定全唐诗','yuding','','[]','兵待皇威振，人隨國步安。萬方休望幸，封嶽始鳴鑾。',24,'御定全唐詩/json/632.json','["兵待皇威振，人隨國步安。萬方休望幸，封嶽始鳴鑾。"]'),
('yuding-61','亂後三首','司空圖','唐','御定全唐诗','yuding','','[]','喪亂家難保，艱虞病懶醫。空將憂國淚，猶擬灑丹墀。',72,'御定全唐詩/json/632.json','["喪亂家難保，艱虞病懶醫。空將憂國淚，猶擬灑丹墀。", "流芳能幾日，惆悵又聞蟬。行在多新貴，幽棲獨長年。", "世事嘗艱險，僧居慣寂寥。美香聞夜合，清景見寅朝。"]'),
('yuding-62','秋景','司空圖','唐','御定全唐诗','yuding','','[]','景物皆難駐，傷春複怨秋。旋書紅葉落，擬畫碧雲收。',24,'御定全唐詩/json/632.json','["景物皆難駐，傷春複怨秋。旋書紅葉落，擬畫碧雲收。"]'),
('yuding-63','避亂','司空圖','唐','御定全唐诗','yuding','','[]','離亂身偶在，竄跡任浮沉。虎暴荒居迥，螢孤黑夜深。',24,'御定全唐詩/json/632.json','["離亂身偶在，竄跡任浮沉。虎暴荒居迥，螢孤黑夜深。"]'),
('yuding-64','長亭','司空圖','唐','御定全唐诗','yuding','','[]','梅雨和鄉淚，終年共酒衣。殷勤華表鶴，羨爾亦曾歸。',24,'御定全唐詩/json/632.json','["梅雨和鄉淚，終年共酒衣。殷勤華表鶴，羨爾亦曾歸。"]'),
('yuding-65','村西杏花二首','司空圖','唐','御定全唐诗','yuding','','[]','薄膩力偏羸，看看愴別時。東風狂不惜，西子病難醫。',48,'御定全唐詩/json/632.json','["薄膩力偏羸，看看愴別時。東風狂不惜，西子病難醫。", "肌細分紅脈，香濃破紫苞。無因留得玩，爭忍折來拋。"]'),
('yuding-66','獨坐','司空圖','唐','御定全唐诗','yuding','','[]','幽徑入桑麻，塢西逢一家。編籬薪帶繭，補屋草和花。',24,'御定全唐詩/json/632.json','["幽徑入桑麻，塢西逢一家。編籬薪帶繭，補屋草和花。"]'),
('yuding-67','借居','司空圖','唐','御定全唐诗','yuding','','[]','借住郊園久，仍逢夏景新。綠苔行屐穩，黃鳥傍窗頻。',24,'御定全唐詩/json/632.json','["借住郊園久，仍逢夏景新。綠苔行屐穩，黃鳥傍窗頻。"]'),
('yuding-68','重陽','司空圖','唐','御定全唐诗','yuding','','[]','菊開猶阻雨，蝶意切於人。亦應知暮節，不比惜殘春。',24,'御定全唐詩/json/632.json','["菊開猶阻雨，蝶意切於人。亦應知暮節，不比惜殘春。"]'),
('yuding-69','偶書五首','司空圖','唐','御定全唐诗','yuding','','[]','衰謝當何懺，惟應悔壯圖。磬聲花外遠，人影塔前孤。',120,'御定全唐詩/json/632.json','["衰謝當何懺，惟應悔壯圖。磬聲花外遠，人影塔前孤。", "色變鶯雛長，竿齊筍籜垂。白頭身偶在，清夏景還移。", "蜀妓輕成妙，吳娃狎共纖。晚妝留拜月，卷上水精簾。", "獨步荒郊暮，沉思遠墅幽。平生多少事，彈指一時休。", "掩謗知迎吠，欺心見強顏。有名人易困，無契債難還。"]'),
('yuding-70','雜題九首','司空圖','唐','御定全唐诗','yuding','','[]','病來勝未病，名縛便忘名。今日甘為客，當時注湣征。',217,'御定全唐詩/json/632.json','["病來勝未病，名縛便忘名。今日甘為客，當時注湣征。", "暑濕深山雨，荒居破屋燈。此生無懺處，此去作高僧。", "不須頻悵望，且喜脫喧囂。亦有終焉意，陂南看稻苗。", "樓帶猿吟迥，庭容鶴舞寬。z4書因閱畫，封藥偶和丹。", "宴罷論詩久，亭高拜表頻。岸香蕃舶月，洲色海煙春。", "驛步堤縈閣，軍城鼓振橋。鷗和湖雁下，雪隔嶺梅飄。", "帶雪南山道，和鐘北闕明。太平當共賀，開化喝來聲。", "舴艋猿偷上，蜻蜓燕競飛。樵香燒桂子，苔濕掛莎衣。", "溪漲漁家近，煙收鳥道高。松花飄可惜，睡裏灑離騷。"]'),
('yuding-71','古樂府','司空圖','唐','御定全唐诗','yuding','','[]','一葉隨西風，君行亦向東。知妾飛書意，無勞待早鴻。',24,'御定全唐詩/json/632.json','["一葉隨西風，君行亦向東。知妾飛書意，無勞待早鴻。"]'),
('yuding-72','有感','司空圖','唐','御定全唐诗','yuding','','[]','燈影看須黑，牆陰惜草青。歲闌悲物我，同是冒霜螢。',24,'御定全唐詩/json/632.json','["燈影看須黑，牆陰惜草青。歲闌悲物我，同是冒霜螢。"]'),
('yuding-73','休休亭','司空圖','唐','御定全唐诗','yuding','','[]','且喜安能保，那堪病更憂。可憐藜杖者，真個種瓜侯。',24,'御定全唐詩/json/632.json','["且喜安能保，那堪病更憂。可憐藜杖者，真個種瓜侯。"]'),
('yuding-74','漫書二首','司空圖','唐','御定全唐诗','yuding','','[]','剩欲逢花折，判須冒雨頻。晴明開漸少，莫怕濕新巾。',48,'御定全唐詩/json/632.json','["剩欲逢花折，判須冒雨頻。晴明開漸少，莫怕濕新巾。", "小蝶爾何競，追飛不憚勞。遠教群雀見，寧悟禍梯高。"]'),
('yuding-75','歲盡二首','司空圖','唐','御定全唐诗','yuding','','[]','明日添一歲，端憂奈爾何。沖寒出洞口，猶校夕陽多。',48,'御定全唐詩/json/632.json','["明日添一歲，端憂奈爾何。沖寒出洞口，猶校夕陽多。", "莫話傷心事，投春滿鬢霜。殷勤共尊酒，今歲只殘陽。"]'),
('yuding-76','牡丹','司空圖','唐','御定全唐诗','yuding','','[]','得地牡丹盛，曉添龍麝香。主人猶自惜，錦幕護春霜。',24,'御定全唐詩/json/632.json','["得地牡丹盛，曉添龍麝香。主人猶自惜，錦幕護春霜。"]'),
('yuding-77','亂後','司空圖','唐','御定全唐诗','yuding','','[]','羽書傳棧道，風火隔鄉關。病眼那堪泣，傷心不到間。',24,'御定全唐詩/json/632.json','["羽書傳棧道，風火隔鄉關。病眼那堪泣，傷心不到間。"]'),
('yuding-78','春山','司空圖','唐','御定全唐诗','yuding','','[]','可是武陵溪，春芳著路迷。花明催曙早，雲膩惹空低。',24,'御定全唐詩/json/632.json','["可是武陵溪，春芳著路迷。花明催曙早，雲膩惹空低。"]'),
('yuding-79','樂府','司空圖','唐','御定全唐诗','yuding','','[]','寶馬跋塵光，雙馳照路旁。喧傳報戚裏，明日幸長楊。',24,'御定全唐詩/json/632.json','["寶馬跋塵光，雙馳照路旁。喧傳報戚裏，明日幸長楊。"]'),
('yuding-80','亂前上盧相','司空圖','唐','御定全唐诗','yuding','','[]','虜黠雖多變，兵驕即易乘。猶須勞斥候，勿遣大河冰。',24,'御定全唐詩/json/632.json','["虜黠雖多變，兵驕即易乘。猶須勞斥候，勿遣大河冰。"]'),
('yuding-0','有感','司空圖','唐','御定全唐诗','yuding','','[]','國事皆須救未然，漢家高閣漫淩煙。',32,'御定全唐詩/json/633.json','["國事皆須救未然，漢家高閣漫淩煙。", "功臣盡遣詞人贊，不省滄洲畫魯連。"]'),
('yuding-1','歌','司空圖','唐','御定全唐诗','yuding','','[]','處處亭台只壞牆，軍營人學內人妝。',32,'御定全唐詩/json/633.json','["處處亭台只壞牆，軍營人學內人妝。", "太平故事因君唱，馬上曾聽隔教坊。"]'),
('yuding-2','偈','司空圖','唐','御定全唐诗','yuding','','[]','人若憎時我亦憎，逃名最要是無能。',32,'御定全唐詩/json/633.json','["人若憎時我亦憎，逃名最要是無能。", "後生乞汝殘風月，自作深林不語僧。"]'),
('yuding-3','鸝','司空圖','唐','御定全唐诗','yuding','','[]','不是流鶯獨佔春，林間彩翠四時新。',32,'御定全唐詩/json/633.json','["不是流鶯獨佔春，林間彩翠四時新。", "應知擬上屏風畫，偏坐橫枝亦向人。"]'),
('yuding-4','白菊雜書四首','司空圖','唐','御定全唐诗','yuding','','[]','黃昏寒立更披襟，露浥清香悅道心。',128,'御定全唐詩/json/633.json','["黃昏寒立更披襟，露浥清香悅道心。", "卻笑誰家扃繡戶，正熏龍麝暖鴛衾。", "四面雲屏一帶天，是非斷得自翛然。", "此生只是償詩債，白菊開時最不眠。", "狂才不足自英雄，僕妾驅令學販舂。", "侯印幾人封萬戶，儂家只辦買孤峰。", "黃鸝囀處誰同聽，白菊開時且剩過。", "漫道南朝足流品，由來叔寶不宜多。"]'),
('yuding-5','漫題','司空圖','唐','御定全唐诗','yuding','','[]','經亂年年厭別離，歌聲喜似太平時。',32,'御定全唐詩/json/633.json','["經亂年年厭別離，歌聲喜似太平時。", "詞臣更有中興頌，磨取蓮峰便作碑。"]'),
('yuding-6','率題','司空圖','唐','御定全唐诗','yuding','','[]','宦路前銜閑不記，醉鄉佳境興方濃。',32,'御定全唐詩/json/633.json','["宦路前銜閑不記，醉鄉佳境興方濃。", "一林高竹長遮日，四壁寒山更閏冬。"]'),
('yuding-7','澗戶','司空圖','唐','御定全唐诗','yuding','','[]','澗戶芳煙接水村，亂來歸得道仍存。',32,'御定全唐詩/json/633.json','["澗戶芳煙接水村，亂來歸得道仍存。", "數竿新竹當軒上，不羨侯家立戟門。"]'),
('yuding-8','故鄉杏花','司空圖','唐','御定全唐诗','yuding','','[]','寄花寄酒喜新開，左把花枝右把杯。',32,'御定全唐詩/json/633.json','["寄花寄酒喜新開，左把花枝右把杯。", "欲問花枝與杯酒，故人何得不同來。"]'),
('yuding-9','華上二首','司空圖','唐','御定全唐诗','yuding','','[]','故國春歸未有涯，小欄高檻別人家。',64,'御定全唐詩/json/633.json','["故國春歸未有涯，小欄高檻別人家。", "五更惆悵回孤枕，猶自殘燈照落花。", "關外風昏欲雨天，薺花耕倒枕河壖。", "村南寂寞時回望，一隻鴛鴦下渡船。"]'),
('yuding-10','夢中','司空圖','唐','御定全唐诗','yuding','','[]','幾多親愛在人間，上徹霞梯會卻還。',32,'御定全唐詩/json/633.json','["幾多親愛在人間，上徹霞梯會卻還。", "須是蓬瀛長買得，一家同占作家山。"]'),
('yuding-11','榜下','司空圖','唐','御定全唐诗','yuding','','[]','三十功名志未伸，初將文字競通津。',32,'御定全唐詩/json/633.json','["三十功名志未伸，初將文字競通津。", "春風漫折一枝桂，煙閣英雄笑殺人。"]'),
('yuding-12','涔陽渡','司空圖','唐','御定全唐诗','yuding','','[]','楚田人立帶殘暉，驛迥村幽客路微。',32,'御定全唐詩/json/633.json','["楚田人立帶殘暉，驛迥村幽客路微。", "兩岸蘆花正蕭颯，渚煙深處白牛歸。"]'),
('yuding-13','偶作','司空圖','唐','御定全唐诗','yuding','','[]','索得身歸未保閑，亂來道在辱來頑。',32,'御定全唐詩/json/633.json','["索得身歸未保閑，亂來道在辱來頑。", "留侯萬戶雖無分，病骨應消一片山。"]'),
('yuding-14','寓居有感三首','司空圖','唐','御定全唐诗','yuding','','[]','亦知世路薄忠貞，不忍殘年負聖明。',96,'御定全唐詩/json/633.json','["亦知世路薄忠貞，不忍殘年負聖明。", "只待東封沾慶賜，碑陰別刻老臣名。", "不放殘年卻到家，銜杯懶更問生涯。", "河堤往往人相送，一曲晴川隔蓼花。", "黑須寄在白須生，一度秋風減幾莖。", "客處不堪頻送別，無多情緒更傷情。"]'),
('yuding-15','淮西','司空圖','唐','御定全唐诗','yuding','','[]','鼇冠三山安海浪，龍盤九鼎鎮皇都。',32,'御定全唐詩/json/633.json','["鼇冠三山安海浪，龍盤九鼎鎮皇都。", "莫誇十萬兵威盛，消個忠良效順無。"]'),
('yuding-16','河湟有感','司空圖','唐','御定全唐诗','yuding','','[]','一自蕭關起戰塵，河湟隔斷異鄉春。',32,'御定全唐詩/json/633.json','["一自蕭關起戰塵，河湟隔斷異鄉春。", "漢兒盡作胡兒語，卻向城頭罵漢人。"]'),
('yuding-17','自gM鄉北歸','司空圖','唐','御定全唐诗','yuding','','[]','巴煙冪冪久縈恨，楚柳綿綿今送歸。',32,'御定全唐詩/json/633.json','["巴煙冪冪久縈恨，楚柳綿綿今送歸。", "回避江邊同去雁，莫教驚起錯南飛。"]'),
('yuding-18','青龍師安上人','司空圖','唐','御定全唐诗','yuding','','[]','災曜偏臨許國人，雨中衰菊病中身。',32,'御定全唐詩/json/633.json','["災曜偏臨許國人，雨中衰菊病中身。", "清香一炷知師意，應為昭陵惜老臣。"]'),
('yuding-19','山中','司空圖','唐','御定全唐诗','yuding','','[]','凡鳥愛喧人靜處，閑雲似妒月明時。',32,'御定全唐詩/json/633.json','["凡鳥愛喧人靜處，閑雲似妒月明時。", "世間萬事非吾事，只愧秋來未有詩。"]'),
('yuding-20','有感二首','司空圖','唐','御定全唐诗','yuding','','[]','自古經綸足是非，陰謀最忌奪天機。',64,'御定全唐詩/json/633.json','["自古經綸足是非，陰謀最忌奪天機。", "留侯卻粒商翁去，甲第何人意氣歸。", "古來賢俊共悲辛，長是豪家拒要津。", "從此當歌唯痛飲，不須經世為閒人。"]'),
('yuding-21','閑夜二首','司空圖','唐','御定全唐诗','yuding','','[]','道侶難留為虐棋，鄰家聞說厭吟詩。',64,'御定全唐詩/json/633.json','["道侶難留為虐棋，鄰家聞說厭吟詩。", "前峰月照分明見，夜合香中露臥時。", "此身閑得易為家，業是吟詩與看花。", "若使他生拋筆硯，更應無事老煙霞。"]'),
('yuding-22','雨中','司空圖','唐','御定全唐诗','yuding','','[]','維摩居士陶居士，盡說高情未足誇。',32,'御定全唐詩/json/633.json','["維摩居士陶居士，盡說高情未足誇。", "簷外蓮峰階下菊，碧蓮黃菊是吾家。"]'),
('yuding-23','送道者二首','司空圖','唐','御定全唐诗','yuding','','[]','洞天真侶昔曾逢，西嶽今居第幾峰。',64,'御定全唐詩/json/633.json','["洞天真侶昔曾逢，西嶽今居第幾峰。", "峰頂他時教我認，相招須把碧芙蓉。", "殷勤不為學燒金，道侶惟應識此心。", "雪裏千山訪君易，微微鹿跡入深林。"]'),
('yuding-24','重陽阻雨','司空圖','唐','御定全唐诗','yuding','','[]','重陽阻雨獨銜杯，移得山家菊未開。',32,'御定全唐詩/json/633.json','["重陽阻雨獨銜杯，移得山家菊未開。", "猶勝登高閑望斷，孤煙殘照馬嘶回。"]'),
('yuding-25','省試','司空圖','唐','御定全唐诗','yuding','','[]','粉闈深鎖唱同人，正是終南雪霽春。',32,'御定全唐詩/json/633.json','["粉闈深鎖唱同人，正是終南雪霽春。", "閑系長安千匹馬，今朝似減六街塵。"]'),
('yuding-26','有贈','司空圖','唐','御定全唐诗','yuding','','[]','有詩有酒有高歌，春色年年奈我何。',32,'御定全唐詩/json/633.json','["有詩有酒有高歌，春色年年奈我何。", "試問羲和能駐否，不勞頻借魯陽戈。"]'),
('yuding-27','證因亭','司空圖','唐','御定全唐诗','yuding','','[]','峰北幽亭願證因，他生此地卻容身。',32,'御定全唐詩/json/633.json','["峰北幽亭願證因，他生此地卻容身。", "上方僧在時應到，笑認前銜記寫真。"]'),
('yuding-28','頃年陪恩地赴甘棠之召感動留題','司空圖','唐','御定全唐诗','yuding','','[]','去時憔悴青衿在，歸路淒涼絳帳空。',32,'御定全唐詩/json/633.json','["去時憔悴青衿在，歸路淒涼絳帳空。", "無限酬恩心未展，又將孤劍別從公。"]'),
('yuding-29','九月八日','司空圖','唐','御定全唐诗','yuding','','[]','已是人間寂寞花，解憐寂寞傍貧家。',32,'御定全唐詩/json/633.json','["已是人間寂寞花，解憐寂寞傍貧家。", "老來不得登高看，更甚殘春惜歲華。"]'),
('yuding-30','敷溪橋院有感','司空圖','唐','御定全唐诗','yuding','','[]','昔歲攀遊景物同，藥爐今在鶴歸空。',32,'御定全唐詩/json/633.json','["昔歲攀遊景物同，藥爐今在鶴歸空。", "青山滿眼淚堪碧，絳帳無人花自紅。"]'),
('yuding-31','寺閣','司空圖','唐','御定全唐诗','yuding','','[]','昔歲登臨未衰颯，不知何事愛傷情。',32,'御定全唐詩/json/633.json','["昔歲登臨未衰颯，不知何事愛傷情。", "今來攬鏡翻堪喜，亂後霜須長幾莖。"]'),
('yuding-32','武陵路','司空圖','唐','御定全唐诗','yuding','','[]','橘岸舟間罾網掛，茶坡日暖鷓鴣啼。',32,'御定全唐詩/json/633.json','["橘岸舟間罾網掛，茶坡日暖鷓鴣啼。", "女郎指點行人笑，知向花間路已迷。"]'),
('yuding-33','南北史感遇十首','司空圖','唐','御定全唐诗','yuding','','[]','雨淋麟閣名臣畫，雪臥龍庭猛將碑。',320,'御定全唐詩/json/633.json','["雨淋麟閣名臣畫，雪臥龍庭猛將碑。", "不用黃金鑄侯印，盡輸公子買蛾眉。", "漢世頻封萬戶侯，雲台空峻謝風流。", "江南不有名儒相，齒冷中原笑未休。", "天風斡海怒長鯨，永固南來百萬兵。", "若向滄洲猶笑傲，江山虛有石頭城。", "花迷公子玉樓恩，鏡弄佳人紅粉春。", "不信關山勞遠戍，綺羅香外任行塵。", "兵圍梁殿金甌破，火發陳宮玉樹摧。", "奸佞豈能慚誤國，空令懷古更徘徊。", "行樂最宜連夜景，太平方覺有春風。", "千金盡把酬歌舞，猶勝三邊賞戰功。", "桃芳李豔年年發，羌管蠻弦處處多。", "海上應無三島路，人間惟有一聲歌。", "佳人自折一枝紅，把唱新詞曲未終。", "惟向眼前憐易落，不如拋擲任春風。", "景陽樓下花鈿鏡，玄武湖邊錦繡旗。", "昔日繁華今日恨，雉媒聲晚草芳時。", "亂後人間盡不平，秦川花木最傷情。", "無窮紅豔紅塵裏，驟馬分香散入營。"]'),
('yuding-34','狂題二首','司空圖','唐','御定全唐诗','yuding','','[]','草堂舊隱猶招我，煙閣英才不見君。',64,'御定全唐詩/json/633.json','["草堂舊隱猶招我，煙閣英才不見君。", "惆悵故山歸未得，酒狂叫斷暮天雲。", "須知世亂身難保，莫喜天晴菊並開。", "長短此身長是客，黃花更助白頭催。"]'),
('yuding-35','紅茶花','司空圖','唐','御定全唐诗','yuding','','[]','景物詩人見即誇，豈憐高韻說紅茶。',32,'御定全唐詩/json/633.json','["景物詩人見即誇，豈憐高韻說紅茶。", "牡丹枉用三春力，開得方知不是花。"]'),
('yuding-36','秋燕','司空圖','唐','御定全唐诗','yuding','','[]','從撲香塵拂面飛，憐渠只為解相依。',32,'御定全唐詩/json/633.json','["從撲香塵拂面飛，憐渠只為解相依。", "經冬好近深爐暖，何必千岩萬水歸。"]'),
('yuding-37','見後雁有感','司空圖','唐','御定全唐诗','yuding','','[]','笑爾窮通亦似人，高飛偶滯莫悲辛。',32,'御定全唐詩/json/633.json','["笑爾窮通亦似人，高飛偶滯莫悲辛。", "卻緣風雪頻相阻，只向關中待得春。"]'),
('yuding-38','移桃栽','司空圖','唐','御定全唐诗','yuding','','[]','獨臨官路易傷摧，從遣春風恣意開。',32,'御定全唐詩/json/633.json','["獨臨官路易傷摧，從遣春風恣意開。", "禪客笑移山上看，流鶯直到檻前來。"]'),
('yuding-39','憶中條','司空圖','唐','御定全唐诗','yuding','','[]','燕辭旅舍人空在，螢出疏籬菊正芳。',32,'御定全唐詩/json/633.json','["燕辭旅舍人空在，螢出疏籬菊正芳。", "堪恨昔年聯句地，念經僧掃過重陽。"]'),
('yuding-40','樂府','司空圖','唐','御定全唐诗','yuding','','[]','五更窗下簇妝台，已怕堂前阿母催。',32,'御定全唐詩/json/633.json','["五更窗下簇妝台，已怕堂前阿母催。", "滿鴨香熏鸚鵡睡，隔簾燈照牡丹開。"]'),
('yuding-41','放龜二首','司空圖','唐','御定全唐诗','yuding','','[]','卻為多知自不靈，今朝教汝卜長生。',64,'御定全唐詩/json/633.json','["卻為多知自不靈，今朝教汝卜長生。", "若求深處無深處，只有依人會有情。", "世外猶迷不死庭，人間莫恃自無營。", "本期滄海堪投跡，卻向朱門待放生。"]'),
('yuding-42','燈花三首','司空圖','唐','御定全唐诗','yuding','','[]','蜀柳絲絲冪畫樓，窗塵滿鏡不梳頭。',96,'御定全唐詩/json/633.json','["蜀柳絲絲冪畫樓，窗塵滿鏡不梳頭。", "幾時金雁傳歸信，剪斷香魂一縷愁。", "姊姊教人且抱兒，逐他女伴卸頭遲。", "明朝鬥草多應喜，翦得燈花自掃眉。", "閏前小雪過經旬，猶自依依向主人。", "開盡菊花憐強舞，與教弟子待新春。"]'),
('yuding-43','偶題三首','司空圖','唐','御定全唐诗','yuding','','[]','浮世悠悠旋一空，多情偏解挫英雄。',96,'御定全唐詩/json/633.json','["浮世悠悠旋一空，多情偏解挫英雄。", "風光只在歌聲裏，不必樓前萬樹紅。", "小池隨事有風荷，燒酹傾壺一曲歌。", "欲待秋塘擎露看，自憐生意已無多。", "遼陽音信近來稀，縱有虛傳逼節歸。", "永日無人新睡覺，小窗晴暖螖蟲飛。"]'),
('yuding-44','華下對菊','司空圖','唐','御定全唐诗','yuding','','[]','清香裛露對高齋，泛酒偏能浣旅懷。',32,'御定全唐詩/json/633.json','["清香裛露對高齋，泛酒偏能浣旅懷。", "不似春風逞紅豔，鏡前空墜玉人釵。"]'),
('yuding-45','與都統參謀書有感','司空圖','唐','御定全唐诗','yuding','','[]','驚鸞迸鷺盡歸林，弱羽低垂分獨沈。',32,'御定全唐詩/json/633.json','["驚鸞迸鷺盡歸林，弱羽低垂分獨沈。", "帶病深山猶草檄，昭陵應識老臣心。"]'),
('yuding-46','漫題','司空圖','唐','御定全唐诗','yuding','','[]','無宦無名拘逸興，有歌有酒任他鄉。',32,'御定全唐詩/json/633.json','["無宦無名拘逸興，有歌有酒任他鄉。", "看看萬里休征戍，莫向新詞寄斷腸。"]'),
('yuding-47','商山二首','司空圖','唐','御定全唐诗','yuding','','[]','清溪一路照羸身，不似雲台畫像人。',64,'御定全唐詩/json/633.json','["清溪一路照羸身，不似雲台畫像人。", "國史數行猶有志，只將談笑繼英塵。", "馬上搜奇已數篇，籍中猶愧是頑仙。", "關頭傳說開元事，指點多疑孟浩然。"]'),
('yuding-48','與伏牛長老偈二首','司空圖','唐','御定全唐诗','yuding','','[]','不算菩提與闡提，惟應執著便生迷。',64,'御定全唐詩/json/633.json','["不算菩提與闡提，惟應執著便生迷。", "無端指個清涼地，凍殺胡僧雪嶺西。", "長繩不見系空虛，半偈傳心亦未疏。", "推倒我山無一事，莫將文字縛真如。"]'),
('yuding-49','客中重九','司空圖','唐','御定全唐诗','yuding','','[]','楚老相逢淚滿衣，片名薄宦已知非。',32,'御定全唐詩/json/633.json','["楚老相逢淚滿衣，片名薄宦已知非。", "他鄉不似人間路，應共東流更不歸。"]'),
('yuding-50','柳二首','司空圖','唐','御定全唐诗','yuding','','[]','誰家按舞傍池塘，已見繁枝嫩眼黃。',64,'御定全唐詩/json/633.json','["誰家按舞傍池塘，已見繁枝嫩眼黃。", "漫說早梅先得意，不知春力暗分張。", "似擬淩寒妒早梅，無端弄色傍高臺。", "折來未有新枝長，莫遣佳人更折來。"]'),
('yuding-51','光啟丁未別山','司空圖','唐','御定全唐诗','yuding','','[]','草堂琴畫已判燒，猶托鄰僧護燕巢。',32,'御定全唐詩/json/633.json','["草堂琴畫已判燒，猶托鄰僧護燕巢。", "此去不緣名利去，若逢逋客莫相嘲。"]'),
('yuding-52','石楠','司空圖','唐','御定全唐诗','yuding','','[]','客處偷閒未是閑，石楠雖好懶頻攀。',32,'御定全唐詩/json/633.json','["客處偷閒未是閑，石楠雖好懶頻攀。", "如何風葉西歸路，吹斷寒雲見故山。"]'),
('yuding-53','力疾馬上走筆','司空圖','唐','御定全唐诗','yuding','','[]','釀黍長添不盡杯，只憂花盡客空回。',32,'御定全唐詩/json/633.json','["釀黍長添不盡杯，只憂花盡客空回。", "垂楊且為晴遮日，留遇重陽即放開。"]'),
('yuding-54','華陰縣樓','司空圖','唐','御定全唐诗','yuding','','[]','丹霄能有幾層梯，懶更揚鞭聳翠蜺。偶憑危欄且南望，不勞高掌欲相攜。',32,'御定全唐詩/json/633.json','["丹霄能有幾層梯，懶更揚鞭聳翠蜺。偶憑危欄且南望，不勞高掌欲相攜。"]'),
('yuding-55','南至四首','司空圖','唐','御定全唐诗','yuding','','[]','今冬臘後無殘日，故國燒來有幾家。',128,'御定全唐詩/json/633.json','["今冬臘後無殘日，故國燒來有幾家。", "卻恨早梅添旅思，強偷春力報年華。", "花時不是偏愁我，好事應難總取他。", "已被詩魔長役思，眼中莫厭早梅多。", "年華亂後偏堪惜，世路拋來已自生。", "猶有玉真長命縷，樽前時唱緩羈情。", "一任喧闐繞四鄰，閑忙皆是自由身。", "人來客去還須議，莫遣他人作主人。"]'),
('yuding-56','蓮峰前軒','司空圖','唐','御定全唐诗','yuding','','[]','人間上壽若能添，只向人間也不嫌。',32,'御定全唐詩/json/633.json','["人間上壽若能添，只向人間也不嫌。", "看著四鄰花競發，高樓從此莫垂簾。"]'),
('yuding-57','步虛','司空圖','唐','御定全唐诗','yuding','','[]','阿母親教學步虛，三元長遣下蓬壺。',32,'御定全唐詩/json/633.json','["阿母親教學步虛，三元長遣下蓬壺。", "雲韶韻俗停瑤瑟，鸞鶴飛低拂寶爐。"]'),
('yuding-58','劍器','司空圖','唐','御定全唐诗','yuding','','[]','樓下公孫昔擅場，空教女子愛軍裝。',32,'御定全唐詩/json/633.json','["樓下公孫昔擅場，空教女子愛軍裝。", "潼關一敗吳兒喜，簇馬驪山看禦湯。"]'),
('yuding-59','乙丑人日','司空圖','唐','御定全唐诗','yuding','','[]','自怪扶持七十身，歸來又見故鄉春。',32,'御定全唐詩/json/633.json','["自怪扶持七十身，歸來又見故鄉春。", "今朝人日逢人喜，不料偷生作老人。"]'),
('yuding-60','攜仙籙九首','司空圖','唐','御定全唐诗','yuding','','[]','嶽北秋空渭北川，晴雲漸薄薄如煙。',288,'御定全唐詩/json/633.json','["嶽北秋空渭北川，晴雲漸薄薄如煙。", "坐來還見微風起，吹散殘陽一片蟬。", "一半晴空一半雲，遠籠仙掌日初曛。", "洞天有路不知處，絕頂異香難更聞。", "決事還須更事酬，清譚妙理一時休。", "漁翁亦被機心誤，眼暗汀邊結釣鉤。", "跡不趨時分不侯，功名身外最悠悠。", "聽君總畫麒麟閣，還我閑眠舴艋舟。", "仙凡路阻兩難留，煙樹人間一片秋。", "若道陰功能濟活，且將方寸自焚修。", "若有陰功救未然，玉皇品籍亦搜賢。", "應知譚笑還高謝，別就滄洲贊上仙。", "英名何用苦搜奇，不朽才銷一句詩。", "卻賴風波阻三島，老臣猶得戀明時。", "剪取紅雲剩寫詩，年年高會趁花時。", "水精樓閣分明見，只欠霞漿別著旗。", "此生得作太平人，只向塵中便出塵。", "移取碧桃花萬樹，年年自樂故鄉春。"]'),
('yuding-61','浪淘沙','司空圖','唐','御定全唐诗','yuding','','[]','不必長漂玉洞花，曲中偏愛浪淘沙。',32,'御定全唐詩/json/633.json','["不必長漂玉洞花，曲中偏愛浪淘沙。", "黃河卻勝天河水，萬里縈紆入漢家。"]'),
('yuding-62','贈日東鑒禪師','司空圖','唐','御定全唐诗','yuding','','[]','故國無心度海潮，老禪方丈倚中條。',32,'御定全唐詩/json/633.json','["故國無心度海潮，老禪方丈倚中條。", "夜深雨絕松堂靜，一點飛螢照寂寥。"]'),
('yuding-63','暮春對柳二首','司空圖','唐','御定全唐诗','yuding','','[]','縈愁惹恨奈楊花，閉戶垂簾亦滿家。',64,'御定全唐詩/json/633.json','["縈愁惹恨奈楊花，閉戶垂簾亦滿家。", "惱得閒人作酒病，剛須又撲越溪茶。", "洞中猶說看桃花，輕絮狂飛自俗家。", "正是階前開遠信，小娥旋拂碾新茶。"]'),
('yuding-64','戊午三月晦二首','司空圖','唐','御定全唐诗','yuding','','[]','隨風逐浪劇蓬萍，圓首何曾解最靈。',64,'御定全唐詩/json/633.json','["隨風逐浪劇蓬萍，圓首何曾解最靈。", "筆硯近來多自棄，不關妖氣暗文星。", "牛誇棋品無勍敵，謝占詩家作上流。", "豈似小敷春水漲，年年鸞鶴待仙舟。"]'),
('yuding-65','偶書五首','司空圖','唐','御定全唐诗','yuding','','[]','情知了得未如僧，客處高樓莫強登。',160,'御定全唐詩/json/633.json','["情知了得未如僧，客處高樓莫強登。", "鶯也解啼花也發，不關心事最堪憎。", "自有池荷作扇搖，不關風動愛芭蕉。", "只憐直上抽紅蕊，似我丹心向本朝。", "曾看輕舟渡遠津，無風著岸不經旬。", "只緣命蹇須知命，卻是人爭阻得人。", "上谷何曾解有情，有情人自惜君行。", "證因池上今生願，的的他生作化生。", "新店南原後夜程，黃河風浪信難平。", "渡頭楊柳知人意，為惹官船莫放行。"]'),
('yuding-66','喜山鵲初歸三首','司空圖','唐','御定全唐诗','yuding','','[]','翠衿紅觜便知機，久避重羅穩處飛。',96,'御定全唐詩/json/633.json','["翠衿紅觜便知機，久避重羅穩處飛。", "只為從來偏護惜，窗前今賀主人歸。", "山中只是惜珍禽，語不分明識爾心。", "若使解言天下事，燕台今築幾千金。", "阻他羅網到柴扉，不奈偷倉雀轉肥。", "賴爾林塘添景趣，剩留山果引教歸。"]'),
('yuding-67','虞鄉北原','司空圖','唐','御定全唐诗','yuding','','[]','澤北村貧煙火獰，稚田冬旱倩牛耕。',32,'御定全唐詩/json/633.json','["澤北村貧煙火獰，稚田冬旱倩牛耕。", "老人惆悵逢人訴，開盡黃花麥未金。"]'),
('yuding-68','洛中三首','司空圖','唐','御定全唐诗','yuding','','[]','秋風團扇未驚心，笑看妝台落葉侵。',96,'御定全唐詩/json/633.json','["秋風團扇未驚心，笑看妝台落葉侵。", "繡鳳不教金縷暗，青樓何處有寒砧。", "不用頻嗟世路難，浮生各自系悲歡。", "風霜一夜添羈思，羅綺誰家待早寒。", "燕巢空後誰相伴，鴛被縫來不忍熏。", "薄命敢辭長滴淚，倡家未必肯留君。"]'),
('yuding-69','寓筆','司空圖','唐','御定全唐诗','yuding','','[]','年年鑷鬢到花飄，依舊花繁鬢易凋。',32,'御定全唐詩/json/633.json','["年年鑷鬢到花飄，依舊花繁鬢易凋。", "撩亂一場人更恨，春風誰道勝輕飆。"]'),
('yuding-70','戲題試衫','司空圖','唐','御定全唐诗','yuding','','[]','朝班盡說人宜紫，洞府應無鶴著緋。',32,'御定全唐詩/json/633.json','["朝班盡說人宜紫，洞府應無鶴著緋。", "從此玉皇須破例，染霞裁賜地仙衣。"]'),
('yuding-71','汴柳半枯因悲柳中隱','司空圖','唐','御定全唐诗','yuding','','[]','行人莫歎前朝樹，已占河堤幾百春。',32,'御定全唐詩/json/633.json','["行人莫歎前朝樹，已占河堤幾百春。", "惆悵題詩柳中隱，柳衰猶在自無身。"]'),
('yuding-72','上方','司空圖','唐','御定全唐诗','yuding','','[]','花落更同悲木落，鶯聲相續即蟬聲。',32,'御定全唐詩/json/633.json','["花落更同悲木落，鶯聲相續即蟬聲。", "榮枯了得無多事，只是閒人漫系情。"]'),
('yuding-73','寄王贊學','司空圖','唐','御定全唐诗','yuding','','[]','黃卷不關兼濟業，青山自保老閑身。',32,'御定全唐詩/json/633.json','["黃卷不關兼濟業，青山自保老閑身。", "一行萬里纖塵靜，可要張儀更入秦。"]'),
('yuding-74','新節','司空圖','唐','御定全唐诗','yuding','','[]','轉悲新歲重於山，不似輕鷗肯複還。',32,'御定全唐詩/json/633.json','["轉悲新歲重於山，不似輕鷗肯複還。", "朱紱縱教金印換，青雲未勝白頭閑。"]'),
('yuding-75','自河西歸山二首','司空圖','唐','御定全唐诗','yuding','','[]','一水悠悠一葉危，往來長恨阻歸期。',64,'御定全唐詩/json/633.json','["一水悠悠一葉危，往來長恨阻歸期。", "鄉關不是無華表，自為多驚獨上遲。", "水闊風驚去路危，孤舟欲上更遲遲。", "鶴群長擾三珠樹，不借人間一隻騎。"]'),
('yuding-76','王官二首','司空圖','唐','御定全唐诗','yuding','','[]','風荷似醉和花舞，沙鳥無情伴客閑。',64,'御定全唐詩/json/633.json','["風荷似醉和花舞，沙鳥無情伴客閑。", "總是此中皆有恨，更堪微雨半遮山。", "荷塘煙罩小齋虛，景物皆宜入畫圖。", "盡日無人只高臥，一雙白鳥隔紗廚。"]'),
('yuding-77','賀翰林侍郎二首','司空圖','唐','御定全唐诗','yuding','','[]','太白東歸鶴背吟，鏡湖空在酒船沈。',64,'御定全唐詩/json/633.json','["太白東歸鶴背吟，鏡湖空在酒船沈。", "今朝忽見銀台事，早晚重征入翰林。", "玉版征書洞裏看，沈羲新拜侍郎官。", "文星喜氣連台曜，聖主方知四海安。"]'),
('yuding-78','寄王十四舍人','司空圖','唐','御定全唐诗','yuding','','[]','幾年汶上約同遊，擬為蓮峰別置樓。',32,'御定全唐詩/json/633.json','["幾年汶上約同遊，擬為蓮峰別置樓。", "今日鳳凰池畔客，五千仞雪不回頭。"]'),
('yuding-79','綸閣有感','司空圖','唐','御定全唐诗','yuding','','[]','風濤曾阻化鱗來，誰料蓬瀛路卻開。',32,'御定全唐詩/json/633.json','["風濤曾阻化鱗來，誰料蓬瀛路卻開。", "欲去遲遲還自笑，狂才應不是仙才。"]'),
('yuding-0','狂題十八首','司空圖','唐','御定全唐诗','yuding','','[]','莫恨艱危日日多，時情其奈幸門何。',384,'御定全唐詩/json/634.json','["莫恨艱危日日多，時情其奈幸門何。", "貔貅睡穩蛟龍渴，猶把燒殘朽鐵磨。", "別鶴淒涼指法存，戴逵能恥近王門。", "世間第一風流事，借得王公玉枕痕。", "交疏自古戒言深，肝膽徒傾致鑠金。", "不是史遷書與說，誰知孤負李陵心。", "南華落筆似荒唐，若肯經綸亦不狂。", "偶作客星侵帝座，卻應虛薄是嚴光。", "不勞世路更相猜，忍到須休惜得材。", "幾度懶乘風水便，拗船折舵恐難回。", "由來相愛只詩僧，怪石長松自得朋。", "卻怕他生還識字，依前日下作孤燈。", "老禪乘仗莫過身，遠岫孤雲見亦頻。", "應是佛邊猶怕鬧，信緣須作且閒人。", "止竟閒人不愛閑，只偷無事閉柴關。", "轟霆攪破蛟龍窟，也被狂風卷出山。", "地下修文著作郎，生前饑處倒空牆。", "何如神爽騎星去，猶自研幾助玉皇。", "雨洗芭蕉葉上詩，獨來憑檻晚晴時。", "故園雖恨風荷膩，新句閑題亦滿池。", "初時拄杖向鄰村，漸到清明亦杜門。", "三十年來辭病表，今朝臥病感皇恩。", "來時雖恨失青氈，自見芭蕉幾十篇。", "應是阿劉還宿債，剩拚才思折供錢。"]'),
('yuding-1','遊仙二首','司空圖','唐','御定全唐诗','yuding','','[]','蛾眉新畫覺嬋娟，鬥走將花阿母邊。',64,'御定全唐詩/json/634.json','["蛾眉新畫覺嬋娟，鬥走將花阿母邊。", "仙曲教成慵不理，玉階相簇打金錢。", "劉郎相約事難諧，雨散雲飛自此乖。", "月姊殷勤留不住，碧空遺下水精釵。"]'),
('yuding-2','漫書五首','司空圖','唐','御定全唐诗','yuding','','[]','長擬求閑未得閒，又勞行役出秦關。',160,'御定全唐詩/json/634.json','["長擬求閑未得閒，又勞行役出秦關。", "逢人漸覺鄉音異，卻恨鶯聲似故山。", "溪邊隨事有桑麻，盡日山程十數家。", "莫怪行人頻悵望，杜鵑不是故鄉花。", "海上昔聞麋愛鶴，山中今日鹿憎龜。", "愛憎止竟須關分，莫把微才望所知。", "世路快心無好事，恩門嘉話合書紳。", "神藏鬼伏能千變，亦勝忘機避要津。", "四翁識勢保安閒，須為生靈暫出山。", "一種老人能算度，磻溪心跡愧商顏。"]'),
('yuding-3','偶詩五首','司空圖','唐','御定全唐诗','yuding','','[]','閑韻雖高不衒才，偶拋猿鳥乍歸來。',160,'御定全唐詩/json/634.json','["閑韻雖高不衒才，偶拋猿鳥乍歸來。", "夕陽照個新紅葉，似要題詩落硯臺。", "芙蓉騷客空留怨，芍藥詩家只寄情。", "誰似天才李山甫，牡丹屬思亦縱橫。", "賢豪出處盡沉吟，白日高懸只照心。", "一掬信陵墳上土，便如碣石累千金。", "聲貌由來固絕倫，今朝共許占殘春。", "當歌莫怪頻垂淚，得地翻慚早失身。", "中宵茶鼎沸時驚，正是寒窗竹雪明。", "甘得寂寥能到老，一生心地亦應平。"]'),
('yuding-4','雜題二首','司空圖','唐','御定全唐诗','yuding','','[]','先知左袒始同行，須待龍樓羽翼成。',64,'御定全唐詩/json/634.json','["先知左袒始同行，須待龍樓羽翼成。", "若使只憑三傑力，猶應漢鼎一毫輕。", "魚在枯池鳥在林，四時無奈雪霜侵。", "若教激勸由真宰，亦獎青松徑寸心。"]'),
('yuding-5','光化踏青有感','司空圖','唐','御定全唐诗','yuding','','[]','引得車回莫認恩，卻成寂寞與誰論。',32,'御定全唐詩/json/634.json','["引得車回莫認恩，卻成寂寞與誰論。", "到頭不是君王意，羞插垂楊更傍門。"]'),
('yuding-6','醜年冬','司空圖','唐','御定全唐诗','yuding','','[]','醉日昔聞都下酒，何如今喜折新茶。',32,'御定全唐詩/json/634.json','["醉日昔聞都下酒，何如今喜折新茶。", "不堪病渴仍多慮，好向灉湖便出家。"]'),
('yuding-7','白菊三首','司空圖','唐','御定全唐诗','yuding','','[]','人間萬恨已難平，栽得垂楊更系情。',96,'御定全唐詩/json/634.json','["人間萬恨已難平，栽得垂楊更系情。", "猶喜閏前霜未下，菊邊依舊舞身輕。", "莫惜西風又起來，猶能婀娜傍池台。", "不辭暫被霜寒挫，舞袖招香即卻回。", "為報繁霜且莫催，窮秋須到自低垂。", "橫拖長袖招人別，只待春風卻舞來。"]'),
('yuding-8','扇','司空圖','唐','御定全唐诗','yuding','','[]','珍重逢秋莫棄捐，依依只仰故人憐。',32,'御定全唐詩/json/634.json','["珍重逢秋莫棄捐，依依只仰故人憐。", "有時池上遮殘日，承得霜林幾個蟬。"]'),
('yuding-9','修史亭三首','司空圖','唐','御定全唐诗','yuding','','[]','山前鄰叟去紛紛，獨強衰羸愛杜門。',96,'御定全唐詩/json/634.json','["山前鄰叟去紛紛，獨強衰羸愛杜門。", "漸覺一家看冷落，地爐生火自溫存。", "甘心七十且酣歌，自算平生幸已多。", "不似香山白居士，晚將心地著禪魔。", "烏紗巾上是青天，檢束酬知四十年。", "誰料平生臂鷹手，挑燈自送佛前錢。"]'),
('yuding-10','力疾山下吳村看杏花十九首','司空圖','唐','御定全唐诗','yuding','','[]','春來漸覺一川明，馬上繁花作陣迎。',384,'御定全唐詩/json/634.json','["春來漸覺一川明，馬上繁花作陣迎。", "掉臂只將詩酒敵，不勞金鼓助橫行。", "閶闔曾排捧禦爐，猶看曉月認金鋪。", "羸形不畫淩煙閣，只為微才激壯圖。", "鏡留雪鬢暖消無，春到梨花日又晡。", "移取扶桑階下種，年年看長礙金烏。", "折來未盡不須休，年少爭來莫與留。", "更願狂風知我意，一時吹向海西頭。", "才情百巧鬥風光，卻笑雕花刻葉忙。", "熨帖新巾來與裹，猶看騰踏少年場。", "浮世榮枯總不知，且憂花陣被風欺。", "儂家自有麒麟閣，第一功名只賞詩。", "白衫裁袖本教寬，朱紫由來亦一般。", "王老小兒吹笛看，我儂試舞爾儂看。", "單床薄被又羈棲，待到花開亦甚迷。", "若道折多還有罪，只應鶯囀是金雞。", "近來桃李半燒枯，歸臥鄉園只老夫。", "莫算明年人在否，不知花得更開無。", "漢王何事損精神，花滿深宮不見春。", "穠豔三千臨粉鏡，獨悲掩面李夫人。", "能豔能芳自一家，勝鸞勝鳳勝煙霞。", "客來須共醒醒看，碾盡明昌幾角茶。", "造化無端欲自神，裁紅剪翠為新春。", "不如分減閒心力，更助英豪濟活人。"]'),
('yuding-11','少儀','司空圖','唐','御定全唐诗','yuding','','[]','昨日登班綴柏台，更慚起草屬微才。',32,'御定全唐詩/json/634.json','["昨日登班綴柏台，更慚起草屬微才。", "錦窠不是尋常錦，兼向丘遲奪得來。"]'),
('yuding-12','重陽四首','司空圖','唐','御定全唐诗','yuding','','[]','簷前減燕菊添芳，燕盡庭前菊又荒。',128,'御定全唐詩/json/634.json','["簷前減燕菊添芳，燕盡庭前菊又荒。", "老大比他年少少，每逢佳節更悲涼。", "雨寒莫待菊花催，須怕晴空暖並開。", "開卻一枝開卻盡，且隨幽蝶更徘徊。", "青娥懶唱無衣換，黃菊新開乞酒難。", "長有長亭惆悵事，隔河更得對憑欄。", "白髮怕寒梳更懶，黃花晴日照初開。", "籬頭應是蝶相報，已被鄰家攜酒來。"]'),
('yuding-13','長命縷','司空圖','唐','御定全唐诗','yuding','','[]','他鄉處處堪悲事，殘照依依惜別天。',32,'御定全唐詩/json/634.json','["他鄉處處堪悲事，殘照依依惜別天。", "此去知名長命縷，殷勤為我唱花前。"]'),
('yuding-14','柏東','司空圖','唐','御定全唐诗','yuding','','[]','冥得機心豈在僧，柏東閒步愛騰騰。',32,'御定全唐詩/json/634.json','["冥得機心豈在僧，柏東閒步愛騰騰。", "免教世路人相忌，逢著村醪亦不憎。"]'),
('yuding-15','歌者十二首','司空圖','唐','御定全唐诗','yuding','','[]','追逐翻嫌傍管弦，金釵擊節自當筵。',384,'御定全唐詩/json/634.json','["追逐翻嫌傍管弦，金釵擊節自當筵。", "風霜一夜燕鴻斷，唱作江南袚禊天。", "玉樹花飄鳳失棲，一聲初壓管弦低。", "清回煩暑成瀟灑，豔逐寒雲變慘淒。", "十斛明珠亦易拚，欲兼人藝古來難。", "五雲合是新聲染，熔作瓊漿灑露盤。", "不似新聲唱亦新，旋調玉管旋生春。", "愁腸隔斷珠簾外，只為今宵共聽人。", "十年逃難別雲林，暫輟狂歌且聽琴。", "轉覺淡交言有味，此聲知是古人心。", "五柳先生自識微，無言共笑手空揮。", "胸中免被風波撓，肯為螳螂動殺機。", "風霜寒水旅人心，幾處笙歌繡戶深。", "分泊一場雲散後，未勝初夜便聽琴。", "自憐眼暗難求藥，莫恨花繁便有風。", "桃李更開須強看，明年兼恐聽歌聾。", "白雲深處寄生涯，歲暮生情賴此花。", "蜂蝶繞來忙繞袖，似知教折送鄰家。", "重九仍重歲漸闌，強開病眼更登攀。", "年年認得酣歌處，猶恐招魂葬故山。", "繞壁依稀認寫真，更須粉繪飾羸身。", "淒涼不道身無壽，九日還無舊會人。", "鶴氅花香搭槿籬，枕前蛩迸酒醒時。", "夕陽似照陶家菊，黃蝶無窮壓故枝。"]'),
('yuding-16','題裴晉公華嶽廟題名','司空圖','唐','御定全唐诗','yuding','','[]','嶽前大隊赴淮西，從此中原息鼓鼙。',32,'御定全唐詩/json/634.json','["嶽前大隊赴淮西，從此中原息鼓鼙。", "石闕莫教苔蘚上，分明認取晉公題。"]'),
('yuding-17','楊柳枝壽杯詞十八首','司空圖','唐','御定全唐诗','yuding','','[]','樂府翻來占太平，風光無處不含情。',384,'御定全唐詩/json/634.json','["樂府翻來占太平，風光無處不含情。", "千門萬戶喧歌吹，富貴人間只此聲。", "撼晚梳空不自持，與君同折上樓時。", "春風還有常情處，系得人心免別離。", "灞亭東去徹隋堤，贈別何須醉似泥。", "萬里往來無一事，便帆輕拂亂鶯啼。", "台城細仗曉初移，詔賜千官禊飲時。", "綠帳遠籠清佩響，更曛晴日上龍旗。", "桃源仙子不須誇，聞道惟栽一片花。", "何似浣紗溪畔住，綠陰相間兩三家。", "偶然樓上卷珠簾，往往長條拂枕函。", "恰值小娥初學舞，擬偷金縷押春衫。", "池邊影動散鴛鴦，更引微風亂繡床。", "直待玉窗塵不起，始應金雁得成行。", "稻畦分影向江村，憔悴經霜只半存。", "昨日流鶯今不見，亂螢飛出照黃昏。", "客淚休沾漢水濱，舞腰羞殺漢宮人。", "狂風更與回煙帚，掃盡繁花獨佔春。", "遊人莫歎易凋衰，長樂榮枯自有期。", "看取明年春意動，更于何處最先知。", "昔年行樂及芳時，一上丹梯桂一枝。", "笑問江頭醉公子，饒君滿把麹塵絲。", "渡頭殘照一行新，獨自依依向北人。", "莫恨鄉程千里遠，眼中從此故鄉春。"]'),
('yuding-18','山鵲','司空圖','唐','御定全唐诗','yuding','','[]','多驚本為好毛衣，只賴人憐始卻歸。',32,'御定全唐詩/json/634.json','["多驚本為好毛衣，只賴人憐始卻歸。", "眾鳥自知顏色減，妒他偏向眼前飛。"]'),
('yuding-19','李居士','司空圖','唐','御定全唐诗','yuding','','[]','高風只在五峰前，應是精靈降作賢。',32,'御定全唐詩/json/634.json','["高風只在五峰前，應是精靈降作賢。", "萬里無雲惟一鶴，鄉中同看卻升天。"]'),
('yuding-20','杏花','司空圖','唐','御定全唐诗','yuding','','[]','詩家偏為此傷情，品韻由來莫與爭。',32,'御定全唐詩/json/634.json','["詩家偏為此傷情，品韻由來莫與爭。", "解笑亦應兼解語，只應慵語倩鶯聲。"]'),
('yuding-21','白菊三首','司空圖','唐','御定全唐诗','yuding','','[]','不疑陶令是狂生，作賦其如有定情。',96,'御定全唐詩/json/634.json','["不疑陶令是狂生，作賦其如有定情。", "猶勝江南隱居士，詩魔終嫋負孤名。", "自古詩人少顯榮，逃名何用更題名。", "詩中有慮猶須戒，莫向詩中著不平。", "登高可羨少年場，白菊堆邊鬢似霜。", "益算更希沾上藥，今朝第七十重陽。"]'),
('yuding-22','聽雨','司空圖','唐','御定全唐诗','yuding','','[]','半夜思家睡裏愁，雨聲落落屋簷頭。',32,'御定全唐詩/json/634.json','["半夜思家睡裏愁，雨聲落落屋簷頭。", "照泥星出依前黑，淹爛庭花不肯休。"]'),
('yuding-23','楊柳枝二首','司空圖','唐','御定全唐诗','yuding','','[]','陶家五柳簇衡門，還有高情愛此君。',64,'御定全唐詩/json/634.json','["陶家五柳簇衡門，還有高情愛此君。", "何處更添詩境好，新蟬欹枕每先聞。", "數枝珍重蘸滄浪，無限塵心暫免忙。", "煩暑若和煙露裛，便同佛手灑清涼。"]'),
('yuding-24','修史亭二首','司空圖','唐','御定全唐诗','yuding','','[]','少年已慣擲年光，時節催驅獨不忙。',64,'御定全唐詩/json/634.json','["少年已慣擲年光，時節催驅獨不忙。", "今日無疑亦無病，前程無事擾醫王。", "籬落輕寒整頓新，雪晴步屣會諸鄰。", "自從南至歌風頂，始見人煙外有人。"]'),
('yuding-25','漫書','司空圖','唐','御定全唐诗','yuding','','[]','樂退安貧知是分，成家報國亦何慚。',32,'御定全唐詩/json/634.json','["樂退安貧知是分，成家報國亦何慚。", "到還僧院心期在，瑟瑟澄鮮百丈潭。"]'),
('yuding-26','雜題二首','司空圖','唐','御定全唐诗','yuding','','[]','棋局長攜上釣船，殺中棋殺勝絲牽。',64,'御定全唐詩/json/634.json','["棋局長攜上釣船，殺中棋殺勝絲牽。", "洪爐任鑄千鈞鼎，只在磻溪一縷懸。", "曉鏡高窗氣象深，自憐清格笑塵心。", "世間不為蛾眉誤，海上方應鶴背吟。"]'),
('yuding-27','題休休亭','司空圖','唐','御定全唐诗','yuding','','[]','咄，諾，休休休，莫莫莫，伎兩雖多性靈惡，',32,'御定全唐詩/json/634.json','["咄，諾，休休休，莫莫莫，伎兩雖多性靈惡，", "若曰爾何能，答言耐辱莫。"]'),
('yuding-28','馮燕歌','司空圖','唐','御定全唐诗','yuding','','[]','魏中義士有馮燕，遊俠幽並最少年。避仇偶作滑台客，',280,'御定全唐詩/json/634.json','["魏中義士有馮燕，遊俠幽並最少年。避仇偶作滑台客，", "兩面高樓語笑聲，指點行人情暗結。擲果潘郎誰不慕，", "馮生敲鐙袖籠鞭，半拂垂楊半惹煙。樹間春鳥知人意，", "梁間客燕正相欺，屋上鳴鳩空自鬥。嬰歸醉臥非仇汝，", "誰言狼戾心能忍，待我情深情不隱。回身本謂取巾難，", "爾能負彼必相負，假手他人複在誰？窗間紅豔猶可掬，", "鳳凰釵碎各分飛，怨魄嬌魂何處追，淩波如喚游金穀，", "誣執張嬰不自明，貴免生前遭考捶。官將赴市擁紅塵，", "初聞僚吏翻疑歎，呵叱風狂詞不變。縲囚解縛猶自疑，", "已為不平能割愛，更將身命救深冤。白馬賢侯賈相公，", "黃河東注無時歇，注盡波瀾名不滅。為感詞人沈下賢，", "鑄作金燕香作堆，焚香酬酒聽歌來。"]'),
('yuding-29','寄薛起居','司空圖','唐','御定全唐诗','yuding','','[]','小域新銜賀聖朝，亦知蹇分巧難拋。',32,'御定全唐詩/json/634.json','["小域新銜賀聖朝，亦知蹇分巧難拋。", "粗才自合無岐路，不破工夫漫解嘲。"]'),
('yuding-30','月下留丹灶','司空圖','唐','御定全唐诗','yuding','','[]','月下留丹灶，壇邊樹羽衣。異香人不覺，殘夜鶴分飛。',48,'御定全唐詩/json/634.json','["月下留丹灶，壇邊樹羽衣。異香人不覺，殘夜鶴分飛。", "朝會初元盛，蓬瀛舊侶稀。瑤函真跡在，妖魅敢揚威。"]'),
('yuding-31','元日','司空圖','唐','御定全唐诗','yuding','','[]','甲子今重數，生涯只自憐。殷勤元日日，欹午又明年。',24,'御定全唐詩/json/634.json','["甲子今重數，生涯只自憐。殷勤元日日，欹午又明年。"]'),
('yuding-32','洛陽詠古','司空圖','唐','御定全唐诗','yuding','','[]','石勒童年有戰機，洛陽長嘯倚門時。',32,'御定全唐詩/json/634.json','["石勒童年有戰機，洛陽長嘯倚門時。", "晉朝不是王夷甫，大智何由得預知。"]'),
('yuding-33','詩品二十四則：雄渾','司空圖','唐','御定全唐诗','yuding','','[]','大用外腓，真體內充。返虛入渾，積健為雄。',60,'御定全唐詩/json/634.json','["大用外腓，真體內充。返虛入渾，積健為雄。", "具備萬物，橫絕太空。荒荒油雲，寥寥長風。", "超以象外，得其環中。持之匪強，來之無窮。"]'),
('yuding-34','詩品二十四則：沖淡','司空圖','唐','御定全唐诗','yuding','','[]','素處以默，妙機其微。飲之太和，獨鶴與飛。',60,'御定全唐詩/json/634.json','["素處以默，妙機其微。飲之太和，獨鶴與飛。", "猶之惠風，苒苒在衣。閱音修篁，美曰載歸。", "遇之匪深，即之愈稀。脫有形似，握手已違。"]'),
('yuding-35','詩品二十四則：纖穠','司空圖','唐','御定全唐诗','yuding','','[]','采采流水，蓬蓬遠春。窈窕深谷，時見美人。',60,'御定全唐詩/json/634.json','["采采流水，蓬蓬遠春。窈窕深谷，時見美人。", "碧桃滿樹，風日水濱。柳陰路曲，流鶯比鄰。", "乘之愈往，識之愈真。如將不盡，與古為新。"]'),
('yuding-36','詩品二十四則：沉著','司空圖','唐','御定全唐诗','yuding','','[]','綠杉野屋，落日氣清。脫巾獨步，時聞鳥聲。',60,'御定全唐詩/json/634.json','["綠杉野屋，落日氣清。脫巾獨步，時聞鳥聲。", "鴻雁不來，之子遠行。所思不遠，若為平生。", "海風碧雲，夜渚月明。如有佳語，大河前橫。"]'),
('yuding-37','詩品二十四則：高古','司空圖','唐','御定全唐诗','yuding','','[]','畸人乘真，手把芙蓉。泛彼浩劫，窅然空縱。',60,'御定全唐詩/json/634.json','["畸人乘真，手把芙蓉。泛彼浩劫，窅然空縱。", "月出東鬥，好風相從。太華夜碧，人聞清鐘。", "虛佇神素，脫然畦封。黃唐在獨，落落玄宗。"]'),
('yuding-38','詩品二十四則：典雅','司空圖','唐','御定全唐诗','yuding','','[]','玉壺買春，賞雨茆屋。坐中佳士，左右修竹。',60,'御定全唐詩/json/634.json','["玉壺買春，賞雨茆屋。坐中佳士，左右修竹。", "白雲初晴，幽鳥相逐。眠琴綠陰，上有飛瀑。", "落花無言，人淡如菊。書之歲華，其曰可讀。"]'),
('yuding-39','詩品二十四則：洗煉','司空圖','唐','御定全唐诗','yuding','','[]','猶礦出金，如鉛出銀。超心煉冶，絕愛緇磷。',60,'御定全唐詩/json/634.json','["猶礦出金，如鉛出銀。超心煉冶，絕愛緇磷。", "空潭瀉春，古鏡照神。體素儲潔，乘月返真。", "載瞻星辰，載歌幽人。流水今日，明月前身。"]'),
('yuding-40','詩品二十四則：勁健','司空圖','唐','御定全唐诗','yuding','','[]','行神如空，行氣如虹。巫峽千尋，走雲連風。',60,'御定全唐詩/json/634.json','["行神如空，行氣如虹。巫峽千尋，走雲連風。", "飲真茹強，蓄素守中。喻彼行健，是謂存雄。", "天地與立，神化攸同。期之以實，禦之以終。"]'),
('yuding-41','詩品二十四則：綺麗','司空圖','唐','御定全唐诗','yuding','','[]','神存富貴，始輕黃金。濃盡必枯，淺者屢深。',60,'御定全唐詩/json/634.json','["神存富貴，始輕黃金。濃盡必枯，淺者屢深。", "露餘山青，紅杏在林。月明華屋，畫橋碧陰。", "金尊酒滿，共客彈琴。取之自足，良殫美襟。"]'),
('yuding-42','詩品二十四則：自然','司空圖','唐','御定全唐诗','yuding','','[]','俯拾即是，不取諸鄰。俱道適往，著手成春。',60,'御定全唐詩/json/634.json','["俯拾即是，不取諸鄰。俱道適往，著手成春。", "如逢花開，如瞻歲新。真予不奪，強得易貧。", "幽人空山，過水采蘋。薄言情晤，悠悠天鈞。"]'),
('yuding-43','詩品二十四則：含蓄','司空圖','唐','御定全唐诗','yuding','','[]','不著一字，盡得風流。語不涉難，已不堪憂。',60,'御定全唐詩/json/634.json','["不著一字，盡得風流。語不涉難，已不堪憂。", "是有真宰，與之沈浮。如淥滿酒，花時返秋。", "悠悠空塵，忽忽海漚。淺深聚散，萬取一收。"]'),
('yuding-44','詩品二十四則：豪放','司空圖','唐','御定全唐诗','yuding','','[]','觀花匪禁，吞吐大荒。由道返氣，處得以狂。',60,'御定全唐詩/json/634.json','["觀花匪禁，吞吐大荒。由道返氣，處得以狂。", "天風浪浪，海山蒼蒼。真力彌滿，萬象在旁。", "前招三辰，後引鳳凰。曉策六鼇，濯足扶桑。"]'),
('yuding-45','詩品二十四則：精神','司空圖','唐','御定全唐诗','yuding','','[]','欲返不盡，相期與來。明漪絕底，奇花初胎。',60,'御定全唐詩/json/634.json','["欲返不盡，相期與來。明漪絕底，奇花初胎。", "青春鸚鵡，楊柳池台。碧山人來，清酒滿杯。", "生氣遠出，不著死灰。妙造自然，伊誰與裁？"]'),
('yuding-46','詩品二十四則：縝密','司空圖','唐','御定全唐诗','yuding','','[]','是有真跡，如不可知。意象欲生，造化已奇。',60,'御定全唐詩/json/634.json','["是有真跡，如不可知。意象欲生，造化已奇。", "水流花開，清露未晞。要路愈遠，幽行為遲。", "語不欲犯，思不欲癡。猶春于綠，明月雪時。"]'),
('yuding-47','詩品二十四則：疏野','司空圖','唐','御定全唐诗','yuding','','[]','惟性所宅，真取弗羈。拾物自富，與率為期。',60,'御定全唐詩/json/634.json','["惟性所宅，真取弗羈。拾物自富，與率為期。", "築屋松下，脫帽看詩。但知旦暮，不辨何時。", "倘然適意，豈必有為。若其天放，如是得之。"]'),
('yuding-48','詩品二十四則：清奇','司空圖','唐','御定全唐诗','yuding','','[]','娟娟群松，下有漪流。晴雪滿汀，隔溪漁舟。',60,'御定全唐詩/json/634.json','["娟娟群松，下有漪流。晴雪滿汀，隔溪漁舟。", "可人如玉，步屟尋幽。載行載止，空碧悠悠。", "神出古異，淡不可收。如月之曙，如氣之秋。"]'),
('yuding-49','詩品二十四則：委曲','司空圖','唐','御定全唐诗','yuding','','[]','登彼太行，翠繞羊腸。杳靄流玉，悠悠花香。',60,'御定全唐詩/json/634.json','["登彼太行，翠繞羊腸。杳靄流玉，悠悠花香。", "力之于時，聲之於羌。似往已回，如幽匪藏。", "水理漩洑，鵬風翱翔。道不自器，與之圓方。"]'),
('yuding-50','詩品二十四則：實境','司空圖','唐','御定全唐诗','yuding','','[]','取語甚直，計思匪深。忽逢幽人，如見道心。',60,'御定全唐詩/json/634.json','["取語甚直，計思匪深。忽逢幽人，如見道心。", "晴澗之曲，碧松之陰。一客荷樵，一客聽琴。", "情性所至，妙不自尋。遇之自天，冷然希音。"]'),
('yuding-51','詩品二十四則：悲慨','司空圖','唐','御定全唐诗','yuding','','[]','大風卷水，林木為摧。意苦若死，招憩不來。',60,'御定全唐詩/json/634.json','["大風卷水，林木為摧。意苦若死，招憩不來。", "百歲如流，富貴冷灰。大道日往，若為雄才。", "壯士拂劍，浩然彌哀。蕭蕭落葉，漏雨蒼苔。"]'),
('yuding-52','詩品二十四則：形容','司空圖','唐','御定全唐诗','yuding','','[]','絕佇靈素，少回清真。如覓水影，如寫陽春。',60,'御定全唐詩/json/634.json','["絕佇靈素，少回清真。如覓水影，如寫陽春。", "風雲變態，花草精神。海之波瀾，山之嶙峋。", "俱似大道，妙契同塵。離形得似，庶幾斯人。"]'),
('yuding-53','詩品二十四則：超詣','司空圖','唐','御定全唐诗','yuding','','[]','匪神之靈，匪機之微。如將白雲，清風與歸。',60,'御定全唐詩/json/634.json','["匪神之靈，匪機之微。如將白雲，清風與歸。", "遠引若至，臨之已非。少有道契，終與俗違。", "亂山高木，碧苔芳暉。誦之思之，其聲愈稀。"]'),
('yuding-54','詩品二十四則：飄逸','司空圖','唐','御定全唐诗','yuding','','[]','落落欲往，矯矯不群。緱山之鶴，華頂之雲。',60,'御定全唐詩/json/634.json','["落落欲往，矯矯不群。緱山之鶴，華頂之雲。", "高人畫中，令色絪縕。禦風蓬葉，泛彼無垠。", "如不可執，如將有聞。識者已領，期之愈分。"]'),
('yuding-55','詩品二十四則：曠達','司空圖','唐','御定全唐诗','yuding','','[]','生者百歲，相去幾何？歡樂苦短，憂愁實多。',60,'御定全唐詩/json/634.json','["生者百歲，相去幾何？歡樂苦短，憂愁實多。", "何如尊酒，日往煙蘿。花覆茆簷，疏雨相過。", "倒酒既盡，杖藜行過。孰不有古，南山峨峨。"]'),
('yuding-56','詩品二十四則：流動','司空圖','唐','御定全唐诗','yuding','','[]','若納水輨，如轉丸珠。夫豈可道，假體遺愚。',60,'御定全唐詩/json/634.json','["若納水輨，如轉丸珠。夫豈可道，假體遺愚。", "荒荒坤軸，悠悠天樞。載要其端，載同其符。", "超超神明，返返冥無。來往千載，是之謂乎。"]'),
('yuding-57','句','司空圖','唐','御定全唐诗','yuding','','[]','忍事敵災星。',342,'御定全唐詩/json/634.json','["忍事敵災星。", "物望傾心久，凶渠破膽頻。（《詠房太尉》。自注：初管", "建親王分鎮天下議，明皇從之，肅宗以是疑管，受讒廢。", "先是祿山見分鎮詔書，附膺歎曰：「吾不得天下矣！」）", "鼎飫和方濟，臺階潤欲平。。", "夜短猿悲減，風和鵲喜虛。", "驊騮思故第，鸚鵡失佳人。", "鯨鯢人海涸，魑魅棘林幽。", "棋聲花院閉，幡影石壇高。", "地涼清鶴夢，林靜肅僧儀。", "晚妝留拜月，春睡更生香。", "隔穀見雞犬，山苗接楚田。人家寒食月，花影午時天。", "官路好禽聲，軒車駐晚程。南樓山最秀，北路邑偏清。", "多病形容五十三，誰憐借笏趁朝參。（華下乞歸，", "十年太華無知己，只得虛中兩首詩。（王禹偁雲：人多", "以四皓、二疏目圖，惟僧虛中贈圖詩雲：道裝汀鶴識，", "有時看禦劄，特地掛朝衣。言其尊戴存誠，非邀君也。", "故圖詩云云，言得其意趣）", "看師逸跡兩師宜，高適歌行李白詩。（贈z6光，"]'),
('yuding-0','送邊上從事','周繇','唐','御定全唐诗','yuding','','[]','戎裝佩鏌鋣，走馬逐輕車。衰草城邊路，殘陽壟上笳。',48,'御定全唐詩/json/635.json','["戎裝佩鏌鋣，走馬逐輕車。衰草城邊路，殘陽壟上笳。", "黃河穿漢界，青塚出胡沙。提筆男兒事，功名立可誇。"]'),
('yuding-1','送洛陽崔員外','周繇','唐','御定全唐诗','yuding','','[]','塞詔除嵩洛，觀圖見廢興。城遷周古鼎，地列漢諸陵。',48,'御定全唐詩/json/635.json','["塞詔除嵩洛，觀圖見廢興。城遷周古鼎，地列漢諸陵。", "日送歸朝客，時招住嶽僧。郡齋台閣滿，公退即吟登。"]'),
('yuding-2','送人尉黔中','周繇','唐','御定全唐诗','yuding','','[]','盤山行幾驛，水路複通巴。峽漲三川雪，園開四季花。',48,'御定全唐詩/json/635.json','["盤山行幾驛，水路複通巴。峽漲三川雪，園開四季花。", "公庭飛白鳥，官俸請丹砂。知尉黔中後，高吟采物華。"]'),
('yuding-3','送宇文虞','周繇','唐','御定全唐诗','yuding','','[]','此別欲何往，未言歸故林。行車新歲近，落日亂山深。',48,'御定全唐詩/json/635.json','["此別欲何往，未言歸故林。行車新歲近，落日亂山深。", "野店寒無客，風巢動有禽。潛知經目事，大半是愁吟。"]'),
('yuding-4','題東林寺虎掊泉','周繇','唐','御定全唐诗','yuding','','[]','勝致通幽感，靈泉有虎掊。爪抬山脈斷，掌托石心拗。',48,'御定全唐詩/json/635.json','["勝致通幽感，靈泉有虎掊。爪抬山脈斷，掌托石心拗。", "竹藹疑相近，松陰蓋亦交。轉令棲遁者，真境逾難拋。"]'),
('yuding-5','登甘露寺','周繇','唐','御定全唐诗','yuding','','[]','盤江上幾層，峭壁半垂藤。殿鎖南朝像，龕禪外國僧。',48,'御定全唐詩/json/635.json','["盤江上幾層，峭壁半垂藤。殿鎖南朝像，龕禪外國僧。", "海濤摏砌檻，山雨灑窗燈。日暮疏鐘起，聲聲徹廣陵。"]'),
('yuding-6','甘露寺東軒','周繇','唐','御定全唐诗','yuding','','[]','每日憐晴眺，閑吟只自娛。山從平地有，水到遠天無。',48,'御定全唐詩/json/635.json','["每日憐晴眺，閑吟只自娛。山從平地有，水到遠天無。", "老樹多封楚，輕煙暗染吳。雖居此廊下，入戶亦躊躕。"]'),
('yuding-7','甘露寺北軒','周繇','唐','御定全唐诗','yuding','','[]','曉色宜閑望，山風遠益清。白雲連晉閣，碧樹盡蕪城。',48,'御定全唐詩/json/635.json','["曉色宜閑望，山風遠益清。白雲連晉閣，碧樹盡蕪城。", "少靜沙痕出，煙消野火平。最堪佳此境，為我長詩情。"]'),
('yuding-8','詠螢','周繇','唐','御定全唐诗','yuding','','[]','熠熠與娟娟，池塘竹樹邊。亂飛同曳火，成聚卻無煙。',48,'御定全唐詩/json/635.json','["熠熠與娟娟，池塘竹樹邊。亂飛同曳火，成聚卻無煙。", "微雨灑不滅，輕風吹欲燃。舊曾書案上，頻把作囊懸。"]'),
('yuding-9','望海','周繇','唐','御定全唐诗','yuding','','[]','蒼茫空泛日，四顧絕人煙。半浸中華岸，旁通異域船。',48,'御定全唐詩/json/635.json','["蒼茫空泛日，四顧絕人煙。半浸中華岸，旁通異域船。", "島間應有國，波外恐無天。欲作乘槎客，翻愁去來年。"]'),
('yuding-10','送楊環校書歸廣南','周繇','唐','御定全唐诗','yuding','','[]','天南行李半波濤，灘樹枝枝拂戲猱。初著藍衫從遠嶠，',40,'御定全唐詩/json/635.json','["天南行李半波濤，灘樹枝枝拂戲猱。初著藍衫從遠嶠，", "名宦兩成歸舊隱，遍尋親友興何饒。"]'),
('yuding-11','經故宅有感','周繇','唐','御定全唐诗','yuding','','[]','身沒南荒雨露賒，朱門空鎖舊繁華。池塘鑿就方通水，',40,'御定全唐詩/json/635.json','["身沒南荒雨露賒，朱門空鎖舊繁華。池塘鑿就方通水，", "昔年埏埴生靈地，今日生人為歎嗟。"]'),
('yuding-12','送入蕃使','周繇','唐','御定全唐诗','yuding','','[]','獵獵旗幡過大荒，敕書猶帶禦煙香。滹沱河凍軍回探，',40,'御定全唐詩/json/635.json','["獵獵旗幡過大荒，敕書猶帶禦煙香。滹沱河凍軍回探，", "早終冊禮朝天闕，莫遣虯髭染塞霜。"]'),
('yuding-13','白石潭秋霽作','周繇','唐','御定全唐诗','yuding','','[]','潭心煙霧破斜暉，殷殷雷聲隔翠微。崖蹙盤渦翻蜃窟，',40,'御定全唐詩/json/635.json','["潭心煙霧破斜暉，殷殷雷聲隔翠微。崖蹙盤渦翻蜃窟，", "秋霽更誰同此望，遠鐘時見一僧歸。"]'),
('yuding-14','題金陵棲霞寺贈月公','周繇','唐','御定全唐诗','yuding','','[]','明家不要買山錢，施作清池種白蓮。松檜老依雲外地，',40,'御定全唐詩/json/635.json','["明家不要買山錢，施作清池種白蓮。松檜老依雲外地，", "欲結茅庵伴師住，肯饒多少薜蘿煙。"]'),
('yuding-15','嘲段成式','周繇','唐','御定全唐诗','yuding','','[]','蹙鞠且徒為，甯如目送時。報仇慚選耎，存想恨逶遲。',72,'御定全唐詩/json/635.json','["蹙鞠且徒為，甯如目送時。報仇慚選耎，存想恨逶遲。", "促坐疑辟咡，銜杯強朵頤。恣情窺窈窕，曾恃好風姿。", "色授應難奪，神交願莫辭。請君看曲譜，不負少年期。"]'),
('yuding-16','送江州薛尚書','周繇','唐','御定全唐诗','yuding','','[]','匡廬千萬峰，影匝郡城中。忽佩虎符去，遙疑鳥道通。',72,'御定全唐詩/json/635.json','["匡廬千萬峰，影匝郡城中。忽佩虎符去，遙疑鳥道通。", "煙霞時滿郭，波浪暮連空。樹翳樓臺月，帆飛鼓角風。", "郡齋多嶽客，鄉戶半漁翁。王事行春外，題詩寄遠公。"]'),
('yuding-17','津頭望白水','周繇','唐','御定全唐诗','yuding','','[]','晴江暗漲岸吹沙，山畔船沖樹杪斜。',32,'御定全唐詩/json/635.json','["晴江暗漲岸吹沙，山畔船沖樹杪斜。", "城郭半淹橋市鬧，鷺鷥繚繞入人家。"]'),
('yuding-18','公子行','周繇','唐','御定全唐诗','yuding','','[]','青山薄薄漏春風，日暮鳴鞭柳影中。',32,'御定全唐詩/json/635.json','["青山薄薄漏春風，日暮鳴鞭柳影中。", "回望玉樓人不見，酒旗深處勒花驄。"]'),
('yuding-19','看牡丹贈段成式','周繇','唐','御定全唐诗','yuding','','[]','金蕊霞英疊彩香，初疑少女出蘭房。',32,'御定全唐詩/json/635.json','["金蕊霞英疊彩香，初疑少女出蘭房。", "逡巡又是一年別，寄語集仙呼索郎。"]'),
('yuding-20','以人參遺段成式','周繇','唐','御定全唐诗','yuding','','[]','人形上品傳方志，我得真英自紫團。',32,'御定全唐詩/json/635.json','["人形上品傳方志，我得真英自紫團。", "慚非叔子空持藥，更請伯言審細看。"]'),
('yuding-21','和段成式','周繇','唐','御定全唐诗','yuding','','[]','回簪轉黛喜猜防，粉署裁詩助酒狂。',64,'御定全唐詩/json/635.json','["回簪轉黛喜猜防，粉署裁詩助酒狂。", "若遇仙丹偕羽化，但隨蕭史亦何傷。", "玉樹瓊筵映彩霞，澄虛樓閣似仙家。", "只緣存想歸蘭室，不向春風看夜花。"]'),
('yuding-0','雜興','聶夷中','唐','御定全唐诗','yuding','','[]','兩葉能蔽目，雙豆能塞聰。理身不知道，將為天地聾。',48,'御定全唐詩/json/636.json','["兩葉能蔽目，雙豆能塞聰。理身不知道，將為天地聾。", "擾擾造化內，茫茫天地中。苟或有所願，毛髮亦不容。"]'),
('yuding-1','雜怨','聶夷中','唐','御定全唐诗','yuding','','[]','生在綺羅下，豈識漁陽道。良人自戍來，夜夜夢中到。',84,'御定全唐詩/json/636.json','["生在綺羅下，豈識漁陽道。良人自戍來，夜夜夢中到。", "漁陽萬里遠，近於中門限。中門逾有時，漁陽常在眼。", "君淚濡羅巾，妾淚滴路塵。羅巾今在手，日得隨妾身。", "路塵如因風，得上君車輪。"]'),
('yuding-2','行路難','聶夷中','唐','御定全唐诗','yuding','','[]','莫言行路難，夷狄如中國。謂言骨肉親，中門如異域。',48,'御定全唐詩/json/636.json','["莫言行路難，夷狄如中國。謂言骨肉親，中門如異域。", "出處全在人，路亦無通塞。門前兩條轍，何處去不得。"]'),
('yuding-3','大垂手','聶夷中','唐','御定全唐诗','yuding','','[]','金刀剪輕雲，盤用黃金縷。裝束趙飛燕，教來掌上舞。',36,'御定全唐詩/json/636.json','["金刀剪輕雲，盤用黃金縷。裝束趙飛燕，教來掌上舞。", "舞罷飛燕死，片片隨風去。"]'),
('yuding-4','空城雀','聶夷中','唐','御定全唐诗','yuding','','[]','一雀入官倉，所食能損幾。所慮往復頻，官倉乃害爾。',48,'御定全唐詩/json/636.json','["一雀入官倉，所食能損幾。所慮往復頻，官倉乃害爾。", "魚網不在天，鳥網不在水。飲啄要自然，何必空城裏。"]'),
('yuding-5','胡無人行','聶夷中','唐','御定全唐诗','yuding','','[]','男兒徇大義，立節不沽名。腰間懸陸離，大歌胡無行。',96,'御定全唐詩/json/636.json','["男兒徇大義，立節不沽名。腰間懸陸離，大歌胡無行。", "不讀戰國書，不覽黃石經。醉臥咸陽樓，夢入受降城。", "更願生羽翼，飛身入青冥。請攜天子劍，斫下旄頭星。", "自然胡無人，雖有無戰爭。悠哉典屬國，驅羊老一生。"]'),
('yuding-6','詠田家','聶夷中','唐','御定全唐诗','yuding','','[]','二月賣新絲，五月糶新穀。醫得眼前瘡，剜卻心頭肉。',48,'御定全唐詩/json/636.json','["二月賣新絲，五月糶新穀。醫得眼前瘡，剜卻心頭肉。", "我願君王心，化作光明燭。不照綺羅筵，只照逃亡屋。"]'),
('yuding-7','燕台二首','聶夷中','唐','御定全唐诗','yuding','','[]','燕台累黃金，上欲招儒雅。貴得賢士來，更下於隗者。',84,'御定全唐詩/json/636.json','["燕台累黃金，上欲招儒雅。貴得賢士來，更下於隗者。", "自然樂毅徒，趨風走天下。何必馳鳳書，旁求向林野。", "燕台高百尺，燕滅台亦平。一種是亡國，猶得禮賢名。", "何似章華畔，空餘禾黍生。"]'),
('yuding-8','古興','聶夷中','唐','御定全唐诗','yuding','','[]','片玉一塵輕，粒粟山丘重。唐虞貴民食，只是勤播種。',48,'御定全唐詩/json/636.json','["片玉一塵輕，粒粟山丘重。唐虞貴民食，只是勤播種。", "前聖後聖同，今人古人共。一歲如苦饑，金玉何所用。"]'),
('yuding-9','勸酒二首','聶夷中','唐','御定全唐诗','yuding','','[]','白日無定影，清江無定波。人無百年壽，百年複如何。',132,'御定全唐詩/json/636.json','["白日無定影，清江無定波。人無百年壽，百年複如何。", "堂上陳美酒，堂下列笙歌。與君入醉鄉，醉鄉樂天和。", "歲歲松柏茂，日日丘陵多。君看終南山，萬古青峨峨。", "灞上送行客，聽唱行客歌。適來橋下水，已作渭川波。", "人間榮樂少，四海別離多。但恐別離淚，自成苦水河。", "勸爾一杯酒，所贈無餘多。"]'),
('yuding-10','飲酒樂','聶夷中','唐','御定全唐诗','yuding','','[]','日月似有事，一夜行一周。草木猶須老，人生得無愁。',72,'御定全唐詩/json/636.json','["日月似有事，一夜行一周。草木猶須老，人生得無愁。", "一飲解百結，再飲破百憂。白髮欺貧賤，不入醉人頭。", "我願東海水，盡向杯中流。安得阮步兵，同入醉鄉遊。"]'),
('yuding-11','公子行二首','聶夷中','唐','御定全唐诗','yuding','','[]','漢代多豪族，恩深益驕逸。走馬踏殺人，街吏不敢詰。',132,'御定全唐詩/json/636.json','["漢代多豪族，恩深益驕逸。走馬踏殺人，街吏不敢詰。", "紅樓宴青春，數裏望雲蔚。金缸焰勝晝，不畏落暉疾。", "美人盡如月，南威莫能匹。芙蓉自天來，不向水中出。", "飛瓊奏雲和，碧簫吹鳳質。唯恨魯陽死，無人駐白日。", "花樹出牆頭，花裏誰家樓。一行書不讀，身封萬戶侯。", "美人樓上歌，不是古涼州。"]'),
('yuding-12','短歌','聶夷中','唐','御定全唐诗','yuding','','[]','八月木陰薄，十葉三墮枝。人生過五十，亦已同此時。',120,'御定全唐詩/json/636.json','["八月木陰薄，十葉三墮枝。人生過五十，亦已同此時。", "朝出東郭門，嘉樹鬱參差。暮出西郭門，原草已離披。", "南鄰好台榭，北鄰善歌吹。榮華忽銷歇，四顧令人悲。", "生死與榮辱，四者乃常期。古人恥其名，沒世無人知。", "無言鬢似霜，勿謂事如絲。耆年無一善，何殊食乳兒。"]'),
('yuding-13','過比干墓','聶夷中','唐','御定全唐诗','yuding','','[]','殷辛帝天下，厭為天下尊。幹綱既一斷，賢愚無二門。',96,'御定全唐詩/json/636.json','["殷辛帝天下，厭為天下尊。幹綱既一斷，賢愚無二門。", "佞是福身本，忠作喪己源。餓虎不食子，人無骨肉恩。", "日影不入地，下埋冤死魂。腐骨不為土，應作石木根。", "餘來過此鄉，下馬吊此墳。靜念君臣間，有道誰敢論。"]'),
('yuding-14','住京寄同志','聶夷中','唐','御定全唐诗','yuding','','[]','有京如在道，日日先雞起。不離十二街，日行一百里。',96,'御定全唐詩/json/636.json','["有京如在道，日日先雞起。不離十二街，日行一百里。", "役役大塊上，周朝複秦市。貴賤與賢愚，古今同一軌。", "白兔落天西，赤鴉飛海底。一日復一日，日日無終始。", "自嫌性如石，不達榮辱理。試問九十翁，吾今尚如此。"]'),
('yuding-15','贈農','聶夷中','唐','御定全唐诗','yuding','','[]','勸爾勤耕田，盈爾倉中粟。勸爾無伐桑，減爾身上服。',60,'御定全唐詩/json/636.json','["勸爾勤耕田，盈爾倉中粟。勸爾無伐桑，減爾身上服。", "清霜一委地，萬草色不綠。狂風一飄林，萬葉不著木。", "青春如不耕，何以自拘束。"]'),
('yuding-16','客有追歎後時者作詩勉之','聶夷中','唐','御定全唐诗','yuding','','[]','後達多晚榮，速得多疾傾。君看構大廈，何曾一日成。',108,'御定全唐詩/json/636.json','["後達多晚榮，速得多疾傾。君看構大廈，何曾一日成。", "在暖須在桑，在飽須在耕。君子貴弘道，道弘無不亨。", "太陽垂好光，毛髮悉見形。我亦二十年，直似戴盆行。", "荊山產美玉，石石皆堅貞。未必盡有玉，玉且間石生。", "精衛一微物，猶恐填海平。"]'),
('yuding-17','訪嵩陽道士不遇','聶夷中','唐','御定全唐诗','yuding','','[]','先生五嶽游，文焰滅金鼎。日下鶴過時，人間空落影。',48,'御定全唐詩/json/636.json','["先生五嶽游，文焰滅金鼎。日下鶴過時，人間空落影。", "常言一粒藥，不隨死生境。何當列禦寇，去問仙人請。"]'),
('yuding-18','早發鄴北經古城','聶夷中','唐','御定全唐诗','yuding','','[]','微月東南明，雙牛耕古城。但耕古城地，不知古城名。',96,'御定全唐詩/json/636.json','["微月東南明，雙牛耕古城。但耕古城地，不知古城名。", "當昔置此城，豈料今日耕。蔓草已離披，狐兔何縱橫。", "秋雲零落散，秋風蕭條生。對古良可歎，念今轉傷情。", "古人已冥冥，今人又營營。不知馬蹄下，誰家舊台亭。"]'),
('yuding-19','題賈氏林泉','聶夷中','唐','御定全唐诗','yuding','','[]','市朝束名利，林泉系清通。豈知黃塵內，迥有白雲蹤。',120,'御定全唐詩/json/636.json','["市朝束名利，林泉系清通。豈知黃塵內，迥有白雲蹤。", "輕流逗密蓧，直幹入寬空。高吟五君詠，疑對九華峰。", "我知種竹心，欲扇清涼風。我知決泉意，將明濟物功。", "有琴不張弦，眾星列梧桐。須知淡澹聽，聲在無聲中。", "地非樵者路，武陵又何逢。只慮迷所歸，池上日西東。"]'),
('yuding-20','送友人歸江南','聶夷中','唐','御定全唐诗','yuding','','[]','泉州五更鼓，月落西南維。此時有行客，別我孤舟歸。',36,'御定全唐詩/json/636.json','["泉州五更鼓，月落西南維。此時有行客，別我孤舟歸。", "上國身無主，下第誠可悲。"]'),
('yuding-21','秋夕','聶夷中','唐','御定全唐诗','yuding','','[]','日往無複見，秋堂暮仍學。玄發不知白，曉人寒銅覺。',48,'御定全唐詩/json/636.json','["日往無複見，秋堂暮仍學。玄發不知白，曉人寒銅覺。", "為材未離群，有玉猶在璞。誰把碧桐枝，刻作雲門樂。"]'),
('yuding-22','哭劉駕博士','聶夷中','唐','御定全唐诗','yuding','','[]','出門四顧望，此日何徘徊。終南舊山色，夫子安在哉。',72,'御定全唐詩/json/636.json','["出門四顧望，此日何徘徊。終南舊山色，夫子安在哉。", "君詩如門戶，夕閉晝還開。君名如四時，春盡夏複來。", "原野多丘陵，累累如高臺。君墳須數尺，誰與夫子偕。"]'),
('yuding-23','公子家','聶夷中','唐','御定全唐诗','yuding','','[]','種花滿西園，花發青樓道。花下一禾生，去之為惡草。',24,'御定全唐詩/json/636.json','["種花滿西園，花發青樓道。花下一禾生，去之為惡草。"]'),
('yuding-24','田家二首','聶夷中','唐','御定全唐诗','yuding','','[]','父耕原上田，子劚山下荒。六月禾未秀，官家已修倉。',48,'御定全唐詩/json/636.json','["父耕原上田，子劚山下荒。六月禾未秀，官家已修倉。", "鋤田當日午，汗滴禾下土。誰念盤中餐，粒粒皆辛苦。"]'),
('yuding-25','雜怨','聶夷中','唐','御定全唐诗','yuding','','[]','良人昨日去，明月又不圓。別時各有淚，零落青樓前。',24,'御定全唐詩/json/636.json','["良人昨日去，明月又不圓。別時各有淚，零落青樓前。"]'),
('yuding-26','烏夜啼','聶夷中','唐','御定全唐诗','yuding','','[]','眾鳥各歸枝，烏烏爾不棲。還應知妾恨，故向綠窗啼。',24,'御定全唐詩/json/636.json','["眾鳥各歸枝，烏烏爾不棲。還應知妾恨，故向綠窗啼。"]'),
('yuding-27','起夜來','聶夷中','唐','御定全唐诗','yuding','','[]','念遠心如燒，不覺中夜起。桃花帶露泛，立在月明裏。',24,'御定全唐詩/json/636.json','["念遠心如燒，不覺中夜起。桃花帶露泛，立在月明裏。"]'),
('yuding-28','古別離','聶夷中','唐','御定全唐诗','yuding','','[]','欲別牽郎衣，問郎遊何處。不恨歸日遲，莫向臨邛去。',24,'御定全唐詩/json/636.json','["欲別牽郎衣，問郎遊何處。不恨歸日遲，莫向臨邛去。"]'),
('yuding-29','長安道','聶夷中','唐','御定全唐诗','yuding','','[]','此地無駐馬，夜中猶走輪。所以路傍草，少於衣上塵。',24,'御定全唐詩/json/636.json','["此地無駐馬，夜中猶走輪。所以路傍草，少於衣上塵。"]'),
('yuding-30','遊子行','聶夷中','唐','御定全唐诗','yuding','','[]','萱草生堂階，遊子行天涯。慈親倚門望，不見萱草花。',24,'御定全唐詩/json/636.json','["萱草生堂階，遊子行天涯。慈親倚門望，不見萱草花。"]'),
('yuding-31','聞人說海北事有感','聶夷中','唐','御定全唐诗','yuding','','[]','故鄉歸路隔高雷，見說年來事可哀。村落日中眠虎豹，',40,'御定全唐詩/json/636.json','["故鄉歸路隔高雷，見說年來事可哀。村落日中眠虎豹，", "荊棘滿山行不得，不知當日是誰栽。"]'),
('yuding-0','華清詞','顧雲','唐','御定全唐诗','yuding','','[]','祥雲皓鶴盤碧空，喬松稍稍韻微風。絳節影來，',45,'御定全唐詩/json/637.json','["祥雲皓鶴盤碧空，喬松稍稍韻微風。絳節影來，", "丹砂黃金世可度，願啟一言告仙翁。道門弟子山中客，"]'),
('yuding-1','天威行','顧雲','唐','御定全唐诗','yuding','','[]','蠻嶺高，蠻海闊，去舸回艘投此歇。一夜舟人得夢間，',96,'御定全唐詩/json/637.json','["蠻嶺高，蠻海闊，去舸回艘投此歇。一夜舟人得夢間，", "海神怕急上岸走，山燕股栗入石藏。金蛇飛狀霍閃過，", "風定雲開始望看，萬里青山分兩片。車遙遙，馬闐闐，", "耿恭拜出井底水，廣利刺開山上泉。若論終古濟物意，"]'),
('yuding-2','築城篇','顧雲','唐','御定全唐诗','yuding','','[]','三十六裏西川地，圍繞城郭峨天橫。一家人率一口甓，',72,'御定全唐詩/json/637.json','["三十六裏西川地，圍繞城郭峨天橫。一家人率一口甓，", "不假神龜出指蹤，盡憑心匠為籌畫。畫閣團團真鐵甕，", "散花樓晚掛殘虹，濯錦秋江澄倒碧。西川父老賀子孫，"]'),
('yuding-3','蘇君廳觀韓幹馬障歌','顧雲','唐','御定全唐诗','yuding','','[]','杜甫歌詩吟不足，可憐曹霸丹青曲。直言弟子韓幹馬，',116,'御定全唐詩/json/637.json','["杜甫歌詩吟不足，可憐曹霸丹青曲。直言弟子韓幹馬，", "秦王學士居武功，六印名家聲價雄。乃孫屈跡甯百里，", "屹然六幅古屏上，欻見胡人牽入天廄之神龍。", "麟鬐鳳臆真相似，秋竹慘慘披兩耳。輕勻杏蕊糝皮毛，", "眼前只欠燕雪飛，蹄下如聞朔風起。朱崖謫掾從亡歿，"]'),
('yuding-4','苔歌','顧雲','唐','御定全唐诗','yuding','','[]','檻前溪奪秋空色，百丈潭心數砂礫。松筠條條長碧苔，',98,'御定全唐詩/json/637.json','["檻前溪奪秋空色，百丈潭心數砂礫。松筠條條長碧苔，", "撥浪輕拈出少時，一髻濃煙三四尺。山光日華亂相射，", "如看玉女洗頭處，解破雲鬟收未得。即是仙宮欲制六銖衣，", "瓊蘇玉鹽爛漫煮，咽入丹田續靈液。會待功成插翅飛，"]'),
('yuding-5','池陽醉歌贈匡廬處士姚岩傑','顧雲','唐','御定全唐诗','yuding','','[]','九華太守行春罷，高絳紅筵壓花榭。四面繁英拂檻開，',160,'御定全唐詩/json/637.json','["九華太守行春罷，高絳紅筵壓花榭。四面繁英拂檻開，", "弦索緊快管聲脆，急曲碎拍聲相連。主人憐才多傾興，", "黿潭鱗粉解不去，鴉嶺蕊花澆不醒。肺枯似著爐鞲煽，", "展開一卷讀一首，四顧特地無涯垠。又開一軸讀一帙，", "經疾史恙萬片恨，墨炙筆針如有神。呵叱潘陸鄙瑣屑，", "吳兢纂出升平源，十事分明鋪在紙。裔孫才業今如此，", "戲操狂翰涴蠻箋，傍人莫笑我率然。"]'),
('yuding-6','詠柳二首','顧雲','唐','御定全唐诗','yuding','','[]','帶露含煙處處垂，綻黃搖綠嫩參差。長堤未見風飄絮，',72,'御定全唐詩/json/637.json','["帶露含煙處處垂，綻黃搖綠嫩參差。長堤未見風飄絮，", "離亭不放到春暮，折盡拂簷千萬枝。", "閑花野草總爭新，眉皺絲幹獨不勻。", "乞取東風殘氣力，莫教虛度一年春。"]'),
('yuding-0','宴邊將','張喬','唐','御定全唐诗','yuding','','[]','一曲梁州金石清，邊風蕭颯動江城。',32,'御定全唐詩/json/638.json','["一曲梁州金石清，邊風蕭颯動江城。", "座中有老沙場客，橫笛休吹塞上聲。"]'),
('yuding-1','郢州即事','張喬','唐','御定全唐诗','yuding','','[]','孤城臨遠水，千里見寒山。白雪無人唱，滄洲盡日閑。',48,'御定全唐詩/json/638.json','["孤城臨遠水，千里見寒山。白雪無人唱，滄洲盡日閑。", "鳥歸殘燒外，帆出斷雲間。此地秋風起，應隨計吏還。"]'),
('yuding-2','送賓貢金夷吾奉使歸本國','張喬','唐','御定全唐诗','yuding','','[]','渡海頓仙籍，還家備漢儀。孤舟無岸泊，萬里有星隨。',48,'御定全唐詩/json/638.json','["渡海頓仙籍，還家備漢儀。孤舟無岸泊，萬里有星隨。", "積水浮魂夢，流年半別離。東風未回日，音信杳難期。"]'),
('yuding-3','華山','張喬','唐','御定全唐诗','yuding','','[]','誰將倚天劍，削出倚天峰。眾水背流急，他山相向重。',48,'御定全唐詩/json/638.json','["誰將倚天劍，削出倚天峰。眾水背流急，他山相向重。", "樹黏青靄合，崖夾白雲濃。一夜盆傾雨，前湫起毒龍。"]'),
('yuding-4','滕王閣','張喬','唐','御定全唐诗','yuding','','[]','昔人登覽處，遺閣大江隅。疊浪有時有，閑雲無日無。',48,'御定全唐詩/json/638.json','["昔人登覽處，遺閣大江隅。疊浪有時有，閑雲無日無。", "早涼先燕去，返照後帆孤。未得營歸計，菱歌滿舊湖。"]'),
('yuding-5','寄處士梁燭','張喬','唐','御定全唐诗','yuding','','[]','賢哉君子風，諷與古人同。采藥楚雲裏，移家湘水東。',48,'御定全唐詩/json/638.json','["賢哉君子風，諷與古人同。采藥楚雲裏，移家湘水東。", "星霜秋野闊，雨雹夜山空。早晚相招隱，深耕老此中。"]'),
('yuding-6','送許棠下第游蜀','張喬','唐','御定全唐诗','yuding','','[]','天下猿多處，西南是蜀關。馬登青壁瘦，人宿翠微閑。',48,'御定全唐詩/json/638.json','["天下猿多處，西南是蜀關。馬登青壁瘦，人宿翠微閑。", "帶雨逢殘日，因江見斷山。行歌風月好，莫老錦城間。"]'),
('yuding-7','題終南山白鶴觀','張喬','唐','御定全唐诗','yuding','','[]','上徹煉丹峰，求玄意未窮。古壇青草合，往事白雲空。',48,'御定全唐詩/json/638.json','["上徹煉丹峰，求玄意未窮。古壇青草合，往事白雲空。", "仙境日月外，帝鄉煙霧中。人間足煩暑，欲去戀松風。"]'),
('yuding-8','贈邊將','張喬','唐','御定全唐诗','yuding','','[]','將軍誇膽氣，功在殺人多。對酒擎鐘飲，臨風拔劍歌。',48,'御定全唐詩/json/638.json','["將軍誇膽氣，功在殺人多。對酒擎鐘飲，臨風拔劍歌。", "翻師平碎葉，掠地取交河。應笑孔門客，年年羨四科。"]'),
('yuding-9','吊建州李員外','張喬','唐','御定全唐诗','yuding','','[]','銘旌歸故里，猿鳥亦淒然。已葬桐江月，空回建水船。',48,'御定全唐詩/json/638.json','["銘旌歸故里，猿鳥亦淒然。已葬桐江月，空回建水船。", "客傳為郡日，僧說讀書年。恐有吟魂在，深山古木邊。"]'),
('yuding-10','送許棠及第歸宣州','張喬','唐','御定全唐诗','yuding','','[]','雅調一生吟，誰為晚達心。傍人賀及第，獨自卻沾襟。',48,'御定全唐詩/json/638.json','["雅調一生吟，誰為晚達心。傍人賀及第，獨自卻沾襟。", "宴別喧天樂，家歸礙日岑。青門許攀送，故里接雲林。"]'),
('yuding-11','送龐百篇之任青陽縣尉','張喬','唐','御定全唐诗','yuding','','[]','都堂公試日，詞翰獨超群。品秩台庭與，篇章聖主聞。',48,'御定全唐詩/json/638.json','["都堂公試日，詞翰獨超群。品秩台庭與，篇章聖主聞。", "鄉連三楚樹，縣封九華雲。多少青門客，臨岐共羨君。"]'),
('yuding-12','曲江春','張喬','唐','御定全唐诗','yuding','','[]','尋春與送春，多繞曲江濱。一片鳧鷖水，千秋輦轂塵。',48,'御定全唐詩/json/638.json','["尋春與送春，多繞曲江濱。一片鳧鷖水，千秋輦轂塵。", "岸涼隨眾木，波影逐遊人。自是遊人老，年年管吹新。"]'),
('yuding-13','秦原春望','張喬','唐','御定全唐诗','yuding','','[]','無窮名利塵，軒蓋逐年新。北闕東堂路，千山萬水人。',48,'御定全唐詩/json/638.json','["無窮名利塵，軒蓋逐年新。北闕東堂路，千山萬水人。", "雲離僧榻曙，燕遠鳳樓春。荏苒文明代，難歸釣艇身。"]'),
('yuding-14','游華山雲際寺','張喬','唐','御定全唐诗','yuding','','[]','少華中峰寺，高秋眾景歸。地連秦塞起，河隔晉山微。',48,'御定全唐詩/json/638.json','["少華中峰寺，高秋眾景歸。地連秦塞起，河隔晉山微。", "晚木蟬相應，涼天雁並飛。殷勤記岩石，只恐再來稀。"]'),
('yuding-15','送棋待詔樸球歸新羅','張喬','唐','御定全唐诗','yuding','','[]','海東誰敵手，歸去道應孤。闕下傳新勢，船中覆舊圖。',48,'御定全唐詩/json/638.json','["海東誰敵手，歸去道應孤。闕下傳新勢，船中覆舊圖。", "窮荒回日月，積水載寰區。故國多年別，桑田複在無。"]'),
('yuding-16','送鄭谷先輩赴妝州辟命','張喬','唐','御定全唐诗','yuding','','[]','看花興未休，已散曲江遊。載筆離秦甸，從軍過洛州。',48,'御定全唐詩/json/638.json','["看花興未休，已散曲江遊。載筆離秦甸，從軍過洛州。", "嵩雲將雨去，汝水背城流。應念依門客，蒿萊滿徑秋。"]'),
('yuding-17','贈敬亭清越上人','張喬','唐','御定全唐诗','yuding','','[]','海上獨隨緣，歸來二十年。久閒時得句，漸老不離禪。',48,'御定全唐詩/json/638.json','["海上獨隨緣，歸來二十年。久閒時得句，漸老不離禪。", "砌木欹臨水，窗峰直倚天。猶期向雲裏，別掃石床眠。"]'),
('yuding-18','題靈山寺','張喬','唐','御定全唐诗','yuding','','[]','樹涼清島寺，虛閣敞禪扉。四面閑雲入，中流獨鳥歸。',48,'御定全唐詩/json/638.json','["樹涼清島寺，虛閣敞禪扉。四面閑雲入，中流獨鳥歸。", "湖平幽徑近，船泊夜燈微。一宿秋風裏，煙波隔擣衣。"]'),
('yuding-19','吊棲白上人','張喬','唐','御定全唐诗','yuding','','[]','今古遞相送，幾時無逝波。篇章名不朽，寂滅理如何。',48,'御定全唐詩/json/638.json','["今古遞相送，幾時無逝波。篇章名不朽，寂滅理如何。", "內殿留真影，閒房落貝多。從茲高塔寺，惆悵懶經過。"]'),
('yuding-20','北山書事','張喬','唐','御定全唐诗','yuding','','[]','黃河一曲山，天半鎖重關。聖日雄藩靜，秋風老將閑。',48,'御定全唐詩/json/638.json','["黃河一曲山，天半鎖重關。聖日雄藩靜，秋風老將閑。", "車輿穿穀口，市井響雲間。大野無飛鳥，元戎校獵還。"]'),
('yuding-21','長安書事','張喬','唐','御定全唐诗','yuding','','[]','出送鄉人盡，滄洲未得還。秋風五陵樹，晴日六街山。',48,'御定全唐詩/json/638.json','["出送鄉人盡，滄洲未得還。秋風五陵樹，晴日六街山。", "有景終年住，無機是處閑。何當向雲外，免老別離間。"]'),
('yuding-22','送鄭侍禦赴汴州辟命','張喬','唐','御定全唐诗','yuding','','[]','官從諫署清，暫去佐戎旌。朝客多相戀，吟僧欲伴行。',48,'御定全唐詩/json/638.json','["官從諫署清，暫去佐戎旌。朝客多相戀，吟僧欲伴行。", "河冰天際白，嶽雪眼前明。即見東風起，梁園聽早鶯。"]'),
('yuding-23','吊造微上人','張喬','唐','御定全唐诗','yuding','','[]','至人隨化往，遺路自堪傷。白塔收真骨，青山閉影堂。',48,'御定全唐詩/json/638.json','["至人隨化往，遺路自堪傷。白塔收真骨，青山閉影堂。", "鐘殘含細韻，煙滅有餘香。松上齋烏在，遲遲立夕陽。"]'),
('yuding-24','經隱岩舊居','張喬','唐','御定全唐诗','yuding','','[]','夜久村落靜，徘徊楊柳津。青山猶有路，明月已無人。',48,'御定全唐詩/json/638.json','["夜久村落靜，徘徊楊柳津。青山猶有路，明月已無人。", "夢寐空前事，星霜倦此身。嘗期結茅處，來往躡遺塵。"]'),
('yuding-25','再題敬亭清越上人山房','張喬','唐','御定全唐诗','yuding','','[]','重來訪惠休，已是十年遊。向水千松老，空山一磬秋。',48,'御定全唐詩/json/638.json','["重來訪惠休，已是十年遊。向水千松老，空山一磬秋。", "石窗清吹入，河漢夜光流。久別多新作，長吟洗俗愁。"]'),
('yuding-26','浮汴東歸','張喬','唐','御定全唐诗','yuding','','[]','日暖泗濱西，無窮岸草齊。薄煙衰草樹，微月迥城雞。',48,'御定全唐詩/json/638.json','["日暖泗濱西，無窮岸草齊。薄煙衰草樹，微月迥城雞。", "水近滄浪急，山隨綠野低。羞將舊名姓，還向舊遊題。"]'),
('yuding-27','雨中宿僧院','張喬','唐','御定全唐诗','yuding','','[]','千燈有宿因，長老許相親。夜永樓臺雨，更深江海人。',48,'御定全唐詩/json/638.json','["千燈有宿因，長老許相親。夜永樓臺雨，更深江海人。", "勞生無了日，妄念起微塵。不是真如理，何門靜此身。"]'),
('yuding-28','江行至沙浦','張喬','唐','御定全唐诗','yuding','','[]','煙霞接杳冥，旅泊寄回汀。夜雨雷電歇，春江蛟蜃腥。',48,'御定全唐詩/json/638.json','["煙霞接杳冥，旅泊寄回汀。夜雨雷電歇，春江蛟蜃腥。", "城侵潮影白，嶠截鳥行青。遍欲探泉石，南須過洞庭。"]'),
('yuding-29','送友人歸江南','張喬','唐','御定全唐诗','yuding','','[]','辛勤同失意，迢遞獨還家。落日江邊笛，殘春島上花。',48,'御定全唐詩/json/638.json','["辛勤同失意，迢遞獨還家。落日江邊笛，殘春島上花。", "親安誠可喜，道在亦何嗟。誰伴高吟處，晴天望九華。"]'),
('yuding-30','劉補闕自九華山拜官因以寄獻','張喬','唐','御定全唐诗','yuding','','[]','冥鴻久不群，征拜動天文。地主迎過郡，山僧送出雲。',48,'御定全唐詩/json/638.json','["冥鴻久不群，征拜動天文。地主迎過郡，山僧送出雲。", "登車殘月在，宿館亂流分。若更思林下，還須共致君。"]'),
('yuding-31','岳陽即事','張喬','唐','御定全唐诗','yuding','','[]','遠色岳陽樓，湘帆數片愁。竹風山上路，沙月水中洲。',48,'御定全唐詩/json/638.json','["遠色岳陽樓，湘帆數片愁。竹風山上路，沙月水中洲。", "力學桑田廢，思歸鬢髮秋。功名如不立，豈易狎汀鷗。"]'),
('yuding-32','題興善寺僧道深院','張喬','唐','御定全唐诗','yuding','','[]','江峰峰頂人，受法老西秦。法本無前業，禪非為後身。',48,'御定全唐詩/json/638.json','["江峰峰頂人，受法老西秦。法本無前業，禪非為後身。", "院栽他國樹，堂展祖師真。甚願依宗旨，求閑未有因。"]'),
('yuding-33','送龍門令劉滄','張喬','唐','御定全唐诗','yuding','','[]','去宰龍門縣，應思變化年。還將魯儒政，又與晉人傳。',48,'御定全唐詩/json/638.json','["去宰龍門縣，應思變化年。還將魯儒政，又與晉人傳。", "峭壁開中古，長河落半天。幾鄉因勸勉，耕稼滿雲煙。"]'),
('yuding-34','送友人往宜春','張喬','唐','御定全唐诗','yuding','','[]','落花兼柳絮，無處不紛紛。遠道空歸去，流鶯獨自聞。',48,'御定全唐詩/json/638.json','["落花兼柳絮，無處不紛紛。遠道空歸去，流鶯獨自聞。", "野橋喧磑水，山郭入樓雲。故里南陵曲，秋期更送君。"]'),
('yuding-35','書邊事','張喬','唐','御定全唐诗','yuding','','[]','調角斷清秋，征人倚戍樓。春風對青塚，白日落梁州。',48,'御定全唐詩/json/638.json','["調角斷清秋，征人倚戍樓。春風對青塚，白日落梁州。", "大漢無兵阻，窮邊有客遊。蕃情似此水，長願向南流。"]'),
('yuding-36','送僧雅覺歸東海','張喬','唐','御定全唐诗','yuding','','[]','山川心地內，一念即千重。老別關中寺，禪歸海外峰。',48,'御定全唐詩/json/638.json','["山川心地內，一念即千重。老別關中寺，禪歸海外峰。", "鳥行來有路，帆影去無蹤。幾夜波濤息，先聞本國鐘。"]'),
('yuding-37','和薛監察題興善寺古松','張喬','唐','御定全唐诗','yuding','','[]','種在法王城，前朝古寺名。瘦根盤地遠，香吹入雲清。',48,'御定全唐詩/json/638.json','["種在法王城，前朝古寺名。瘦根盤地遠，香吹入雲清。", "鶴動池台影，僧禪雨雪聲。看來人旋老，因此歎浮生。"]'),
('yuding-38','聽琴','張喬','唐','御定全唐诗','yuding','','[]','清月轉瑤軫，弄中湘水寒。能令坐來客，不語自相看。',48,'御定全唐詩/json/638.json','["清月轉瑤軫，弄中湘水寒。能令坐來客，不語自相看。", "靜恐鬼神出，急疑風雨殘。幾時歸嶺嶠，更過洞庭彈。"]'),
('yuding-39','送友人游蜀','張喬','唐','御定全唐诗','yuding','','[]','此心知者稀，欲別倍相依。無食擬同去，有家還未歸。',48,'御定全唐詩/json/638.json','["此心知者稀，欲別倍相依。無食擬同去，有家還未歸。", "巴山開國遠，劍道入天微。必恐臨邛客，疑君學賦非。"]'),
('yuding-40','聞仰山禪師往曹溪因贈','張喬','唐','御定全唐诗','yuding','','[]','曹溪松下路，猿鳥重相親。四海求玄理，千峰繞定身。',48,'御定全唐詩/json/638.json','["曹溪松下路，猿鳥重相親。四海求玄理，千峰繞定身。", "異花天上墮，靈草雪中春。自惜經行處，焚香禮舊真。"]'),
('yuding-41','藍溪夜坐','張喬','唐','御定全唐诗','yuding','','[]','藍水警塵夢，夜吟開草堂。月臨山靄薄，松滴露花香。',48,'御定全唐詩/json/638.json','["藍水警塵夢，夜吟開草堂。月臨山靄薄，松滴露花香。", "詩外真風遠，人間靜興長。明朝訪禪侶，更上翠微房。"]'),
('yuding-42','題鄭侍禦藍田別業','張喬','唐','御定全唐诗','yuding','','[]','秋山清若水，吟客靜於僧。小徑通商嶺，高窗見杜陵。',48,'御定全唐詩/json/638.json','["秋山清若水，吟客靜於僧。小徑通商嶺，高窗見杜陵。", "雲霞朝入鏡，猿鳥夜窺燈。許作前峰侶，終來寄上層。"]'),
('yuding-43','送友人進士許棠','張喬','唐','御定全唐诗','yuding','','[]','離鄉積歲年，歸路遠依然。夜火山頭市，春江樹杪船。',48,'御定全唐詩/json/638.json','["離鄉積歲年，歸路遠依然。夜火山頭市，春江樹杪船。", "干戈愁鬢改，瘴癘喜家全。何處營甘旨，潮濤浸薄田。"]'),
('yuding-44','秘省伴直','張喬','唐','御定全唐诗','yuding','','[]','喬枝聚暝禽，疊閣鎖遙岑。待月當秋直，看書廢夜吟。',48,'御定全唐詩/json/638.json','["喬枝聚暝禽，疊閣鎖遙岑。待月當秋直，看書廢夜吟。", "殘薪留火細，古井下瓶深。縱欲抄前史，貧難遂此心。"]'),
('yuding-45','宿昭應','張喬','唐','御定全唐诗','yuding','','[]','夜憶開元寺，淒涼裏巷間。薄煙通魏闕，明月照驪山。',48,'御定全唐詩/json/638.json','["夜憶開元寺，淒涼裏巷間。薄煙通魏闕，明月照驪山。", "半壁空宮閉，連天白道閑。清晨更回首，獨向灞陵還。"]'),
('yuding-46','送陸處士','張喬','唐','御定全唐诗','yuding','','[]','樽前放浩歌，便起泛煙波。舟楫故人少，江湖明月多。',48,'御定全唐詩/json/638.json','["樽前放浩歌，便起泛煙波。舟楫故人少，江湖明月多。", "孤峰經宿上，僻寺共雲過。若向仙岩住，還應著薜蘿。"]'),
('yuding-47','送韓處士歸少室山','張喬','唐','御定全唐诗','yuding','','[]','江外曆千岑，還歸少室吟。地閑緱嶺月，窗迥洛城砧。',48,'御定全唐詩/json/638.json','["江外曆千岑，還歸少室吟。地閑緱嶺月，窗迥洛城砧。", "石竇垂寒乳，松枝長別琴。他年瀑泉下，亦擬置家林。"]'),
('yuding-48','贈初上人','張喬','唐','御定全唐诗','yuding','','[]','竹色覆禪棲，幽禽繞院啼。空門無去住，行客自東西。',48,'御定全唐詩/json/638.json','["竹色覆禪棲，幽禽繞院啼。空門無去住，行客自東西。", "井氣春來歇，庭枝雪後低。相看念山水，盡日話曹溪。"]'),
('yuding-49','送新羅僧','張喬','唐','御定全唐诗','yuding','','[]','東來此學禪，多病念佛緣。把錫離岩寺，收經上海船。',48,'御定全唐詩/json/638.json','["東來此學禪，多病念佛緣。把錫離岩寺，收經上海船。", "落帆敲石火，宿島汲瓶泉。永向扶桑老，知無再少年。"]'),
('yuding-50','題山僧院','張喬','唐','御定全唐诗','yuding','','[]','溪路曾來日，年多與舊同。地寒松影裏，僧老磬聲中。',48,'御定全唐詩/json/638.json','["溪路曾來日，年多與舊同。地寒松影裏，僧老磬聲中。", "遠水清風落，閑雲別院通。心源若無礙，何必更論空。"]'),
('yuding-51','書梅福殿壁二首','張喬','唐','御定全唐诗','yuding','','[]','梅真從羽化，萬古是須臾。此地名空在，西山雲亦孤。',96,'御定全唐詩/json/638.json','["梅真從羽化，萬古是須臾。此地名空在，西山雲亦孤。", "井痕平野水，壇級上春蕪。縱有雙飛鶴，年多松已枯。", "一自白雲去，千秋壇月明。我來思往事，誰更得長生。", "雅韻磬鐘遠，真風樓殿清。今來為尉者，天下有仙名。"]'),
('yuding-52','荊楚道中','張喬','唐','御定全唐诗','yuding','','[]','前程曾未到，岐路擬何為。返照行人急，荒郊去鳥遲。',48,'御定全唐詩/json/638.json','["前程曾未到，岐路擬何為。返照行人急，荒郊去鳥遲。", "春宵多旅夢，夏閏遠秋期。處處牽愁緒，無窮是柳絲。"]'),
('yuding-53','送南陵尉李頻','張喬','唐','御定全唐诗','yuding','','[]','重作東南尉，生涯尚似僧。客程淮館月，鄉思海船燈。',48,'御定全唐詩/json/638.json','["重作東南尉，生涯尚似僧。客程淮館月，鄉思海船燈。", "晚霧看春轂，晴天見朗陵。不應三考足，先授詔書征。"]'),
('yuding-54','將歸江淮書','張喬','唐','御定全唐诗','yuding','','[]','東風搖眾木，即有看花期。紫陌頻來日，滄洲獨去時。',48,'御定全唐詩/json/638.json','["東風搖眾木，即有看花期。紫陌頻來日，滄洲獨去時。", "郡因兵役苦，家為海翻移。未老多如此，那堪鬢不衰。"]'),
('yuding-55','沿漢東歸','張喬','唐','御定全唐诗','yuding','','[]','北去窮秦塞，南歸繞漢川。深山逢古跡，遠道見新年。',48,'御定全唐詩/json/638.json','["北去窮秦塞，南歸繞漢川。深山逢古跡，遠道見新年。", "絕壁雲銜寺，空江雪灑船。縈回還此景，多坐夜燈前。"]'),
('yuding-56','送蜀客','張喬','唐','御定全唐诗','yuding','','[]','劍閣緣空去，西南轉幾州。丹霄行客語，明月杜鵑愁。',48,'御定全唐詩/json/638.json','["劍閣緣空去，西南轉幾州。丹霄行客語，明月杜鵑愁。", "露帶山花落，雲隨野水流。相如曾醉地，莫滯少年游。"]'),
('yuding-57','塞上','張喬','唐','御定全唐诗','yuding','','[]','勒兵遼水邊，風急卷旌旃。絕塞寒無樹，平沙勢盡天。',48,'御定全唐詩/json/638.json','["勒兵遼水邊，風急卷旌旃。絕塞寒無樹，平沙勢盡天。", "雪晴回探騎，月落控鳴弦。永定山河誓，南歸改漢年。"]'),
('yuding-58','送友人歸袁州','張喬','唐','御定全唐诗','yuding','','[]','袁江猿鳥清，曾向此中行。才子登科去，諸侯掃榻迎。',48,'御定全唐詩/json/638.json','["袁江猿鳥清，曾向此中行。才子登科去，諸侯掃榻迎。", "山藏明月浦，樹繞白雲城。遠想安親後，秋風夢不驚。"]'),
('yuding-59','贈別李山人','張喬','唐','御定全唐诗','yuding','','[]','分合老西秦，年年夢白蘋。曾為洞庭客，還送洞庭人。',48,'御定全唐詩/json/638.json','["分合老西秦，年年夢白蘋。曾為洞庭客，還送洞庭人。", "語別惜殘夜，思歸愁見春。遙知泊舟處，沙月自相親。"]'),
('yuding-60','思宜春寄友人','張喬','唐','御定全唐诗','yuding','','[]','勝遊雖來年，魂夢亦依然。瀑水喧秋思，孤燈動夜船。',48,'御定全唐詩/json/638.json','["勝遊雖來年，魂夢亦依然。瀑水喧秋思，孤燈動夜船。", "斷虹全嶺雨，斜月半溪煙。舊日吟詩侶，何人更不眠。"]'),
('yuding-61','江行夜雨','張喬','唐','御定全唐诗','yuding','','[]','江風木落天，遊子感流年。萬里波連蜀，三更雨到船。',48,'御定全唐詩/json/638.json','["江風木落天，遊子感流年。萬里波連蜀，三更雨到船。", "夢殘燈影外，愁積葦叢邊。不及樵漁客，全家住島田。"]'),
('yuding-62','贈仰大師','張喬','唐','御定全唐诗','yuding','','[]','仰山因久住，天下仰山名。井邑身雖到，林泉性本清。',48,'御定全唐詩/json/638.json','["仰山因久住，天下仰山名。井邑身雖到，林泉性本清。", "野雲居處盡，江月定中明。仿佛曾相識，今來隔幾生。"]'),
('yuding-63','江南逢洛下友人','張喬','唐','御定全唐诗','yuding','','[]','洛下吟詩侶，南遊只有君。波濤歸路見，蟋蟀在船聞。',48,'御定全唐詩/json/638.json','["洛下吟詩侶，南遊只有君。波濤歸路見，蟋蟀在船聞。", "曉月江城出，晴霞島樹分。無窮懷古意，豈獨繞湘雲。"]'),
('yuding-64','東湖贈僧子蘭','張喬','唐','御定全唐诗','yuding','','[]','名利了無時，何人暫訪師。道情閑外見，心地語來知。',48,'御定全唐詩/json/638.json','["名利了無時，何人暫訪師。道情閑外見，心地語來知。", "竹落穿窗葉，松寒蔭井枝。匡山許同社，願蔔掛帆期。"]'),
('yuding-65','隱岩陪鄭少師夜坐','張喬','唐','御定全唐诗','yuding','','[]','幸喜陪騶馭，頻來向此宵。硯磨清澗石，廚爨白雲樵。',48,'御定全唐詩/json/638.json','["幸喜陪騶馭，頻來向此宵。硯磨清澗石，廚爨白雲樵。", "竹外村煙細，燈中禁漏遙。衣冠與文理，靜語對前朝。"]'),
('yuding-66','送三傳赴長城尉','張喬','唐','御定全唐诗','yuding','','[]','登科精魯史，為尉及良時。高論窮諸國，長才並幾司。',48,'御定全唐詩/json/638.json','["登科精魯史，為尉及良時。高論窮諸國，長才並幾司。", "地傾流水疾，山疊過雲遲。暇日琴書畔，何人對手棋。"]'),
('yuding-67','送李道士歸南嶽','張喬','唐','御定全唐诗','yuding','','[]','千峰隔湘水，迢遞掛帆歸。掃月眠蒼壁，和雲著褐衣。',48,'御定全唐詩/json/638.json','["千峰隔湘水，迢遞掛帆歸。掃月眠蒼壁，和雲著褐衣。", "洞虛懸溜滴，徑狹長松圍。只恐相尋日，人間舊識稀。"]'),
('yuding-68','延福裏秋懷','張喬','唐','御定全唐诗','yuding','','[]','終年九陌行，要路跡皆生。苦學猶難至，甘貧豈有成。',48,'御定全唐詩/json/638.json','["終年九陌行，要路跡皆生。苦學猶難至，甘貧豈有成。", "病攜秋卷重，閑著暑衣輕。一別林泉久，中宵禦水聲。"]'),
('yuding-69','題玄哲禪師影堂','張喬','唐','御定全唐诗','yuding','','[]','吾師視化身，一念即遺塵。岩谷藏虛塔，江湖散學人。',48,'御定全唐詩/json/638.json','["吾師視化身，一念即遺塵。岩谷藏虛塔，江湖散學人。", "雲迷禪處石，院掩寫來真。寂寞焚香後，閑階細草生。"]'),
('yuding-70','登慈恩寺塔','張喬','唐','御定全唐诗','yuding','','[]','窗戶幾層風，清涼碧落中。世人來往別，煙景古今同。',48,'御定全唐詩/json/638.json','["窗戶幾層風，清涼碧落中。世人來往別，煙景古今同。", "列岫橫秦斷，長河極塞空。斜陽越鄉思，天末見歸鴻。"]'),
('yuding-71','送友人東歸','張喬','唐','御定全唐诗','yuding','','[]','遠涉期秋卷，將行不廢吟。故鄉芳草路，來往別離心。',48,'御定全唐詩/json/638.json','["遠涉期秋卷，將行不廢吟。故鄉芳草路，來往別離心。", "掛席春風盡，開齋夏景深。子規誰共聽，江月上清岑。"]'),
('yuding-72','送僧鸞歸蜀甯親','張喬','唐','御定全唐诗','yuding','','[]','歌詩精外學，天子是知音。坐夏宮鐘近，寧親劍閣深。',48,'御定全唐詩/json/638.json','["歌詩精外學，天子是知音。坐夏宮鐘近，寧親劍閣深。", "高名徹西國，舊跡寄東林。自此棲禪者，因師滿蜀吟。"]'),
('yuding-73','送人歸江南','張喬','唐','御定全唐诗','yuding','','[]','貧歸無定程，水宿與山行。未有安親計，難為去國情。',48,'御定全唐詩/json/638.json','["貧歸無定程，水宿與山行。未有安親計，難為去國情。", "島煙孤寺磬，江月遠船箏。思苦秋回日，多應吟更清。"]'),
('yuding-74','將離江上作','張喬','唐','御定全唐诗','yuding','','[]','白衣歸樹下，青草戀江邊。三楚足深隱，五陵多少年。',48,'御定全唐詩/json/638.json','["白衣歸樹下，青草戀江邊。三楚足深隱，五陵多少年。", "寂寥聞蜀魄，清絕怨湘弦。岐路在何處，西行心渺然。"]'),
('yuding-75','別李參軍','張喬','唐','御定全唐诗','yuding','','[]','王孫游不遇，況我五湖人。野店難投宿，漁家獨問津。',48,'御定全唐詩/json/638.json','["王孫游不遇，況我五湖人。野店難投宿，漁家獨問津。", "嶺分中夜月，江隔兩鄉春。靜想青雲路，還應寄此身。"]'),
('yuding-76','送睦州張參軍','張喬','唐','御定全唐诗','yuding','','[]','重祿輕身日，清資近故鄉。因知送君後，轉自惜年芳。',48,'御定全唐詩/json/638.json','["重祿輕身日，清資近故鄉。因知送君後，轉自惜年芳。", "遠水分林影，層峰起鳥行。扁舟此中去，溪月有餘光。"]'),
('yuding-77','贈棋僧侶','張喬','唐','御定全唐诗','yuding','','[]','機謀時未有，多向弈棋銷。已與山僧敵，無令海客饒。',48,'御定全唐詩/json/638.json','["機謀時未有，多向弈棋銷。已與山僧敵，無令海客饒。", "靜驅雲陣起，疏點雁行遙。夜雨如相憶，松窗更見招。"]'),
('yuding-78','題湖上友人居','張喬','唐','御定全唐诗','yuding','','[]','豈得戀樵漁，全家湖畔居。遠無潮客信，閑寄嶽僧書。',48,'御定全唐詩/json/638.json','["豈得戀樵漁，全家湖畔居。遠無潮客信，閑寄嶽僧書。", "野白梅繁後，山明雨散初。逍遙向雲水，莫與宦情疏。"]'),
('yuding-79','送友人歸宣州','張喬','唐','御定全唐诗','yuding','','[]','失計複離愁，君歸我獨遊。亂花藏道發，春水繞鄉流。',48,'御定全唐詩/json/638.json','["失計複離愁，君歸我獨遊。亂花藏道發，春水繞鄉流。", "暝火叢橋市，晴山疊郡樓。無為謝公戀，吟過曉蟬秋。"]'),
('yuding-80','題古觀','張喬','唐','御定全唐诗','yuding','','[]','急景遞衰老，此經誰養真。松留千載鶴，碑隔六朝人。',48,'御定全唐詩/json/638.json','["急景遞衰老，此經誰養真。松留千載鶴，碑隔六朝人。", "洞水流花早，壺天閉雪春。其如為名利，歸踏五陵塵。"]'),
('yuding-81','送友人及第歸江南','張喬','唐','御定全唐诗','yuding','','[]','豈易及歸榮，辛勤致此名。登車思往事，回首勉諸生。',48,'御定全唐詩/json/638.json','["豈易及歸榮，辛勤致此名。登車思往事，回首勉諸生。", "路繞山光曉，帆通海氣清。秋期卻閑坐，林下聽江聲。"]'),
('yuding-82','送樸充侍禦歸海東','張喬','唐','御定全唐诗','yuding','','[]','天涯離二紀，闕下曆三朝。漲海雖然闊，歸帆不覺遙。',48,'御定全唐詩/json/638.json','["天涯離二紀，闕下曆三朝。漲海雖然闊，歸帆不覺遙。", "驚波時失侶，舉火夜相招。來往尋遺事，秦皇有斷橋。"]'),
('yuding-83','吊前水部賈員外','張喬','唐','御定全唐诗','yuding','','[]','籠中江海禽，日夕有歸心。魏闕長謠久，吳山獨往深。',48,'御定全唐詩/json/638.json','["籠中江海禽，日夕有歸心。魏闕長謠久，吳山獨往深。", "別時群木落，終處亂猿吟。李白墳前路，溪僧送入林。"]'),
('yuding-84','題小松','張喬','唐','御定全唐诗','yuding','','[]','松子落何年，纖枝長水邊。斫開深澗雪，移出遠林煙。',48,'御定全唐詩/json/638.json','["松子落何年，纖枝長水邊。斫開深澗雪，移出遠林煙。", "帶月棲幽鳥，兼花灌冷泉。微風動清韻，閑聽罷琴眠。"]'),
('yuding-85','寄中嶽顓頊先生','張喬','唐','御定全唐诗','yuding','','[]','先生顓頊後，得道自何人。松柏卑于壽，兒孫老卻身。',48,'御定全唐詩/json/638.json','["先生顓頊後，得道自何人。松柏卑于壽，兒孫老卻身。", "夜窗峰頂曙，寒澗洞中春。戀此逍遙境，雲間不可親。"]'),
('yuding-86','送沈先輩尉昭應','張喬','唐','御定全唐诗','yuding','','[]','餘才不廢詩，佐邑喜閑司。丹陛終須去，青山未可期。',48,'御定全唐詩/json/638.json','["餘才不廢詩，佐邑喜閑司。丹陛終須去，青山未可期。", "葉凋溫穀晚，雲出古宮遲。若草東封疏，君王到有時。"]'),
('yuding-87','送友人游湖南','張喬','唐','御定全唐诗','yuding','','[]','所投非舊知，亦似有前期。路向長江上，帆揚細雨時。',48,'御定全唐詩/json/638.json','["所投非舊知，亦似有前期。路向長江上，帆揚細雨時。", "春生南嶽早，日轉大荒遲。盡采瀟湘句，重來會近期。"]'),
('yuding-88','江上送友人南游','張喬','唐','御定全唐诗','yuding','','[]','何處積鄉愁，天涯聚亂流。岸長群岫晚，湖闊片帆秋。',48,'御定全唐詩/json/638.json','["何處積鄉愁，天涯聚亂流。岸長群岫晚，湖闊片帆秋。", "買酒過漁舍，分燈與釣舟。瀟湘見來雁，應念獨邊遊。"]'),
('yuding-89','江南別友人','張喬','唐','御定全唐诗','yuding','','[]','勞生故白頭，頭白未應休。闕下難孤立，天涯尚旅遊。',48,'御定全唐詩/json/638.json','["勞生故白頭，頭白未應休。闕下難孤立，天涯尚旅遊。", "聽猿吟島寺，待月上江樓。醉別醒惆悵，雲帆滿亂流。"]'),
('yuding-90','商山道中','張喬','唐','御定全唐诗','yuding','','[]','春去計秋期，長安在夢思。多逢山好處，少值客行時。',48,'御定全唐詩/json/638.json','["春去計秋期，長安在夢思。多逢山好處，少值客行時。", "雲起爭峰勢，花交隱澗枝。停驂一惆悵，應只嶺猿知。"]'),
('yuding-91','吳江旅次','張喬','唐','御定全唐诗','yuding','','[]','行人愁落日，去鳥倦遙林。曠野鳴流水，空山響暮砧。',48,'御定全唐詩/json/638.json','["行人愁落日，去鳥倦遙林。曠野鳴流水，空山響暮砧。", "旅途歸計晚，鄉樹別年深。寂寞逢村酒，漁家一醉吟。"]'),
('yuding-92','寄南中友人','張喬','唐','御定全唐诗','yuding','','[]','相夢如相見，相思去後頻。舊時行處斷，華髮別來新。',48,'御定全唐詩/json/638.json','["相夢如相見，相思去後頻。舊時行處斷，華髮別來新。", "浪動三湘月，煙藏五嶺春。又無歸北客，書劄寄何人。"]'),
('yuding-93','寄績溪陳明府','張喬','唐','御定全唐诗','yuding','','[]','古邑猿聲裏，空城只半存。岸移無舊路，沙漲別成村。',48,'御定全唐詩/json/638.json','["古邑猿聲裏，空城只半存。岸移無舊路，沙漲別成村。", "鼓角喧京口，江山盡汝濆。六朝興廢地，行子一銷魂。"]'),
('yuding-94','試月中桂','張喬','唐','御定全唐诗','yuding','','[]','與月轉洪蒙，扶疏萬古同。根非生下土，葉不墜秋風。',72,'御定全唐詩/json/638.json','["與月轉洪蒙，扶疏萬古同。根非生下土，葉不墜秋風。", "每以圓時足，還隨缺處空。影高群木外，香滿一輪中。", "未種丹霄日，應虛玉兔宮。何當因羽化，細得問玄功。"]'),
('yuding-95','遊歙州興唐寺','張喬','唐','御定全唐诗','yuding','','[]','山橋通絕境，到此憶天臺。竹裏尋幽徑，雲邊上古台。',48,'御定全唐詩/json/638.json','["山橋通絕境，到此憶天臺。竹裏尋幽徑，雲邊上古台。", "鳥歸殘照出，鐘斷細泉來。為愛澄溪月，因成隔宿回。"]'),
('yuding-96','題詮律師院','張喬','唐','御定全唐诗','yuding','','[]','院涼松雨聲，相對有山情。未許溪邊老，猶思嶽頂行。',48,'御定全唐詩/json/638.json','["院涼松雨聲，相對有山情。未許溪邊老，猶思嶽頂行。", "紗燈留火細，石井灌瓶清。欲問吾師外，何人得此生。"]'),
('yuding-97','金山寺空上人院','張喬','唐','御定全唐诗','yuding','','[]','已老金山頂，無心上石橋。講移三楚遍，梵譯五天遙。',48,'御定全唐詩/json/638.json','["已老金山頂，無心上石橋。講移三楚遍，梵譯五天遙。", "板閣禪秋月，銅瓶汲夜潮。自慚昏醉客，來坐亦通宵。"]'),
('yuding-98','題廣信寺','張喬','唐','御定全唐诗','yuding','','[]','亭北敞靈溪，林梢與檻齊。野雲來影遠，沙鳥去行低。',48,'御定全唐詩/json/638.json','["亭北敞靈溪，林梢與檻齊。野雲來影遠，沙鳥去行低。", "晚渡明村火，晴山響郡鼙。思鄉值搖落，賴不有猿啼。"]'),
('yuding-0','興善寺貝多樹','張喬','唐','御定全唐诗','yuding','','[]','還應毫末長，始見拂丹霄。得子從西國，成陰見昔朝。',96,'御定全唐詩/json/639.json','["還應毫末長，始見拂丹霄。得子從西國，成陰見昔朝。", "勢隨雙刹直，寒出四牆遙。帶月啼春鳥，連空噪暝蜩。", "遠根穿古井，高頂起涼飆。影動懸燈夜，聲繁過雨朝。", "靜遲松桂老，堅任雪霜凋。永共終南在，應隨劫火燒。"]'),
('yuding-1','華山','張喬','唐','御定全唐诗','yuding','','[]','青蒼河一隅，氣狀杳難圖。卓傑三峰出，高奇四嶽無。',144,'御定全唐詩/json/639.json','["青蒼河一隅，氣狀杳難圖。卓傑三峰出，高奇四嶽無。", "力疑擎上界，勢獨壓中區。眾水東西走，群山遠近趨。", "天回諸宿照，地聳百靈扶。石壁煙霞麗，龍潭雨雹粗。", "澄凝臨甸服，險固束神都。淺覺川原異，深應日月殊。", "鶴歸青靄合，仙去白雲孤。瀑漏斜飛凍，松長倒掛枯。", "每來尋洞穴，不擬返江湖。儻有芝田種，岩間老一夫。"]'),
('yuding-2','送何道士歸山','張喬','唐','御定全唐诗','yuding','','[]','身非絕粒本清羸，束掛仙經杖一枝。落葉獨尋流水去，',40,'御定全唐詩/json/639.json','["身非絕粒本清羸，束掛仙經杖一枝。落葉獨尋流水去，", "樵客若能隨洞裏，回歸人世始應悲。"]'),
('yuding-3','城東寓居寄知己','張喬','唐','御定全唐诗','yuding','','[]','花木閑門苔蘚生，滻川特去得吟情。病來久絕洞庭信，',40,'御定全唐詩/json/639.json','["花木閑門苔蘚生，滻川特去得吟情。病來久絕洞庭信，", "幹時退出長如此，頻愧相憂道姓名。"]'),
('yuding-4','再書邊事','張喬','唐','御定全唐诗','yuding','','[]','萬里沙西寇已平，犬羊群外築空城。分營夜火燒雲遠，',40,'御定全唐詩/json/639.json','["萬里沙西寇已平，犬羊群外築空城。分營夜火燒雲遠，", "羌戎不識干戈老，須賀當時聖主明。"]'),
('yuding-5','游邊感懷二首','張喬','唐','御定全唐诗','yuding','','[]','貧游繚繞困邊沙，卻被遼陽戰士嗟。',64,'御定全唐詩/json/639.json','["貧游繚繞困邊沙，卻被遼陽戰士嗟。", "不是無家歸不得，有家歸去似無家。", "兄弟江南身塞北，雁飛猶自半年餘。", "夜來因得思鄉夢，重讀前秋轉海書。"]'),
('yuding-6','無題','張喬','唐','御定全唐诗','yuding','','[]','九霄無詔下，何事觸清塵。宅帶松蘿僻，身惟猿鳥親。',48,'御定全唐詩/json/639.json','["九霄無詔下，何事觸清塵。宅帶松蘿僻，身惟猿鳥親。", "吟看仙掌月，期有洞庭人。莫問煙霞句，懸知見嶽神。"]'),
('yuding-7','蟬','張喬','唐','御定全唐诗','yuding','','[]','先秋蟬一悲，長是客行時。曾感去年者，又鳴何處枝。',48,'御定全唐詩/json/639.json','["先秋蟬一悲，長是客行時。曾感去年者，又鳴何處枝。", "細聽殘韻在，回望舊聲遲。斷續誰家樹，涼風送別離。"]'),
('yuding-8','江上逢進士許棠','張喬','唐','御定全唐诗','yuding','','[]','詩人推上第，新榜又無君。鶴發他鄉老，漁歌故國聞。',48,'御定全唐詩/json/639.json','["詩人推上第，新榜又無君。鶴發他鄉老，漁歌故國聞。", "平江流曉月，獨鳥伴餘雲。且了髫年志，沙鷗未可群。"]'),
('yuding-9','送河西從事','張喬','唐','御定全唐诗','yuding','','[]','結束佐戎旃，河西住幾年。隴頭隨日去，磧裏寄星眠。',48,'御定全唐詩/json/639.json','["結束佐戎旃，河西住幾年。隴頭隨日去，磧裏寄星眠。", "水近沙連帳，程遙馬入天。聖朝思上策，重待奏安邊。"]'),
('yuding-10','河湟舊卒','張喬','唐','御定全唐诗','yuding','','[]','少年隨將討河湟，頭白時清返故鄉。',32,'御定全唐詩/json/639.json','["少年隨將討河湟，頭白時清返故鄉。", "十萬漢軍零落盡，獨吹邊曲向殘陽。"]'),
('yuding-11','促織','張喬','唐','御定全唐诗','yuding','','[]','念爾無機自有情，迎寒辛苦弄梭聲。',32,'御定全唐詩/json/639.json','["念爾無機自有情，迎寒辛苦弄梭聲。", "椒房金屋何曾識，偏向貧家壁下鳴。"]'),
('yuding-12','猿','張喬','唐','御定全唐诗','yuding','','[]','掛月棲雲向楚林，取來全是為清音。',32,'御定全唐詩/json/639.json','["掛月棲雲向楚林，取來全是為清音。", "誰知系在黃金索，翻畏侯家不敢吟。"]'),
('yuding-13','寄薦福寺棲白大師','張喬','唐','御定全唐诗','yuding','','[]','高塔六街無不見，塔邊名出只吾師。',32,'御定全唐詩/json/639.json','["高塔六街無不見，塔邊名出只吾師。", "嘗聞朝客多相□，記得□□數句詩。"]'),
('yuding-14','越中贈別','張喬','唐','御定全唐诗','yuding','','[]','東越相逢幾醉眠，滿樓明月鏡湖邊。',32,'御定全唐詩/json/639.json','["東越相逢幾醉眠，滿樓明月鏡湖邊。", "別離吟斷西陵渡，楊柳秋風兩岸蟬。"]'),
('yuding-15','寄清越上人','張喬','唐','御定全唐诗','yuding','','[]','大道本來無所染，白雲那得有心期。',32,'御定全唐詩/json/639.json','["大道本來無所染，白雲那得有心期。", "遠公獨刻蓮花漏，猶向空山禮六時。"]'),
('yuding-16','宿齊山僧舍','張喬','唐','御定全唐诗','yuding','','[]','一宿經窗臥白波，萬重歸夢隔煙蘿。',32,'御定全唐詩/json/639.json','["一宿經窗臥白波，萬重歸夢隔煙蘿。", "若言不得南宗要，長在禪床事更多。"]'),
('yuding-17','春日游曲江','張喬','唐','御定全唐诗','yuding','','[]','日暖鴛鴦拍浪春，蒹葭浦際聚青蘋。若論來往鄉心切，須是煙波島上人。',32,'御定全唐詩/json/639.json','["日暖鴛鴦拍浪春，蒹葭浦際聚青蘋。若論來往鄉心切，須是煙波島上人。"]'),
('yuding-18','漁家','張喬','唐','御定全唐诗','yuding','','[]','擁棹思悠悠，更深泛積流。唯將一星火，何處宿蘆洲。',24,'御定全唐詩/json/639.json','["擁棹思悠悠，更深泛積流。唯將一星火，何處宿蘆洲。"]'),
('yuding-19','送人及第歸海東','張喬','唐','御定全唐诗','yuding','','[]','東風日邊起，草木一時春。自笑中華路，年年送遠人。',24,'御定全唐詩/json/639.json','["東風日邊起，草木一時春。自笑中華路，年年送遠人。"]'),
('yuding-20','題河中鸛雀樓','張喬','唐','御定全唐诗','yuding','','[]','高樓懷古動悲歌，鸛雀今無野燕過。樹隔五陵秋色早，',40,'御定全唐詩/json/639.json','["高樓懷古動悲歌，鸛雀今無野燕過。樹隔五陵秋色早，", "十載重來值搖落，天涯歸計欲如何。"]'),
('yuding-21','宿洛都門','張喬','唐','御定全唐诗','yuding','','[]','山川馬上度邊禽，一宿都門永夜吟。',32,'御定全唐詩/json/639.json','["山川馬上度邊禽，一宿都門永夜吟。", "客路不歸秋又晚，西風吹動洛陽砧。"]'),
('yuding-22','對月二首','張喬','唐','御定全唐诗','yuding','','[]','圓魄上寒空，皆言四海同。安知千裏外，不有雨兼風。',48,'御定全唐詩/json/639.json','["圓魄上寒空，皆言四海同。安知千裏外，不有雨兼風。", "盈缺青冥外，東風萬古吹。何人種丹桂，不長出輪枝。"]'),
('yuding-23','贈友人','張喬','唐','御定全唐诗','yuding','','[]','自說安貧歸未得，竹邊門掩小池冰。典琴賒酒吟過寺，',40,'御定全唐詩/json/639.json','["自說安貧歸未得，竹邊門掩小池冰。典琴賒酒吟過寺，", "幾時獻了相如賦，共向嵩山采茯苓。"]'),
('yuding-24','笛','張喬','唐','御定全唐诗','yuding','','[]','剪雨裁煙一節秋，落梅楊柳曲中愁。',32,'御定全唐詩/json/639.json','["剪雨裁煙一節秋，落梅楊柳曲中愁。", "尊前暫借殷勤看，明日曾聞向隴頭。"]'),
('yuding-25','漁者','張喬','唐','御定全唐诗','yuding','','[]','首戴圓荷發不梳，葉舟為宅水為居。',32,'御定全唐詩/json/639.json','["首戴圓荷發不梳，葉舟為宅水為居。", "沙頭聚看人如市，釣得澄江一丈魚。"]'),
('yuding-26','宿潺湲亭','張喬','唐','御定全唐诗','yuding','','[]','走月流煙疊樹西，聽來愁甚聽猿啼。',32,'御定全唐詩/json/639.json','["走月流煙疊樹西，聽來愁甚聽猿啼。", "幾時禦水聲邊住，卻夢潺湲宿此溪。"]'),
('yuding-27','台城','張喬','唐','御定全唐诗','yuding','','[]','宮殿餘基長草花，景陽宮樹噪村鴉。',32,'御定全唐詩/json/639.json','["宮殿餘基長草花，景陽宮樹噪村鴉。", "雲屯雉堞依然在，空繞漁樵四五家。"]'),
('yuding-28','寄山僧','張喬','唐','御定全唐诗','yuding','','[]','閑倚蒲團向日眠，不能歸老岳雲邊。',32,'御定全唐詩/json/639.json','["閑倚蒲團向日眠，不能歸老岳雲邊。", "舊時僧侶無人在，惟有長松見少年。"]'),
('yuding-29','題上元許棠所任王昌齡廳','張喬','唐','御定全唐诗','yuding','','[]','琉璃堂裏當時客，久絕吟聲繼後塵。',32,'御定全唐詩/json/639.json','["琉璃堂裏當時客，久絕吟聲繼後塵。", "百四十年庭樹老，如今重得見詩人。"]'),
('yuding-30','自誚','張喬','唐','御定全唐诗','yuding','','[]','每到花時恨道窮，一生光景半成空。',32,'御定全唐詩/json/639.json','["每到花時恨道窮，一生光景半成空。", "只應抱璞非良玉，豈得年年不至公。"]'),
('yuding-31','贈河南詩友','張喬','唐','御定全唐诗','yuding','','[]','山東令族玉無塵，裁剪煙花筆下春。',32,'御定全唐詩/json/639.json','["山東令族玉無塵，裁剪煙花筆下春。", "不把瑤華借風月，洛陽才子更何人。"]'),
('yuding-32','寄維揚故人','張喬','唐','御定全唐诗','yuding','','[]','離別河邊綰柳條，千山萬水玉人遙。',32,'御定全唐詩/json/639.json','["離別河邊綰柳條，千山萬水玉人遙。", "月明記得相尋處，城鎖東風十五橋。"]'),
('yuding-33','孤雲','張喬','唐','御定全唐诗','yuding','','[]','舒卷因風何所之，碧天孤影勢遲遲。',32,'御定全唐詩/json/639.json','["舒卷因風何所之，碧天孤影勢遲遲。", "莫言長是無心物，還有隨龍作雨時。"]'),
('yuding-34','詠棋子贈弈僧','張喬','唐','御定全唐诗','yuding','','[]','黑白誰能用入玄，千回生死體方圓。',32,'御定全唐詩/json/639.json','["黑白誰能用入玄，千回生死體方圓。", "空門說得恒沙劫，應笑終年為一先。"]'),
('yuding-35','穀口作','張喬','唐','御定全唐诗','yuding','','[]','巴客青冥過嶺塵，雪崖交映一川春。',32,'御定全唐詩/json/639.json','["巴客青冥過嶺塵，雪崖交映一川春。", "晴朝采藥尋源去，必恐雲深見異人。"]'),
('yuding-36','寄弟','張喬','唐','御定全唐诗','yuding','','[]','故里行人戰後疏，青崖萍寄白雲居。',32,'御定全唐詩/json/639.json','["故里行人戰後疏，青崖萍寄白雲居。", "那堪又是傷春日，把得長安落第書。"]'),
('yuding-37','春日有懷','張喬','唐','御定全唐诗','yuding','','[]','高下尋花春景遲，汾陽台榭白雲詩。',32,'御定全唐詩/json/639.json','["高下尋花春景遲，汾陽台榭白雲詩。", "看山懷古翻惆悵，未勝遙傳不到時。"]'),
('yuding-38','鷺鷥障子','張喬','唐','御定全唐诗','yuding','','[]','剪得機中如雪素，畫為江上帶絲禽。',32,'御定全唐詩/json/639.json','["剪得機中如雪素，畫為江上帶絲禽。", "閑來相對茅堂下，引出煙波萬里心。"]'),
('yuding-39','甘露寺僧房','張喬','唐','御定全唐诗','yuding','','[]','臨水登山路，重尋旅思勞。竹陰行處密，僧臘別來高。',48,'御定全唐詩/json/639.json','["臨水登山路，重尋旅思勞。竹陰行處密，僧臘別來高。", "遠岫明寒火，危樓響夜濤。悲秋不成寐，明月上千舠。"]'),
('yuding-40','宿江叟島居','張喬','唐','御定全唐诗','yuding','','[]','一家煙島隈，竹裏夜窗開。數派分潮去，千檣聚月來。',48,'御定全唐詩/json/639.json','["一家煙島隈，竹裏夜窗開。數派分潮去，千檣聚月來。", "石樓雲斷續，澗渚雁徘徊。了得平生志，還歸築釣台。"]'),
('yuding-41','江村','張喬','唐','御定全唐诗','yuding','','[]','貧遊無定蹤，鄉信轉難逢。寒渚暮煙闊，去帆歸思重。',48,'御定全唐詩/json/639.json','["貧遊無定蹤，鄉信轉難逢。寒渚暮煙闊，去帆歸思重。", "潮平低戌火，木落遠山鐘。況是漁家宿，疏籬響夜舂。"]'),
('yuding-42','贈進士顧雲','張喬','唐','御定全唐诗','yuding','','[]','潮檻煙波別釣津，西京同□荻□貧。不知守道歸何日，',40,'御定全唐詩/json/639.json','["潮檻煙波別釣津，西京同□荻□貧。不知守道歸何日，", "與君愁寂無消處，賒酒青門送楚人。"]'),
('yuding-43','贈頭陀僧','張喬','唐','御定全唐诗','yuding','','[]','自說年深別石橋，遍遊靈跡熟南朝。已知世路皆虛幻，',40,'御定全唐詩/json/639.json','["自說年深別石橋，遍遊靈跡熟南朝。已知世路皆虛幻，", "如今竹院藏衰老，一點寒燈弟子燒。"]'),
('yuding-44','尋陽村舍','張喬','唐','御定全唐诗','yuding','','[]','荒林寄遠居，坐臥見樵漁。夜火隨船遠，寒更出郡疏。',48,'御定全唐詩/json/639.json','["荒林寄遠居，坐臥見樵漁。夜火隨船遠，寒更出郡疏。", "雪迷登岳路，風阻轉江書。寂寞高窗下，思鄉歲欲除。"]'),
('yuding-45','江樓作','張喬','唐','御定全唐诗','yuding','','[]','憑檻見天涯，非秋亦可悲。晚天帆去疾，春雪燕來遲。',48,'御定全唐詩/json/639.json','["憑檻見天涯，非秋亦可悲。晚天帆去疾，春雪燕來遲。", "山水分鄉縣，干戈足別離。南人廢耕織，早晚罷王師。"]'),
('yuding-46','回鸞閣寫望','張喬','唐','御定全唐诗','yuding','','[]','古閣上空半，寥寥千里心。多年為客路，盡日倚欄吟。',48,'御定全唐詩/json/639.json','["古閣上空半，寥寥千里心。多年為客路，盡日倚欄吟。", "山壓秦川重，河來虜塞深。回鑾今不見，煙霧杳沉沉。"]'),
('yuding-47','題宣州開元寺','張喬','唐','御定全唐诗','yuding','','[]','誰家煙徑長莓苔，金碧虛欄竹上開。流水遠分山色斷，',40,'御定全唐詩/json/639.json','["誰家煙徑長莓苔，金碧虛欄竹上開。流水遠分山色斷，", "達理始應盡惆悵，僧閑應得話天臺。"]'),
('yuding-48','題友人草堂','張喬','唐','御定全唐诗','yuding','','[]','空山卜隱初，生計亦無餘。三畝水邊竹，一床琴畔書。',48,'御定全唐詩/json/639.json','["空山卜隱初，生計亦無餘。三畝水邊竹，一床琴畔書。", "深林收晚果，絕頂拾秋蔬。堅話長如此，何年獻子虛。"]'),
('yuding-49','七松亭','張喬','唐','御定全唐诗','yuding','','[]','七松亭上望秦川，高鳥閑雲滿目前。已比子真耕穀口，',40,'御定全唐詩/json/639.json','["七松亭上望秦川，高鳥閑雲滿目前。已比子真耕穀口，", "明月影中宮漏近，佩聲應宿使朝天。"]'),
('yuding-50','題友人林齋','張喬','唐','御定全唐诗','yuding','','[]','喬木帶涼蟬，來吟暑雨天。不離高枕上，似宿遠山邊。',48,'御定全唐詩/json/639.json','["喬木帶涼蟬，來吟暑雨天。不離高枕上，似宿遠山邊。", "簟冷窗中月，茶香竹裏泉。吾廬近溪島，憶別動經年。"]'),
('yuding-51','經宣城元員外山居','張喬','唐','御定全唐诗','yuding','','[]','無人襲仙隱，石室閉空山。避燒猿猶到，隨雲鶴不還。',48,'御定全唐詩/json/639.json','["無人襲仙隱，石室閉空山。避燒猿猶到，隨雲鶴不還。", "澗荒岩影在，橋斷樹陰閑。但有黃河賦，長留在世間。"]'),
('yuding-52','經九華山費征君故居','張喬','唐','御定全唐诗','yuding','','[]','草堂蕪沒後，來往問樵翁。斷石荒林外，孤墳晚照中。',48,'御定全唐詩/json/639.json','["草堂蕪沒後，來往問樵翁。斷石荒林外，孤墳晚照中。", "數溪分大野，九子立寒空。煙壁曾行處，青雲路不通。"]'),
('yuding-53','題賈島吟詩台','張喬','唐','御定全唐诗','yuding','','[]','吟魂不復遊，台亦似荒丘。一徑草中出，長江天外流。',48,'御定全唐詩/json/639.json','["吟魂不復遊，台亦似荒丘。一徑草中出，長江天外流。", "暝煙寒鳥集，殘月夜蟲愁。願得生禾黍，鋤平恨即休。"]'),
('yuding-54','游南嶽','張喬','唐','御定全唐诗','yuding','','[]','入岩仙境清，行盡複重行。若得閒無事，長來寄此生。',48,'御定全唐詩/json/639.json','["入岩仙境清，行盡複重行。若得閒無事，長來寄此生。", "澗松閑易老，籠燭晚生明。一宿泉聲裏，思鄉夢不成。"]'),
('yuding-55','尋桃源','張喬','唐','御定全唐诗','yuding','','[]','武林春草齊，花影隔澄溪。路遠無人去，山空有鳥啼。',48,'御定全唐詩/json/639.json','["武林春草齊，花影隔澄溪。路遠無人去，山空有鳥啼。", "水垂青靄斷，松偃綠蘿低。世上迷途客，經茲盡不迷。"]'),
('yuding-56','青鳥泉','張喬','唐','御定全唐诗','yuding','','[]','只此沉仙翼，瑤池似不遙。有聲懸翠壁，無勢下丹霄。',48,'御定全唐詩/json/639.json','["只此沉仙翼，瑤池似不遙。有聲懸翠壁，無勢下丹霄。", "淨瀨煙霞古，寒原草木凋。山河幾更變，幽咽到唐朝。"]'),
('yuding-57','望巫山','張喬','唐','御定全唐诗','yuding','','[]','溪疊雲深轉谷遲，暝投孤店草蟲悲。愁連遠水波濤夜，',40,'御定全唐詩/json/639.json','["溪疊雲深轉谷遲，暝投孤店草蟲悲。愁連遠水波濤夜，", "東歸未必勝羈旅，況是東歸未有期。"]'),
('yuding-58','省中偶作','張喬','唐','御定全唐诗','yuding','','[]','二轉郎曹自勉旃，莎階吟步想前賢。不如何遜無佳句，',40,'御定全唐詩/json/639.json','["二轉郎曹自勉旃，莎階吟步想前賢。不如何遜無佳句，", "乳毛松雪春來好，直夜清閒且學禪。"]'),
('yuding-59','秋夕','張喬','唐','御定全唐诗','yuding','','[]','春恨複秋悲，秋悲難到時。每逢明月夜，長起故山思。',48,'御定全唐詩/json/639.json','["春恨複秋悲，秋悲難到時。每逢明月夜，長起故山思。", "巷僻行吟遠，蛩多獨臥遲。溪僧與樵客，動別十年期。"]'),
('yuding-60','山中冬夜','張喬','唐','御定全唐诗','yuding','','[]','寒葉風搖盡，空林鳥宿稀。澗冰妨鹿飲，山雪阻僧歸。',48,'御定全唐詩/json/639.json','["寒葉風搖盡，空林鳥宿稀。澗冰妨鹿飲，山雪阻僧歸。", "夜坐塵心定，長吟語力微。人間去多事，何處夢柴扉。"]'),
('yuding-61','宿劉溫書齋','張喬','唐','御定全唐诗','yuding','','[]','不掩盈窗月，天然格調高。涼風移蟋蟀，落葉在離騷。',48,'御定全唐詩/json/639.json','["不掩盈窗月，天然格調高。涼風移蟋蟀，落葉在離騷。", "回筆挑燈燼，懸圖見海濤。因論三國志，空載幾英豪。"]'),
('yuding-62','歸舊山','張喬','唐','御定全唐诗','yuding','','[]','昔年山下結茅茨，村落重來野徑移。樵客相逢悲往事，',40,'御定全唐詩/json/639.json','["昔年山下結茅茨，村落重來野徑移。樵客相逢悲往事，", "此景一拋吟欲老，可能文字聖朝知。"]'),
('yuding-63','潭上作','張喬','唐','御定全唐诗','yuding','','[]','竹島殘陽映翠微，雪翎禽過碧潭飛。',32,'御定全唐詩/json/639.json','["竹島殘陽映翠微，雪翎禽過碧潭飛。", "人間未有關身事，每到漁家不欲歸。"]'),
('yuding-64','楊花落','張喬','唐','御定全唐诗','yuding','','[]','北斗南回春物老，紅英落盡綠尚早。韶風澹蕩無所依，',64,'御定全唐詩/json/639.json','["北斗南回春物老，紅英落盡綠尚早。韶風澹蕩無所依，", "人家女兒出羅幕，淨掃玉除看花落。寶環纖手捧更飛，", "東園桃李芳已歇，猶有楊花嬌暮春。"]'),
('yuding-65','九華樓晴望','張喬','唐','御定全唐诗','yuding','','[]','一夜江潭風雨後，九華晴望倚天秋。',32,'御定全唐詩/json/639.json','["一夜江潭風雨後，九華晴望倚天秋。", "重來此地知何日，欲別殷勤更上樓。"]'),
('yuding-66','終南山','張喬','唐','御定全唐诗','yuding','','[]','帶雪複銜春，橫天占半秦。勢奇看不定，景變寫難真。',48,'御定全唐詩/json/639.json','["帶雪複銜春，橫天占半秦。勢奇看不定，景變寫難真。", "洞遠皆通嶽，川多更有神。白雲幽絕處，自古屬樵人。"]'),
('yuding-67','哭陳陶','張喬','唐','御定全唐诗','yuding','','[]','先生抱衰疾，不起茂陵間。夕臨諸孤少，荒居吊客還。',72,'御定全唐詩/json/639.json','["先生抱衰疾，不起茂陵間。夕臨諸孤少，荒居吊客還。", "遺文禪東嶽，留語葬鄉山。多雨銘旌故，殘燈素帳閑。", "樂章誰與集，隴樹即堪攀。神理今難問，予將叫帝關。"]'),
('yuding-68','長門怨','張喬','唐','御定全唐诗','yuding','','[]','禦泉長繞鳳凰樓，自是恩波別處流。',32,'御定全唐詩/json/639.json','["禦泉長繞鳳凰樓，自是恩波別處流。", "閑揲舞衣歸未得，夜來砧杵六宮秋。"]'),
('yuding-0','升平詞五首','曹唐','唐','御定全唐诗','yuding','','[]','瑞氣繞宮樓，皇居上苑遊。遠岡連聖祚，平地載神州。',240,'御定全唐詩/json/640.json','["瑞氣繞宮樓，皇居上苑遊。遠岡連聖祚，平地載神州。", "會合兼重譯，潺湲近八流。中興豈假問，據此自千秋。", "寥泬敞延英，朝班立位橫。宣傳無草動，拜舞有衣聲。", "鴛瓦霜消濕，蟲絲日照明。辛勤自不到，遙見似前程。", "處處是歡心，時康歲已深。不同三尺劍，應似五弦琴。", "壽笑山猶盡，明嫌日有陰。何當憐一物，亦遣斷愁吟。", "日日聽歌謠，區中盡祝堯。蟲蝗初不害，夷狄近全銷。", "史筆唯書瑞，天臺絕見妖。因令匹夫志，轉欲事清朝。", "五帝三皇主，蕭曹魏邴臣。文章唯返朴，戈甲盡生塵。", "諫紙應無用，朝綱自有倫。升平不可記，所見是閒人。"]'),
('yuding-1','洛東蘭若歸','曹唐','唐','御定全唐诗','yuding','','[]','一衲老禪床，吾生半異鄉。管弦愁裏老，書劍夢中忙。',48,'御定全唐詩/json/640.json','["一衲老禪床，吾生半異鄉。管弦愁裏老，書劍夢中忙。", "鳥急山初暝，蟬稀樹正涼。又歸何處去，塵路月蒼蒼。"]'),
('yuding-2','仙都即景','曹唐','唐','御定全唐诗','yuding','','[]','黃帝登真處，青青不記年。孤峰應礙日，一柱自擎天。',48,'御定全唐詩/json/640.json','["黃帝登真處，青青不記年。孤峰應礙日，一柱自擎天。", "石怪長棲鶴，雲閑若有仙。鼎湖看不見，零落數枝蓮。"]'),
('yuding-3','漢武帝將候西王母下降','曹唐','唐','御定全唐诗','yuding','','[]','昆侖凝想最高峰，王母來乘五色龍。歌聽紫鸞猶縹緲，',40,'御定全唐詩/json/640.json','["昆侖凝想最高峰，王母來乘五色龍。歌聽紫鸞猶縹緲，", "樹影悠悠花悄悄，若聞簫管是行蹤。"]'),
('yuding-4','漢武帝于宮中宴西王母','曹唐','唐','御定全唐诗','yuding','','[]','鼇岫雲低太一壇，武皇齋潔不勝歡。長生碧字期親署，',40,'御定全唐詩/json/640.json','["鼇岫雲低太一壇，武皇齋潔不勝歡。長生碧字期親署，", "秋風嫋嫋月朗朗，玉女清歌一夜闌。"]'),
('yuding-5','劉晨阮肇游天臺','曹唐','唐','御定全唐诗','yuding','','[]','樹入天臺石路新，雲和草靜迥無塵。煙霞不省生前事，',40,'御定全唐詩/json/640.json','["樹入天臺石路新，雲和草靜迥無塵。煙霞不省生前事，", "不知此地歸何處，須就桃源問主人。"]'),
('yuding-6','劉阮洞中遇仙子','曹唐','唐','御定全唐诗','yuding','','[]','天和樹色靄蒼蒼，霞重嵐深路渺茫。雲實滿山無鳥雀，',40,'御定全唐詩/json/640.json','["天和樹色靄蒼蒼，霞重嵐深路渺茫。雲實滿山無鳥雀，", "願得花間有人出，免令仙犬吠劉郎。"]'),
('yuding-7','仙子送劉阮出洞','曹唐','唐','御定全唐诗','yuding','','[]','殷勤相送出天臺，仙境那能卻再來。雲液每歸須強飲，',40,'御定全唐詩/json/640.json','["殷勤相送出天臺，仙境那能卻再來。雲液每歸須強飲，", "惆悵溪頭從此別，碧山明月閉蒼苔。"]'),
('yuding-8','仙子洞中有懷劉阮','曹唐','唐','御定全唐诗','yuding','','[]','不將清瑟理霓裳，塵夢那知鶴夢長。洞裏有天春寂寂，',40,'御定全唐詩/json/640.json','["不將清瑟理霓裳，塵夢那知鶴夢長。洞裏有天春寂寂，", "曉露風燈零落盡，此生無處訪劉郎。"]'),
('yuding-9','劉阮再到天臺不復見仙子','曹唐','唐','御定全唐诗','yuding','','[]','再到天臺訪玉真，青苔白石已成塵。笙歌冥寞閑深洞，',40,'御定全唐詩/json/640.json','["再到天臺訪玉真，青苔白石已成塵。笙歌冥寞閑深洞，", "桃花流水依然在，不見當時勸酒人。"]'),
('yuding-10','織女懷牽牛','曹唐','唐','御定全唐诗','yuding','','[]','北斗佳人雙淚流，眼穿腸斷為牽牛。封題錦字凝新恨，',40,'御定全唐詩/json/640.json','["北斗佳人雙淚流，眼穿腸斷為牽牛。封題錦字凝新恨，", "欲將心向仙郎說，借問榆花早晚秋。"]'),
('yuding-11','王遠宴麻姑蔡經宅','曹唐','唐','御定全唐诗','yuding','','[]','好風吹樹杏花香，花下真人道姓王。大篆龍蛇隨筆劄，',40,'御定全唐詩/json/640.json','["好風吹樹杏花香，花下真人道姓王。大篆龍蛇隨筆劄，", "要喚麻姑同一醉，使人沽酒向餘杭。"]'),
('yuding-12','萼綠華將歸九疑留別許真人','曹唐','唐','御定全唐诗','yuding','','[]','九點秋煙黛色空，綠華歸思頗無窮。每悲馭鶴身難任，',40,'御定全唐詩/json/640.json','["九點秋煙黛色空，綠華歸思頗無窮。每悲馭鶴身難任，", "藍絲重勒金條脫，留與人間許侍中。"]'),
('yuding-13','穆王宴王母於九光流霞館','曹唐','唐','御定全唐诗','yuding','','[]','桑葉扶疏閉日華，穆王邀命宴流霞。霓旌著地雲初駐，',40,'御定全唐詩/json/640.json','["桑葉扶疏閉日華，穆王邀命宴流霞。霓旌著地雲初駐，", "不知白馬紅韁解，偷吃東田碧玉花。"]'),
('yuding-14','紫河張休真','曹唐','唐','御定全唐诗','yuding','','[]','琪樹扶疏壓瑞煙，玉皇朝客滿花前。山川到處成三月，',40,'御定全唐詩/json/640.json','["琪樹扶疏壓瑞煙，玉皇朝客滿花前。山川到處成三月，", "東風小飲人皆醉，從聽黃龍枕水眠。"]'),
('yuding-15','張碩重寄杜蘭香','曹唐','唐','御定全唐诗','yuding','','[]','碧落香銷蘭露秋，星河無夢夜悠悠。靈妃不降三清駕，',40,'御定全唐詩/json/640.json','["碧落香銷蘭露秋，星河無夢夜悠悠。靈妃不降三清駕，", "人間何事堪惆悵，海色西風十二樓。"]'),
('yuding-16','玉女杜蘭香下嫁于張碩','曹唐','唐','御定全唐诗','yuding','','[]','天上人間兩渺茫，不知誰識杜蘭香。來經玉樹三山遠，',40,'御定全唐詩/json/640.json','["天上人間兩渺茫，不知誰識杜蘭香。來經玉樹三山遠，", "遺情更說何珍重，擘破雲鬟金鳳凰。"]'),
('yuding-17','蕭史攜弄玉上升','曹唐','唐','御定全唐诗','yuding','','[]','豈是丹台歸路遙，紫鸞煙駕不同飄。一聲洛水傳幽咽，',40,'御定全唐詩/json/640.json','["豈是丹台歸路遙，紫鸞煙駕不同飄。一聲洛水傳幽咽，", "緱山碧樹青樓月，腸斷春風為玉簫。"]'),
('yuding-18','皇初平將入金華山','曹唐','唐','御定全唐诗','yuding','','[]','莫道真游煙景賒，瀟湘有路入京華。溪頭鶴樹春常在，',40,'御定全唐詩/json/640.json','["莫道真游煙景賒，瀟湘有路入京華。溪頭鶴樹春常在，", "白羊成隊難收拾，吃盡溪邊巨勝花。"]'),
('yuding-19','漢武帝思李夫人','曹唐','唐','御定全唐诗','yuding','','[]','惆悵冰顏不復歸，晚秋黃葉滿天飛。迎風細荇傳香粉，',40,'御定全唐詩/json/640.json','["惆悵冰顏不復歸，晚秋黃葉滿天飛。迎風細荇傳香粉，", "夜深池上蘭橈歇，斷續歌聲徹太微。"]'),
('yuding-20','送羽人王錫歸羅浮','曹唐','唐','御定全唐诗','yuding','','[]','風前整頓紫荷巾，常向羅浮保養神。石磴倚天行帶月，',40,'御定全唐詩/json/640.json','["風前整頓紫荷巾，常向羅浮保養神。石磴倚天行帶月，", "最愛葛洪尋藥處，露苗煙蕊滿山春。"]'),
('yuding-21','送劉尊師祗詔闕庭三首','曹唐','唐','御定全唐诗','yuding','','[]','海風葉葉駕霓旌，天路悠悠接上清。錦誥淒涼遺去恨，',120,'御定全唐詩/json/640.json','["海風葉葉駕霓旌，天路悠悠接上清。錦誥淒涼遺去恨，", "從此暫辭華表柱，便應千載是歸程。", "五峰已別隔人間，雙闕何年許再還。既掃山川收地脈，", "從此枕中唯有夢，夢魂何處訪三山。", "仙老閑眠碧草堂，帝書征入白雲鄉。龜台欲署長生籍，", "五千言外無文字，更有何詞贈武皇。"]'),
('yuding-22','三年冬大禮五首','曹唐','唐','御定全唐诗','yuding','','[]','皇帝齋心潔素誠，自朝真祖報升平。華山秋草多歸馬，',200,'御定全唐詩/json/640.json','["皇帝齋心潔素誠，自朝真祖報升平。華山秋草多歸馬，", "千官整肅三天夜，劍佩初聞入太清。", "海日西飛度禁林，太清宮殿月沉沉。不聞北斗傾堯酒，", "雪風更起古杉葉，時送步虛清磬音。", "太一天壇降紫君，屬車龍鶴夜成群。春浮玉藻寒初落，", "千官不動旌旗下，日照南山萬樹雲。", "山擁飛雲海水清，天壇未夕仗先成。千官不起金縢議，", "側聞左右皆周呂，看取從容致太平。", "太和琴暖發南熏，水闊風高得細聞。滄海舉歌夔是相，", "今日病身慚小隱，欲將泉石勒移文。"]'),
('yuding-23','暮春戲贈吳端公','曹唐','唐','御定全唐诗','yuding','','[]','年少英雄好丈夫，大家望拜執金吾。閑眠曉日聽鶗鴂，',40,'御定全唐詩/json/640.json','["年少英雄好丈夫，大家望拜執金吾。閑眠曉日聽鶗鴂，", "牡丹花下簾鉤外，獨憑紅肌捋虎鬚。"]'),
('yuding-24','奉送嚴大夫再領容府二首','曹唐','唐','御定全唐诗','yuding','','[]','海風卷樹凍嵐消，憂國寧辭嶺外遙。自顧勤勞甘百戰，',80,'御定全唐詩/json/640.json','["海風卷樹凍嵐消，憂國寧辭嶺外遙。自顧勤勞甘百戰，", "代北天南盡成事，肯將心許霍嫖姚。", "日照雙旌射火山，笑迎賓從卻南還。風雲暗發談諧外，", "無因得靸真珠履，親從新侯定八蠻。"]'),
('yuding-25','贈南嶽馮處士二首','曹唐','唐','御定全唐诗','yuding','','[]','白石溪邊自結廬，風泉滿院稱幽居。鳥啼深樹劚靈藥，',80,'御定全唐詩/json/640.json','["白石溪邊自結廬，風泉滿院稱幽居。鳥啼深樹劚靈藥，", "支頤冷笑緣名出，終日王門強曳裾。", "寂寥深木閉煙霞，洞裏相知有幾家。笑看潭魚吹水沫，", "夜靜著灰封釜灶，自添文武養丹砂。"]'),
('yuding-26','題子侄書院雙松','曹唐','唐','御定全唐诗','yuding','','[]','自種雙松費幾錢，頓令院落似秋天。能藏此地新晴雨，',40,'御定全唐詩/json/640.json','["自種雙松費幾錢，頓令院落似秋天。能藏此地新晴雨，", "莫教取次成閑夢，使汝悠悠十八年。"]'),
('yuding-27','羽林賈中丞','曹唐','唐','御定全唐诗','yuding','','[]','四十年前百戰身，曾驅虎隊掃胡塵。風悲鼓角榆關暮，',40,'御定全唐詩/json/640.json','["四十年前百戰身，曾驅虎隊掃胡塵。風悲鼓角榆關暮，", "胸中別有安邊計，誰睬髭須白似銀。"]'),
('yuding-28','送康祭酒赴輪台','曹唐','唐','御定全唐诗','yuding','','[]','灞水橋邊酒一杯，送君千里赴輪台。霜粘海眼旗聲凍，',40,'御定全唐詩/json/640.json','["灞水橋邊酒一杯，送君千里赴輪台。霜粘海眼旗聲凍，", "分明會得將軍意，不斬樓蘭不擬回。"]'),
('yuding-29','南游','曹唐','唐','御定全唐诗','yuding','','[]','盡興南遊卒未回，水工舟子不須催。政思碧樹關心句，',40,'御定全唐詩/json/640.json','["盡興南遊卒未回，水工舟子不須催。政思碧樹關心句，", "蘆花寂寂月如練，何處笛聲江上來。"]'),
('yuding-30','哭陷邊許兵馬使','曹唐','唐','御定全唐诗','yuding','','[]','北風裂地黯邊霜，戰敗桑幹日色黃。故國暗回殘士卒，',40,'御定全唐詩/json/640.json','["北風裂地黯邊霜，戰敗桑幹日色黃。故國暗回殘士卒，", "除卻陰符與兵法，更無一物在儀床。"]'),
('yuding-31','和周侍禦買劍','曹唐','唐','御定全唐诗','yuding','','[]','將軍溢價買吳鉤，要與中原靜寇仇。試掛窗前驚電轉，',40,'御定全唐詩/json/640.json','["將軍溢價買吳鉤，要與中原靜寇仇。試掛窗前驚電轉，", "見說夜深星斗畔，等閒期克月支頭。"]'),
('yuding-32','病馬五首呈鄭校書章三吳十五先輩','曹唐','唐','御定全唐诗','yuding','','[]','騄耳何年別渥窪，病來顏色半泥沙。四啼不鑿金砧裂，',200,'御定全唐詩/json/640.json','["騄耳何年別渥窪，病來顏色半泥沙。四啼不鑿金砧裂，", "平原好放無人放，嘶向秋風苜蓿花。", "隴上沙蔥葉正齊，騰黃猶自局羸啼。尾蟠夜雨紅絲脆，", "階前莫怪垂雙淚，不遇孫陽不敢嘶。", "不剪焦毛鬣半翻，何人別是古龍孫。霜侵病骨無驕氣，", "一朝千里心猶在，爭肯潛忘秣飼恩。", "空被秋風吹病毛，無因濯浪刷洪濤。臥來總怪龍蹄跙，", "欲將鬐鬣重裁剪，乞借新成利鉸刀。", "病久無人著意看，玉華衫色欲凋殘。飲驚白露泉花冷，", "王良若許相抬策，千里追風也不難。"]'),
('yuding-33','長安客舍敘邵陵舊宴，寄永州蕭使君五首','曹唐','唐','御定全唐诗','yuding','','[]','邵陵佳樹碧蔥蘢，河漢西沈宴未終。殘漏五更傳海月，',200,'御定全唐詩/json/640.json','["邵陵佳樹碧蔥蘢，河漢西沈宴未終。殘漏五更傳海月，", "今日卻懷行樂處，兩床絲竹水樓中。", "不知何路卻飛翻，虛受賢侯鄭重恩。五夜清歌敲玉樹，", "狼藉梨花滿城月，當時長醉信陵門。", "粉堞彤軒畫障西，水雲紅樹窣璿題。鷓鴣欲絕歌聲定，", "東風夜月三年飲，不省非時不似泥。", "木魚金鑰鎖春城，夜上紅樓縱酒情。竹葉水繁更漏促，", "星斗漸稀賓客散，碧雲猶戀豔歌聲。", "三年身逐漢諸侯，賓榻容居最上頭。飽聽笙歌陪痛飲，", "月滿前山圓不動，更邀詩客上高樓。"]'),
('yuding-34','勖劍','曹唐','唐','御定全唐诗','yuding','','[]','古物神光雪見羞，未能擎出恐泉流。暗臨黑水蛟螭泣，',40,'御定全唐詩/json/640.json','["古物神光雪見羞，未能擎出恐泉流。暗臨黑水蛟螭泣，", "垂情不用將閒氣，惱亂司空犯鬥牛。"]'),
('yuding-35','仙都即景','曹唐','唐','御定全唐诗','yuding','','[]','蟠桃花老華陽東，軒後登真謝六宮。旌節暗迎歸碧落，',40,'御定全唐詩/json/640.json','["蟠桃花老華陽東，軒後登真謝六宮。旌節暗迎歸碧落，", "看卻龍髯攀不得，紅霞零落鼎湖空。"]'),
('yuding-36','望九華寄池陽杜員外','曹唐','唐','御定全唐诗','yuding','','[]','戴月早辭三秀館，遲明初識九華峰。差差玉劍寒鋩利，',40,'御定全唐詩/json/640.json','["戴月早辭三秀館，遲明初識九華峰。差差玉劍寒鋩利，", "行春若到五溪上，此處褰帷正面逢。"]'),
('yuding-0','小遊仙詩九十八首','曹唐','唐','御定全唐诗','yuding','','[]','玉簫金瑟發商聲，桑葉枯乾海水清。',384,'御定全唐詩/json/641.json','["玉簫金瑟發商聲，桑葉枯乾海水清。", "淨掃蓬萊山下路，略邀王母話長生。", "上元元日豁明堂，五帝望空拜玉皇。", "萬樹琪花千圃藥，心知不敢輒形相。", "騎龍重過玉溪頭，紅葉還春碧水流。", "省得壺中見天地，壺中天地不曾秋。", "真王未許久從容，立在花前別甯封。", "手把玉簫頭不舉，自愁如醉倚黃龍。", "金殿無人鎖絳煙，玉郎並不賞丹田。", "白龍蹀躞難回跋，爭下紅綃碧玉鞭。", "玄洲草木不知黃，甲子初開浩劫長。", "無限萬年年少女，手攀紅樹滿殘陽。", "宮闕重重閉玉林，昆侖高辟彩雲深。", "黃龍掉尾引郎去，使妾月明何處尋。", "風滿塗山玉蕊稀，赤龍閑臥鶴東飛。", "紫梨爛盡無人吃，何事韓君去不歸。", "武帝徒勞厭暮年，不曾清淨不精專。", "上元少女絕還往，滿灶丹成白玉煙。", "百辟朝回閉玉除，露風清宴桂花疏。", "西歸使者騎金虎，嚲鞚垂鞭唱步虛。", "南斗闌珊北斗稀，茅君夜著紫霞衣。", "朝騎白鹿趁朝去，鳳押笙歌逐後飛。", "焚香獨自上天壇，桂樹風吹玉簡寒。", "長怕嵇康乏仙骨，與將仙籍再尋看。"]'),
('yuding-1','《又遊仙詩一絕','曹唐','唐','御定全唐诗','yuding','','[]','靖節先生幾代孫，青娥曾接玉郎魂。',32,'御定全唐詩/json/641.json','["靖節先生幾代孫，青娥曾接玉郎魂。", "春風流水還無賴，偷放桃花出洞門。"]'),
('yuding-2','題武陵洞五首','曹唐','唐','御定全唐诗','yuding','','[]','此生終使此身閑，不是春時且要還。',160,'御定全唐詩/json/641.json','["此生終使此身閑，不是春時且要還。", "寄語桃花與流水，莫辭相送到人間。", "溪口回舟日已昏，卻聽雞犬隔前村。", "殷勤重與秦人別，莫使桃花閉洞門。", "卻恐重來路不通，殷勤回首謝春風。", "白雞黃犬不將去，且寄桃花深洞中。", "桃花夾岸杳何之，花滿春山水去遲。", "三宿武陵溪上月，始知人世有秦時。", "渡水傍山尋絕壁，白雲飛處洞天開。", "仙人來往無行跡，石徑春風長綠苔。"]'),
('yuding-3','句','曹唐','唐','御定全唐诗','yuding','','[]','斬蛟青海上，射虎黑山頭。。',61,'御定全唐詩/json/641.json','["斬蛟青海上，射虎黑山頭。。", "簫聲欲盡月色苦，依舊漢家宮樹秋。", "一曲哀歌茂陵道，漢家天子葬秋風。", "誰知漢武無仙骨，滿灶黃金成白煙。"]'),
('yuding-0','聖政紀頌','來鵠','唐','御定全唐诗','yuding','','[]','三皇不書，五帝不紀。有聖有神，風銷日已。何教何師，',574,'御定全唐詩/json/642.json','["三皇不書，五帝不紀。有聖有神，風銷日已。何教何師，", "成天造地，不昏不圯。言得非排，文得聖齒。表表如見者，", "嗚呼！貞觀多籲，永徽多俞。廷日發論，殿日發謨。", "牙孽不作，鳥鼠不除。論出不蓋，謨行不紆。楹然史臣，", "不梏爾智，不息我愚。執言直注，史文直敷。", "故得粲粲朝典，落落廷謇。聖牘既多，堯風不淺。", "頌編坦軸，君出臣顯。若儼見旒，若俯見冕。無閑殿曠廷，", "暨乎後相圖身，天子專問。我獨以言，史不得近。", "丘明見嫌，倚相在擯。秉筆如今，隨班不進。班退史歸，", "炯哉時皇，言必成章。德宣五帝，道奧三皇。如何翌臣，", "垣私藩已，遠史廋唐。俾德音嘉訪，默縮暗亡。咽典噤法，", "謂乎殿空扆逸，朝懵廷荒。不知奸蔽，文失汪洋。", "有貞觀業，有永徽綱。亦匿匪見，亦寢匪彰。賴有後臣，", "乃具前欺，大陳不敬。曰逐史之喻，請以物並。", "且十夫樹楊，一夫欲競。栽既未牢，摒豈能盛！帝業似栽，", "不傳親問，不寫密諍。孰示來朝，以光神政。", "由是天呼震吸，征奔召急。史題筆來，叱廷而入。", "端耳抗目，不撝不挹。獬豸側頭，螭虯擺濕。握管絕怡，", "大何不顯，細何不明。語未絕緒，史已錄成。謂之何書，", "方之我後，錄裏書分。錄有君法，書有君文。君法君文，", "君劬臣勞，上討下述。惟勤惟明，在聖政紀出。至德何比，", "有道有謨，在聖政紀書。一體列秩，同力翼戴。祈福去邪，", "不偷不蓋，在聖政紀載。諒夫！總斯不朽，可懸魏闕。", "愚得是言，非訕非伐。實謂醫臣渾沌，開君日月。"]'),
('yuding-1','宛陵送李明府罷任歸江州','來鵠','唐','御定全唐诗','yuding','','[]','菊花村晚雁來天，共把離觴向水邊。官滿便尋垂釣侶，',40,'御定全唐詩/json/642.json','["菊花村晚雁來天，共把離觴向水邊。官滿便尋垂釣侶，", "倘見吾鄉舊知己，為言憔悴過年年。"]'),
('yuding-2','清明日與友人游玉粒塘莊','來鵠','唐','御定全唐诗','yuding','','[]','幾宿春山逐陸郎，清明時節好煙光。歸穿細荇船頭滑，',40,'御定全唐詩/json/642.json','["幾宿春山逐陸郎，清明時節好煙光。歸穿細荇船頭滑，", "不堪吟罷東回首，滿耳蛙聲正夕陽。"]'),
('yuding-3','寒食山館書情','來鵠','唐','御定全唐诗','yuding','','[]','獨把一杯山館中，每經時節恨飄蓬。侵階草色連朝雨，',40,'御定全唐詩/json/642.json','["獨把一杯山館中，每經時節恨飄蓬。侵階草色連朝雨，", "分明記得還家夢，徐孺宅前湖水東。"]'),
('yuding-4','病起','來鵠','唐','御定全唐诗','yuding','','[]','春初一臥到秋深，不見紅芳與綠陰。窗下展書難久讀，',40,'御定全唐詩/json/642.json','["春初一臥到秋深，不見紅芳與綠陰。窗下展書難久讀，", "在舍渾如遠鄉客，詩僧酒伴鎮相尋。"]'),
('yuding-5','鄂渚除夜書懷','來鵠','唐','御定全唐诗','yuding','','[]','鸚鵡洲頭夜泊船，此時形影共淒然。難歸故國干戈後，',40,'御定全唐詩/json/642.json','["鸚鵡洲頭夜泊船，此時形影共淒然。難歸故國干戈後，", "自嗟落魄無成事，明日春風又一年。"]'),
('yuding-6','鄂渚清明日與鄉友登頭陀山','來鵠','唐','御定全唐诗','yuding','','[]','冷酒一杯相勸頻，異鄉相遇轉相親。落花風裏數聲笛，',40,'御定全唐詩/json/642.json','["冷酒一杯相勸頻，異鄉相遇轉相親。落花風裏數聲笛，", "思量費子真仙子，不作頭陀山下塵。"]'),
('yuding-7','蠶婦','來鵠','唐','御定全唐诗','yuding','','[]','曉夕采桑多苦辛，好花時節不閑身。',32,'御定全唐詩/json/642.json','["曉夕采桑多苦辛，好花時節不閑身。", "若教解愛繁華事，凍殺黃金屋裏人。"]'),
('yuding-8','題廬山雙劍峰','來鵠','唐','御定全唐诗','yuding','','[]','倚天雙劍古今閑，三尺高於四面山。',32,'御定全唐詩/json/642.json','["倚天雙劍古今閑，三尺高於四面山。", "若使火雲燒得動，始應農器滿人間。"]'),
('yuding-9','雲','來鵠','唐','御定全唐诗','yuding','','[]','千形萬象竟還空，映水藏山片複重。',32,'御定全唐詩/json/642.json','["千形萬象竟還空，映水藏山片複重。", "無限旱苗枯欲盡，悠悠閑處作奇峰。"]'),
('yuding-10','金錢花','來鵠','唐','御定全唐诗','yuding','','[]','也無棱郭也無神，露洗還同鑄出新。',32,'御定全唐詩/json/642.json','["也無棱郭也無神，露洗還同鑄出新。", "青帝若教花裏用，牡丹應是得錢人。"]'),
('yuding-11','曉雞','來鵠','唐','御定全唐诗','yuding','','[]','黯黯嚴城罷鼓鼙，數聲相續出寒棲。',32,'御定全唐詩/json/642.json','["黯黯嚴城罷鼓鼙，數聲相續出寒棲。", "不嫌驚破紗窗夢，卻怕為妖半夜啼。"]'),
('yuding-12','山中避難作','來鵠','唐','御定全唐诗','yuding','','[]','山頭烽火水邊營，鬼哭人悲夜夜聲。',32,'御定全唐詩/json/642.json','["山頭烽火水邊營，鬼哭人悲夜夜聲。", "唯有碧天無一事，日還西下月還明。"]'),
('yuding-13','早春','來鵠','唐','御定全唐诗','yuding','','[]','新曆才將半紙開，小庭猶聚爆竿灰。',32,'御定全唐詩/json/642.json','["新曆才將半紙開，小庭猶聚爆竿灰。", "偏憎楊柳難鈐轄，又惹東風意緒來。"]'),
('yuding-14','鷺鷥','來鵠','唐','御定全唐诗','yuding','','[]','嫋絲翹足傍澄瀾，消盡年光佇思間。',32,'御定全唐詩/json/642.json','["嫋絲翹足傍澄瀾，消盡年光佇思間。", "若使見魚無羨意，向人姿態更應閑。"]'),
('yuding-15','子規','來鵠','唐','御定全唐诗','yuding','','[]','雨恨花愁同此冤，啼時聞處正春繁。',32,'御定全唐詩/json/642.json','["雨恨花愁同此冤，啼時聞處正春繁。", "千聲萬血誰哀爾，爭得如花笑不言。"]'),
('yuding-16','新安官舍閑坐','來鵠','唐','御定全唐诗','yuding','','[]','寂寞空階草亂生，簟涼風動若為情。',32,'御定全唐詩/json/642.json','["寂寞空階草亂生，簟涼風動若為情。", "不知獨坐閑多少，看得蜘蛛結網成。"]'),
('yuding-17','除夜','來鵠','唐','御定全唐诗','yuding','','[]','事關休戚已成空，萬里相思一夜中。',32,'御定全唐詩/json/642.json','["事關休戚已成空，萬里相思一夜中。", "愁到曉雞聲絕後，又將憔悴見春風。"]'),
('yuding-18','遊魚','來鵠','唐','御定全唐诗','yuding','','[]','弄萍隈荇思夷猶，掉尾揚鬐逐慢流。',32,'御定全唐詩/json/642.json','["弄萍隈荇思夷猶，掉尾揚鬐逐慢流。", "應怕碧岩岩下水，浮藤如線月如鉤。"]'),
('yuding-19','鸚鵡','來鵠','唐','御定全唐诗','yuding','','[]','色白還應及雪衣，嘴紅毛綠語仍奇。',32,'御定全唐詩/json/642.json','["色白還應及雪衣，嘴紅毛綠語仍奇。", "年年鎖在金籠裏，何似隴山閑處飛。"]'),
('yuding-20','偶題二首','來鵠','唐','御定全唐诗','yuding','','[]','近來靈鵲語何疏，獨憑欄幹恨有殊。',64,'御定全唐詩/json/642.json','["近來靈鵲語何疏，獨憑欄幹恨有殊。", "一夜綠荷霜剪破，賺他秋雨不成珠。", "水邊箕踞靜書空，欲解愁腸酒不濃。", "可惜青天好雷雹，只能驅趁懶蛟龍。"]'),
('yuding-21','惜花','來鵠','唐','御定全唐诗','yuding','','[]','東風漸急夕陽斜，一樹夭桃數日花。',32,'御定全唐詩/json/642.json','["東風漸急夕陽斜，一樹夭桃數日花。", "為惜紅芳今夜裏，不知和月落誰家。"]'),
('yuding-22','洞庭隱','來鵠','唐','御定全唐诗','yuding','','[]','高臥洞庭三十春，芰荷香裏獨垂綸。',32,'御定全唐詩/json/642.json','["高臥洞庭三十春，芰荷香裏獨垂綸。", "莫嫌無事閑銷日，有事始憐無事人。"]'),
('yuding-23','古劍池','來鵠','唐','御定全唐诗','yuding','','[]','秋水蓮花三四枝，我來慷慨步遲遲。',32,'御定全唐詩/json/642.json','["秋水蓮花三四枝，我來慷慨步遲遲。", "不決浮雲斬邪佞，直成龍去欲何為。"]'),
('yuding-24','梅花','來鵠','唐','御定全唐诗','yuding','','[]','枝枝倚檻照池冰，粉薄香殘恨不勝。',32,'御定全唐詩/json/642.json','["枝枝倚檻照池冰，粉薄香殘恨不勝。", "占得早芳何所利，與他霜雪助威棱。"]'),
('yuding-25','聞蟬','來鵠','唐','御定全唐诗','yuding','','[]','綠槐陰裏一聲新，霧薄風輕力未勻。',32,'御定全唐詩/json/642.json','["綠槐陰裏一聲新，霧薄風輕力未勻。", "莫道聞時總惆悵，有愁人有不愁人。"]'),
('yuding-26','賣花謠','來鵠','唐','御定全唐诗','yuding','','[]','紫豔紅苞價不同，匝街羅列起香風。',32,'御定全唐詩/json/642.json','["紫豔紅苞價不同，匝街羅列起香風。", "無言無語呈顏色，知落誰家池館中。"]'),
('yuding-27','子規','來鵠','唐','御定全唐诗','yuding','','[]','月落空山聞數聲，此時孤館酒初醒。',32,'御定全唐詩/json/642.json','["月落空山聞數聲，此時孤館酒初醒。", "投人語若似伊淚，口畔血流應始聽。"]'),
('yuding-28','句','來鵠','唐','御定全唐诗','yuding','','[]','回眸綠水波初起，合掌白蓮花未開。（觀懺會夫人，',23,'御定全唐詩/json/642.json','["回眸綠水波初起，合掌白蓮花未開。（觀懺會夫人，"]'),
('yuding-0','菊','李山甫','唐','御定全唐诗','yuding','','[]','籬下霜前偶得存，忍教遲晚避蘭蓀。也銷造化無多力，',40,'御定全唐詩/json/643.json','["籬下霜前偶得存，忍教遲晚避蘭蓀。也銷造化無多力，", "陶潛歿後誰知己，露滴幽叢見淚痕。"]'),
('yuding-1','風','李山甫','唐','御定全唐诗','yuding','','[]','喜怒寒暄直不勻，終無形狀始無因。能將塵土平欺客，',40,'御定全唐詩/json/643.json','["喜怒寒暄直不勻，終無形狀始無因。能將塵土平欺客，", "深知造化由君力，試為吹噓借與春。"]'),
('yuding-2','月','李山甫','唐','御定全唐诗','yuding','','[]','狡兔頑蟾死複生，度雲經漢澹還明。夜長雖耐對君坐，',40,'御定全唐詩/json/643.json','["狡兔頑蟾死複生，度雲經漢澹還明。夜長雖耐對君坐，", "人間半被虛拋擲，唯向孤吟客有情。"]'),
('yuding-3','秋','李山甫','唐','御定全唐诗','yuding','','[]','傍雨依風冷漸勻，更憑青女事精神。來時將得幾多雁，',40,'御定全唐詩/json/643.json','["傍雨依風冷漸勻，更憑青女事精神。來時將得幾多雁，", "鄒家不用偏吹律，到底榮枯也自均。"]'),
('yuding-4','松','李山甫','唐','御定全唐诗','yuding','','[]','地聳蒼龍勢抱雲，天教青共眾材分。孤標百尺雪中見，',40,'御定全唐詩/json/643.json','["地聳蒼龍勢抱雲，天教青共眾材分。孤標百尺雪中見，", "平生相愛應相識，誰道修篁勝此君。"]'),
('yuding-5','讀漢史','李山甫','唐','御定全唐诗','yuding','','[]','四百年間反復尋，漢家興替好沾襟。每逢奸詐須挼手，',40,'御定全唐詩/json/643.json','["四百年間反復尋，漢家興替好沾襟。每逢奸詐須挼手，", "當時虛受君恩者，謾向青編作鬼林。"]'),
('yuding-6','上元懷古二首','李山甫','唐','御定全唐诗','yuding','','[]','南朝天子愛風流，盡守江山不到頭。總是戰爭收拾得，',80,'御定全唐詩/json/643.json','["南朝天子愛風流，盡守江山不到頭。總是戰爭收拾得，", "試問繁華何處有，雨苔煙草古城秋。", "爭帝圖王德盡衰，驟興馳霸亦何為。君臣都是一場笑，", "今朝城上難回首，不見樓船索戰時。"]'),
('yuding-7','隋堤柳','李山甫','唐','御定全唐诗','yuding','','[]','曾傍龍舟拂翠華，至今凝恨倚天涯。但經春色還秋色，',40,'御定全唐詩/json/643.json','["曾傍龍舟拂翠華，至今凝恨倚天涯。但經春色還秋色，", "年年只有晴風便，遙為雷塘送雪花。"]'),
('yuding-8','蒲關西道中作','李山甫','唐','御定全唐诗','yuding','','[]','國東王氣凝蒲關，樓臺帖出晴空間。紫煙橫捧大舜廟，',40,'御定全唐詩/json/643.json','["國東王氣凝蒲關，樓臺帖出晴空間。紫煙橫捧大舜廟，", "來來去去身依舊，未及潘年鬢已斑。"]'),
('yuding-9','送李秀才入軍','李山甫','唐','御定全唐诗','yuding','','[]','弱柳貞松一地栽，不因霜霰自難媒。書生只是平時物，',40,'御定全唐詩/json/643.json','["弱柳貞松一地栽，不因霜霰自難媒。書生只是平時物，", "到頭功業須如此，莫為初心首重回。"]'),
('yuding-10','送蘄州裴員外','李山甫','唐','御定全唐诗','yuding','','[]','正作南宮第一人，暫隨霓旆愴離群。曉從闕下辭天子，',40,'御定全唐詩/json/643.json','["正作南宮第一人，暫隨霓旆愴離群。曉從闕下辭天子，", "明朝無路尋歸處，禁樹參差隔紫雲。"]'),
('yuding-11','代孔明哭先主','李山甫','唐','御定全唐诗','yuding','','[]','憶昔南陽顧草廬，便乘雷電捧乘輿。酌量諸夏須平取，',40,'御定全唐詩/json/643.json','["憶昔南陽顧草廬，便乘雷電捧乘輿。酌量諸夏須平取，", "九疑山下頻惆悵，曾許微臣水共魚。"]'),
('yuding-12','送職方王郎中吏部劉員外自太原鄭相公幕繼奉征書歸省署','李山甫','唐','御定全唐诗','yuding','','[]','雙鳳銜書次第飛，玉皇催促列仙歸。雲開日月臨青瑣，',40,'御定全唐詩/json/643.json','["雙鳳銜書次第飛，玉皇催促列仙歸。雲開日月臨青瑣，", "此生長掃朱門者，每向人間夢粉闈。"]'),
('yuding-13','寒食二首','李山甫','唐','御定全唐诗','yuding','','[]','柳帶東風一向斜，春陰澹澹蔽人家。有時三點兩點雨，',80,'御定全唐詩/json/643.json','["柳帶東風一向斜，春陰澹澹蔽人家。有時三點兩點雨，", "年年今日誰相問，獨臥長安泣歲華。", "風煙放蕩花披猖，秋千女兒飛短牆。繡袍馳馬拾遺翠，", "自憐塵土無他事，空脫荷衣泥醉鄉。"]'),
('yuding-14','又代孔明哭先主','李山甫','唐','御定全唐诗','yuding','','[]','鯨鬣翻騰四海波，始將天意用干戈。盡驅神鬼隨鞭策，',40,'御定全唐詩/json/643.json','["鯨鬣翻騰四海波，始將天意用干戈。盡驅神鬼隨鞭策，", "鼎湖無路追仙駕，空使群臣泣血多。"]'),
('yuding-15','貧女','李山甫','唐','御定全唐诗','yuding','','[]','平生不識繡衣裳，閑把荊釵亦自傷。鏡裏只應諳素貌，',40,'御定全唐詩/json/643.json','["平生不識繡衣裳，閑把荊釵亦自傷。鏡裏只應諳素貌，", "兩意定知無說處，暗垂珠淚濕蠶筐。"]'),
('yuding-16','寓懷','李山甫','唐','御定全唐诗','yuding','','[]','萬古交馳一片塵，思量名利孰如身。長疑好事皆虛事，',40,'御定全唐詩/json/643.json','["萬古交馳一片塵，思量名利孰如身。長疑好事皆虛事，", "勸君不用誇頭角，夢裏輸贏總未真。"]'),
('yuding-17','蜀中寓懷','李山甫','唐','御定全唐诗','yuding','','[]','千里煙霞錦水頭，五丁開得也風流。春裝寶闕重重樹，',40,'御定全唐詩/json/643.json','["千里煙霞錦水頭，五丁開得也風流。春裝寶闕重重樹，", "此中無限英雄鬼，應對江山各自羞。"]'),
('yuding-18','下第臥疾盧員外召游曲江','李山甫','唐','御定全唐诗','yuding','','[]','眼前何事不傷神，忍向江頭更弄春。桂樹既能欺賤子，',40,'御定全唐詩/json/643.json','["眼前何事不傷神，忍向江頭更弄春。桂樹既能欺賤子，", "珍重列星相借問，嵇康慵病也天真。"]'),
('yuding-19','司天臺','李山甫','唐','御定全唐诗','yuding','','[]','拂雲朱檻捧昭回，靜對銅渾水鏡開。太史只知頻奏瑞，',40,'御定全唐詩/json/643.json','["拂雲朱檻捧昭回，靜對銅渾水鏡開。太史只知頻奏瑞，", "何事曠官全不語，好天良月鎖高臺。"]'),
('yuding-20','落花','李山甫','唐','御定全唐诗','yuding','','[]','落拓東風不藉春，吹開吹謝兩何因。當時曾見笑筵主，',40,'御定全唐詩/json/643.json','["落拓東風不藉春，吹開吹謝兩何因。當時曾見笑筵主，", "明年寒食重相見，零淚無端又滿巾。"]'),
('yuding-21','赴舉別所知','李山甫','唐','御定全唐诗','yuding','','[]','腰劍囊書出戶遲，壯心奇命兩相疑。麻衣盡舉一雙手，',40,'御定全唐詩/json/643.json','["腰劍囊書出戶遲，壯心奇命兩相疑。麻衣盡舉一雙手，", "叔牙憂我應相痛，回首天涯寄所思。"]'),
('yuding-22','賀邢州盧員外','李山甫','唐','御定全唐诗','yuding','','[]','紫泥飛詔下金鑾，列象分明世仰觀。北省諫書藏舊草，',40,'御定全唐詩/json/643.json','["紫泥飛詔下金鑾，列象分明世仰觀。北省諫書藏舊草，", "偏是此生棲息者，滿衣零淚一時幹。"]'),
('yuding-23','方幹隱居','李山甫','唐','御定全唐诗','yuding','','[]','咬咬嘎嘎水禽聲，露洗松陰滿院清。溪畔印沙多鶴跡，',40,'御定全唐詩/json/643.json','["咬咬嘎嘎水禽聲，露洗松陰滿院清。溪畔印沙多鶴跡，", "早晚塵埃得休去，且將書劍事先生。"]'),
('yuding-24','早春微雨','李山甫','唐','御定全唐诗','yuding','','[]','怪來鶯蝶似凝愁，不覺看花暫濕頭。疏影未藏千里樹，',40,'御定全唐詩/json/643.json','["怪來鶯蝶似凝愁，不覺看花暫濕頭。疏影未藏千里樹，", "歲旱且須教濟物，為霖何事愛風流。"]'),
('yuding-25','謁翰林劉學士不遇','李山甫','唐','御定全唐诗','yuding','','[]','夢繞清華宴地深，洞宮橫鎖曉沉沉。鵬飛碧海終難見，',40,'御定全唐詩/json/643.json','["夢繞清華宴地深，洞宮橫鎖曉沉沉。鵬飛碧海終難見，", "平生只恥淩風翼，隨得鳴珂上禁林。"]'),
('yuding-26','答劉書記見贈','李山甫','唐','御定全唐诗','yuding','','[]','吟近秋光思不窮，酷探騷雅愧無功。茫然心苦千篇拙，',40,'御定全唐詩/json/643.json','["吟近秋光思不窮，酷探騷雅愧無功。茫然心苦千篇拙，", "知音頻有新詩贈，白雪紛紛落郢中。"]'),
('yuding-27','賀友人及第','李山甫','唐','御定全唐诗','yuding','','[]','得水蛟龍失水魚，此心相對兩何如。敢辭今日須行卷，',40,'御定全唐詩/json/643.json','["得水蛟龍失水魚，此心相對兩何如。敢辭今日須行卷，", "春風不見尋花伴，遙向青雲泥子虛。"]'),
('yuding-28','雨後過華岳廟','李山甫','唐','御定全唐诗','yuding','','[]','華山黑影霄崔嵬，金天□□門未開。雨淋鬼火滅不滅，',40,'御定全唐詩/json/643.json','["華山黑影霄崔嵬，金天□□門未開。雨淋鬼火滅不滅，", "知君暗宰人間事，休把蒼生夢裏裁。"]'),
('yuding-29','贈彈琴李處士','李山甫','唐','御定全唐诗','yuding','','[]','情知此事少知音，自是先生枉用心。世上幾時曾好古，',40,'御定全唐詩/json/643.json','["情知此事少知音，自是先生枉用心。世上幾時曾好古，", "三尺焦桐七條線，子期師曠兩沉沉。"]'),
('yuding-30','劉員外寄移菊','李山甫','唐','御定全唐诗','yuding','','[]','秋來緣樹複緣牆，怕共平蕪一例荒。顏色不能隨地變，',40,'御定全唐詩/json/643.json','["秋來緣樹複緣牆，怕共平蕪一例荒。顏色不能隨地變，", "深謝栽培與知賞，但慚終歲待重陽。"]'),
('yuding-31','南山','李山甫','唐','御定全唐诗','yuding','','[]','鈍碧頑青幾萬秋，直無天地始應休。莫嫌塵土佯遮面，',40,'御定全唐詩/json/643.json','["鈍碧頑青幾萬秋，直無天地始應休。莫嫌塵土佯遮面，", "假饒不是神仙骨，終抱琴書向此遊。"]'),
('yuding-32','山中覽劉書記新詩','李山甫','唐','御定全唐诗','yuding','','[]','記室新詩相寄我，藹然清絕更無過。溪風滿袖吹騷雅，',40,'御定全唐詩/json/643.json','["記室新詩相寄我，藹然清絕更無過。溪風滿袖吹騷雅，", "靜酬嘉唱對幽景，蒼鶴羸棲古木柯。"]'),
('yuding-33','早秋山中作','李山甫','唐','御定全唐诗','yuding','','[]','榮枯無路入千峰，肥遁誰諧此志同。司寇亦曾遭魯黜，',40,'御定全唐詩/json/643.json','["榮枯無路入千峰，肥遁誰諧此志同。司寇亦曾遭魯黜，", "山思更清人影絕，隴雲飛入草堂中。"]'),
('yuding-34','賦得寒月寄齊已','李山甫','唐','御定全唐诗','yuding','','[]','松下清風吹我襟，上方鐘磬夜沉沉。已知廬嶽塵埃絕，',40,'御定全唐詩/json/643.json','["松下清風吹我襟，上方鐘磬夜沉沉。已知廬嶽塵埃絕，", "豈知名出遍諸夏，石上棲禪竹影侵。"]'),
('yuding-35','曲江二首','李山甫','唐','御定全唐诗','yuding','','[]','南山低對紫雲樓，翠影紅陰瑞氣浮。一種是春長富貴，',80,'御定全唐詩/json/643.json','["南山低對紫雲樓，翠影紅陰瑞氣浮。一種是春長富貴，", "獨向江邊最惆悵，滿衣塵土避王侯。", "江色沈天萬草齊，暖煙晴靄自相迷。蜂憐杏蕊細香落，", "斜陽怪得長安動，陌上分飛萬馬蹄。"]'),
('yuding-36','遷居清溪和劉書記見示','李山甫','唐','御定全唐诗','yuding','','[]','擔錫歸來竹繞溪，過津曾笑魯儒迷。端居味道塵勞息，',48,'御定全唐詩/json/643.json','["擔錫歸來竹繞溪，過津曾笑魯儒迷。端居味道塵勞息，", "山衣毳爛唯添野，石井源清不貯泥。祖意豈從年臘得，"]'),
('yuding-37','陰地關崇徽公主手跡','李山甫','唐','御定全唐诗','yuding','','[]','一拓纖痕更不收，翠微蒼蘚幾經秋。誰陳帝子和番策，',40,'御定全唐詩/json/643.json','["一拓纖痕更不收，翠微蒼蘚幾經秋。誰陳帝子和番策，", "可憐汾水知人意，旁與吞聲未忍休。"]'),
('yuding-38','題李員外廳','李山甫','唐','御定全唐诗','yuding','','[]','石砌蛩吟響，草堂人語稀。道孤思絕唱，年長漸知非。',84,'御定全唐詩/json/643.json','["石砌蛩吟響，草堂人語稀。道孤思絕唱，年長漸知非。", "名利終成患，煙霞亦可依。高丘松蓋古，閑地藥苗肥。", "猿鳥啼嘉景，牛羊傍晚暉。幽棲還自得，清嘯坐忘機。", "愛彼人深處，白雲相伴歸。"]'),
('yuding-39','山中寄梁判官','李山甫','唐','御定全唐诗','yuding','','[]','歸臥東林計偶諧，柴門深向翠微開。更無塵事心頭起，',40,'御定全唐詩/json/643.json','["歸臥東林計偶諧，柴門深向翠微開。更無塵事心頭起，", "星郎雅是道中侶，六藝拘牽在隗台。"]'),
('yuding-40','禪林寺作寄劉書記','李山甫','唐','御定全唐诗','yuding','','[]','坐近松風骨自寒，茅齋直拶白雪邊。玄關不閉何人到，',40,'御定全唐詩/json/643.json','["坐近松風骨自寒，茅齋直拶白雪邊。玄關不閉何人到，", "今朝林下忘言說，強把新詩寄謫仙。"]'),
('yuding-41','山中病後作','李山甫','唐','御定全唐诗','yuding','','[]','臥病厭厭三伏盡，商飆初自水邊來。高峰枯槁骨偏峭，',40,'御定全唐詩/json/643.json','["臥病厭厭三伏盡，商飆初自水邊來。高峰枯槁骨偏峭，", "雲門不閉全無事，心外沈然一聚灰。"]'),
('yuding-42','寄衛別駕','李山甫','唐','御定全唐诗','yuding','','[]','曉屐歸來嶽寺深，嘗思道侶會東林。昏沈天竺看經眼，',40,'御定全唐詩/json/643.json','["曉屐歸來嶽寺深，嘗思道侶會東林。昏沈天竺看經眼，", "知君超達悟空旨，三徑閑行抱素琴。"]'),
('yuding-43','遣懷','李山甫','唐','御定全唐诗','yuding','','[]','長松埋澗底，鬱鬱未出原。孤雲飛隴首，高潔不可攀。',72,'御定全唐詩/json/643.json','["長松埋澗底，鬱鬱未出原。孤雲飛隴首，高潔不可攀。", "古道貴拙直，時事不足言。莫飲盜泉水，無為天下先。", "智者與愚者，盡歸北邙山。唯有東流水，年光不暫閑。"]'),
('yuding-44','酬劉書記一二知己見寄','李山甫','唐','御定全唐诗','yuding','','[]','見說金台客，相逢只論詩。坐來殘暑退，吟許野僧知。',72,'御定全唐詩/json/643.json','["見說金台客，相逢只論詩。坐來殘暑退，吟許野僧知。", "自喜幽棲僻，唯慚道義虧。身閑偏好古，句冷不求奇。", "晦跡全無累，安貧自得宜。同人終念我，蓮社有歸期。"]'),
('yuding-45','山中依韻答劉書記見贈','李山甫','唐','御定全唐诗','yuding','','[]','幽居少人事，三徑草不開。隱幾虛室靜，閑雲入坐來。',192,'御定全唐詩/json/643.json','["幽居少人事，三徑草不開。隱幾虛室靜，閑雲入坐來。", "至道非內外，詎言才不才。寶月當秋空，高潔無纖埃。", "心滅百慮減，詩成萬象回。亦有吾廬在，寂寞舊山隈。", "從容未歸去，滿地生青苔。謝公寄我詩，清奇不可陪。", "白雪飛不盡，碧雲欲成堆。驚風出地戶，虩虩似震雷。", "吟哦山嶽動，令人心膽摧。思君覽章句，還複如望梅。", "慷慨追古意，曠望登高台。何當陶淵明，遠師勸傾杯。", "流年將老來，華髮自相催。野寺連屏障，左右相裴回。"]'),
('yuding-46','山中答劉書記寓懷','李山甫','唐','御定全唐诗','yuding','','[]','貴門多冠冕，日與榮辱並。山中有獨夫，笑傲出衰盛。',120,'御定全唐詩/json/643.json','["貴門多冠冕，日與榮辱並。山中有獨夫，笑傲出衰盛。", "正直任天真，鬼神亦相敬。之子賁丘園，戶牖松蘿映。", "骨將槁木齊，心同止水淨。筆頭指金波，座上橫玉柄。", "芙蓉出秋渚，繡段流清詠。高古不稱時，沉默豈相競。", "窮搜萬籟息，危坐千峰靜。林僧繼嘉唱，風前亦為幸。"]'),
('yuding-47','項羽廟','李山甫','唐','御定全唐诗','yuding','','[]','為虜為王盡偶然，有何羞見漢江船。',32,'御定全唐詩/json/643.json','["為虜為王盡偶然，有何羞見漢江船。", "停分天下猶嫌少，可要行人贈紙錢。"]'),
('yuding-48','春日商山道中作','李山甫','唐','御定全唐诗','yuding','','[]','一徑春光裏，揚鞭入翠微。風來花落帽，雲過雨沾衣。',48,'御定全唐詩/json/643.json','["一徑春光裏，揚鞭入翠微。風來花落帽，雲過雨沾衣。", "穀鳥銜枝去，巴人負笈歸。殘陽更惆悵，前路客亭稀。"]'),
('yuding-49','古石硯','李山甫','唐','御定全唐诗','yuding','','[]','追琢他山石，方圓一勺深。抱真唯守墨，求用每虛心。',48,'御定全唐詩/json/643.json','["追琢他山石，方圓一勺深。抱真唯守墨，求用每虛心。", "波浪因文起，塵埃為廢侵。憑君更研究，何啻直千金。"]'),
('yuding-50','惜花','李山甫','唐','御定全唐诗','yuding','','[]','未會春風意，開君又落君。一年今爛漫，幾日便繽紛。',48,'御定全唐詩/json/643.json','["未會春風意，開君又落君。一年今爛漫，幾日便繽紛。", "別豔那堪賞，餘香不忍聞。尊前恨無語，應解作朝雲。"]'),
('yuding-51','別楊秀才','李山甫','唐','御定全唐诗','yuding','','[]','因亂與君別，相逢悲且驚。開襟魂自慰，拭淚眼空明。',48,'御定全唐詩/json/643.json','["因亂與君別，相逢悲且驚。開襟魂自慰，拭淚眼空明。", "故國已無業，舊交多不生。如何又分袂，難話別離情。"]'),
('yuding-52','自歎拙','李山甫','唐','御定全唐诗','yuding','','[]','自憐心計拙，欲語更悲辛。世亂僮欺主，年衰鬼弄人。',48,'御定全唐詩/json/643.json','["自憐心計拙，欲語更悲辛。世亂僮欺主，年衰鬼弄人。", "鏡中顏欲老，江上業長貧。不是劉公樂，何由變此身。"]'),
('yuding-53','亂後途中','李山甫','唐','御定全唐诗','yuding','','[]','亂離尋故園，朝市不如村。慟哭翻無淚，顛狂覺少魂。',48,'御定全唐詩/json/643.json','["亂離尋故園，朝市不如村。慟哭翻無淚，顛狂覺少魂。", "諸侯貪割據，群盜恣併吞。為問登壇者，何年答漢恩。"]'),
('yuding-54','燕','李山甫','唐','御定全唐诗','yuding','','[]','每歲同辛苦，看人似有情。亂飛春得意，幽語夜聞聲。',48,'御定全唐詩/json/643.json','["每歲同辛苦，看人似有情。亂飛春得意，幽語夜聞聲。", "整羽莊薑恨，回身漢後輕。豪家足金彈，不用汙雕楹。"]'),
('yuding-55','題慈雲寺僧院','李山甫','唐','御定全唐诗','yuding','','[]','帝城深處寺，樓殿壓秋江。紅葉去寒樹，碧峰來曉窗。',48,'御定全唐詩/json/643.json','["帝城深處寺，樓殿壓秋江。紅葉去寒樹，碧峰來曉窗。", "煙霞生淨土，苔蘚上高幢。欲問吾師語，心猿不肯降。"]'),
('yuding-56','聞子規','李山甫','唐','御定全唐诗','yuding','','[]','冤禽名杜宇，此事更難知。昔帝一時恨，後人千古悲。',48,'御定全唐詩/json/643.json','["冤禽名杜宇，此事更難知。昔帝一時恨，後人千古悲。", "斷腸思故國，啼血濺芳枝。況是天涯客，那堪□□眉。"]'),
('yuding-57','送劉將軍入關討賊','李山甫','唐','御定全唐诗','yuding','','[]','世人多恃武，何者是真雄。欲滅黃巾賊，須憑黑槊公。',48,'御定全唐詩/json/643.json','["世人多恃武，何者是真雄。欲滅黃巾賊，須憑黑槊公。", "指星憂國計，望氣識天風。明日淩雲上，期君第一功。"]'),
('yuding-58','陪鄭先輩華山羅谷訪張隱者','李山甫','唐','御定全唐诗','yuding','','[]','白雲閑洞口，飛蓋入嵐光。好鳥共人語，異花迎客香。',48,'御定全唐詩/json/643.json','["白雲閑洞口，飛蓋入嵐光。好鳥共人語，異花迎客香。", "谷風聞鼓吹，苔石見文章。不是陪仙侶，無因訪阮郎。"]'),
('yuding-59','兵後尋邊三首','李山甫','唐','御定全唐诗','yuding','','[]','千里煙沙盡日昏，戰餘燒罷閉重門。新成劍戟皆農器，',120,'御定全唐詩/json/643.json','["千里煙沙盡日昏，戰餘燒罷閉重門。新成劍戟皆農器，", "自憐長策無人問，羞戴儒冠傍塞垣。", "旗頭指處見黃埃，萬馬橫馳鶻翅回。劍戟遠腥凝血在，", "日暮卻登寒壘望，飽鴟清嘯伏屍堆。", "風怒邊沙迸鐵衣，胡兒胡馬正驕肥。將軍對陣誰教入，", "胸中縱有銷兵術，欲向何門說是非。"]'),
('yuding-60','滄浪峽','李山甫','唐','御定全唐诗','yuding','','[]','走轂飛蹄過此傍，幾人留意問滄浪。',32,'御定全唐詩/json/643.json','["走轂飛蹄過此傍，幾人留意問滄浪。", "煙波莫笑趨名客，為愛朝宗日夜忙。"]'),
('yuding-61','公子家二首','李山甫','唐','御定全唐诗','yuding','','[]','曾是皇家幾世侯，入雲高第照神州。柳遮門戶橫金鎖，',80,'御定全唐詩/json/643.json','["曾是皇家幾世侯，入雲高第照神州。柳遮門戶橫金鎖，", "麻衣酷獻平生業，醉倚春風不點頭。", "柳底花陰壓露塵，醉煙輕罩一團春。鴛鴦占水能嗔客，", "不知買盡長安笑，活得蒼生幾戶貧。"]'),
('yuding-62','山下殘夏偶作','李山甫','唐','御定全唐诗','yuding','','[]','等閒三伏後，獨臥此高丘。殘暑炎于火，林風爽帶秋。',48,'御定全唐詩/json/643.json','["等閒三伏後，獨臥此高丘。殘暑炎于火，林風爽帶秋。", "聲名何要出，吟詠亦堪休。自許紅塵外，雲溪好漱流。"]'),
('yuding-63','夜吟','李山甫','唐','御定全唐诗','yuding','','[]','除卻閑吟外，人間事事慵。更深成一句，月冷上孤峰。',48,'御定全唐詩/json/643.json','["除卻閑吟外，人間事事慵。更深成一句，月冷上孤峰。", "窮理多瞑目，含毫靜倚松。終篇渾不寐，危坐到晨鐘。"]'),
('yuding-64','代崇徽公主意','李山甫','唐','御定全唐诗','yuding','','[]','金釵墜地鬢堆雲，自別朝陽帝豈聞。',32,'御定全唐詩/json/643.json','["金釵墜地鬢堆雲，自別朝陽帝豈聞。", "遣妾一身安社稷，不知何處用將軍。"]'),
('yuding-65','下第獻所知三首','李山甫','唐','御定全唐诗','yuding','','[]','偶向江頭別釣磯，等閒經歲與心違。虛教六尺受辛苦，',120,'御定全唐詩/json/643.json','["偶向江頭別釣磯，等閒經歲與心違。虛教六尺受辛苦，", "春風不用相催促，回避花時也解歸。", "不識人間巧路岐，只將端拙泥神祇。與他名利本無分，", "自憐心計今如此，憑仗春醪為解頤。", "十年磨鏃事鋒鋩，始逐朱旗入戰場。四海風雲難際會，", "今日慚知也慚命，笑餘歌罷忽淒涼。"]'),
('yuding-66','寄太常王少卿','李山甫','唐','御定全唐诗','yuding','','[]','別後西風起，新蟬坐臥聞。秋天靜如水，遠岫碧侵雲。',48,'御定全唐詩/json/643.json','["別後西風起，新蟬坐臥聞。秋天靜如水，遠岫碧侵雲。", "雅飲純和氣，清吟冰雪文。想思重回首，梧葉下紛紛。"]'),
('yuding-67','遊俠兒','李山甫','唐','御定全唐诗','yuding','','[]','好把雄姿渾世塵，一場閒事莫因循。',32,'御定全唐詩/json/643.json','["好把雄姿渾世塵，一場閒事莫因循。", "荊軻只為閑言語，不與燕丹了得人。"]'),
('yuding-68','下第出春明門','李山甫','唐','御定全唐诗','yuding','','[]','曾和秋雨驅愁入，卻向春風領恨回。',32,'御定全唐詩/json/643.json','["曾和秋雨驅愁入，卻向春風領恨回。", "深謝灞陵堤畔柳，與人頭上拂塵埃。"]'),
('yuding-69','望思台','李山甫','唐','御定全唐诗','yuding','','[]','君父昏蒙死不回，謾將平地築高臺。',32,'御定全唐詩/json/643.json','["君父昏蒙死不回，謾將平地築高臺。", "九層黃土是何物，銷得向前冤恨來。"]'),
('yuding-70','病中答劉書記見贈','李山甫','唐','御定全唐诗','yuding','','[]','病來雙樹下，雲腳上禪袍。頻有瓊瑤贈，空瞻雪月高。',48,'御定全唐詩/json/643.json','["病來雙樹下，雲腳上禪袍。頻有瓊瑤贈，空瞻雪月高。", "已知捐俗態，時許話風騷。衰疾未能起，相思徒自勞。"]'),
('yuding-71','早秋山中作','李山甫','唐','御定全唐诗','yuding','','[]','誰到山中語，雨餘風氣秋。煙嵐出澗底，瀑布落床頭。',48,'御定全唐詩/json/643.json','["誰到山中語，雨餘風氣秋。煙嵐出澗底，瀑布落床頭。", "至道亦非遠，僻詩須苦求。千峰有嘉景，拄杖獨巡遊。"]'),
('yuding-72','別墅','李山甫','唐','御定全唐诗','yuding','','[]','此地可求息，開門足野情。窗明雨初歇，日落風更清。',48,'御定全唐詩/json/643.json','["此地可求息，開門足野情。窗明雨初歇，日落風更清。", "蒼蘚槎根匝，碧煙水面生。玩奇心自樂，暑月聽蟬聲。"]'),
('yuding-73','柳十首','李山甫','唐','御定全唐诗','yuding','','[]','灞岸江頭臘雪消，東風偷軟入纖條。',320,'御定全唐詩/json/643.json','["灞岸江頭臘雪消，東風偷軟入纖條。", "春來不忍登樓望，萬架金絲著地嬌。", "受盡風霜得到春，一條條是逐年新。", "尋常送別無餘事，爭忍攀將過與人。", "長恨陽和也世情，把香和豔與紅英。", "家家只是栽桃李，獨自無根到處生。", "只為遮樓又拂橋，被人摧折好枝條。", "假饒張緒如今在，須把風流暗裏銷。", "弱帶低垂可自由，傍他門戶倚他樓。", "金風不解相抬舉，露壓煙欺直到秋。", "終日堂前學畫眉，幾人曾道勝花枝。", "試看三月春殘後，門外青陰是阿誰。", "也曾飛絮謝家庭，從此風流別有名。", "不是向人無用處，一枝愁殺別離情。", "從來只是愛花人，楊柳何曾占得春。", "多向客亭門外立，與他迎送往來塵。", "強扶柔態酒難醒，殢著春風別有情。", "公子王孫且相伴，與君俱得幾時榮。", "無賴秋風斗覺寒，萬條煙草一時幹。", "遊人若要春消息，直向江頭臘後看。"]'),
('yuding-74','酬劉書記見贈','李山甫','唐','御定全唐诗','yuding','','[]','獨在西峰末，憐君和氣多。勞生同朽索，急景似傾波。',96,'御定全唐詩/json/643.json','["獨在西峰末，憐君和氣多。勞生同朽索，急景似傾波。", "禪者行擔錫，樵師語隔坡。旱□生赤蘚，古木架青蘿。", "石澗新蟬脫，茅簷舊燕窠。篇章蒙見許，松月好相過。", "思苦通真理，吟清合大和。□□□□□，風起送漁歌。"]'),
('yuding-75','贈徐三十','李山甫','唐','御定全唐诗','yuding','','[]','春滿南宮白日長，夜來新值錦衣郎。朱排六相助神聳，',40,'御定全唐詩/json/643.json','["春滿南宮白日長，夜來新值錦衣郎。朱排六相助神聳，", "從今不羨乘槎客，曾到三星列宿傍。"]'),
('yuding-76','牡丹','李山甫','唐','御定全唐诗','yuding','','[]','邀勒春風不早開，眾芳飄後上樓臺。數苞仙豔火中出，',40,'御定全唐詩/json/643.json','["邀勒春風不早開，眾芳飄後上樓臺。數苞仙豔火中出，", "知君也解相輕薄，斜倚闌幹首重回。"]'),
('yuding-77','贈宿將','李山甫','唐','御定全唐诗','yuding','','[]','校獵燕山經幾春，雕弓白羽不離身。',32,'御定全唐詩/json/643.json','["校獵燕山經幾春，雕弓白羽不離身。", "年來馬上渾無力，望見飛鴻指似人。"]'),
('yuding-0','水仙操','李鹹用','唐','御定全唐诗','yuding','','[]','大波相拍流水鳴，蓬山鳥獸多奇形。琴心不喜亦不驚，',88,'御定全唐詩/json/644.json','["大波相拍流水鳴，蓬山鳥獸多奇形。琴心不喜亦不驚，", "嶧陽散木虛且輕，重華斧下知其聲。檿絲相糾成淒清，", "後人好事傳其曲，有時聲足意不足。始峨峨兮複洋洋，", "琴兮琴兮在自然，不在徽金將軫玉。"]'),
('yuding-1','雞鳴曲','李鹹用','唐','御定全唐诗','yuding','','[]','海樹相扶烏影翹，戴紅拍翠聲膠膠。鴛瓦凍危金距趫，',48,'御定全唐詩/json/644.json','["海樹相扶烏影翹，戴紅拍翠聲膠膠。鴛瓦凍危金距趫，", "霜濃月薄星昭昭，太平才子能歌謠。山翁夢斷出衡茅，"]'),
('yuding-2','西門行','李咸用','唐','御定全唐诗','yuding','','[]','勞禽不擇枝，饑虎不畏檻。君子當固窮，無為仲由濫。',48,'御定全唐詩/json/644.json','["勞禽不擇枝，饑虎不畏檻。君子當固窮，無為仲由濫。", "爾奮空拳彼擊劍，水縱長瀾火飛焰。漢高偶試神蛇驗，"]'),
('yuding-3','輕薄怨','李鹹用','唐','御定全唐诗','yuding','','[]','花驄躞蹀游龍驕，連連寶節揮長鞘。鳳雛麟子皆至交，',64,'御定全唐詩/json/644.json','["花驄躞蹀游龍驕，連連寶節揮長鞘。鳳雛麟子皆至交，", "碧蹄偃蹇連金鑣，狂情十裏飛相燒。西母青禽輕飄飄，", "明朝何處逢嬌饒，門前桃樹空夭夭。"]'),
('yuding-4','長歌行','李鹹用','唐','御定全唐诗','yuding','','[]','要衣須破束，欲炙須解牛。當年不快意，徒為他人留。',72,'御定全唐詩/json/644.json','["要衣須破束，欲炙須解牛。當年不快意，徒為他人留。", "百歲之約何悠悠，華髮星星稀滿頭。峨眉螓首聊我仇，", "象箸擊折歌勿休，玉山未到非風流。眼前有物俱是夢，"]'),
('yuding-5','巫山高','李鹹用','唐','御定全唐诗','yuding','','[]','通蜀連秦山十二，中有妖靈會人意。鬥豔傳情世不知，',48,'御定全唐詩/json/644.json','["通蜀連秦山十二，中有妖靈會人意。鬥豔傳情世不知，", "露泫煙愁岩上花，至今猶滴相思淚。西眉南臉人中美，"]'),
('yuding-6','公無渡河','李鹹用','唐','御定全唐诗','yuding','','[]','有叟有叟何清狂，行搔短髮提壺漿。亂流直涉神洋洋，',48,'御定全唐詩/json/644.json','["有叟有叟何清狂，行搔短髮提壺漿。亂流直涉神洋洋，", "刳松輕穩琅玕長，連呼急榜庸何妨。見溺不援能語狼，"]'),
('yuding-7','春雨','李鹹用','唐','御定全唐诗','yuding','','[]','大帝閑吹破凍風，青雲融液流長空。天人醉引玄酒注，',40,'御定全唐詩/json/644.json','["大帝閑吹破凍風，青雲融液流長空。天人醉引玄酒注，", "老農私與牧童論，紛紛便是倉箱本。"]'),
('yuding-8','石版歌','李鹹用','唐','御定全唐诗','yuding','','[]','雲根劈裂雷斧痕，龍泉切璞青皮皴。直方挺質貞且真，',40,'御定全唐詩/json/644.json','["雲根劈裂雷斧痕，龍泉切璞青皮皴。直方挺質貞且真，", "明月夜來回短影，何如照冷太湖濱。"]'),
('yuding-9','春宮詞','李鹹用','唐','御定全唐诗','yuding','','[]','風和氣淑宮殿春，感陽體解思君恩。眼光滴滴心振振，',24,'御定全唐詩/json/644.json','["風和氣淑宮殿春，感陽體解思君恩。眼光滴滴心振振，"]'),
('yuding-10','富貴曲','李鹹用','唐','御定全唐诗','yuding','','[]','畫藻雕山金碧彩，鴛鴦疊翠眠晴靄。編珠影裏醉春庭，',96,'御定全唐詩/json/644.json','["畫藻雕山金碧彩，鴛鴦疊翠眠晴靄。編珠影裏醉春庭，", "活花起舞夜春來，蠟焰煌煌天日在。雪暖瑤杯鳳髓融，", "車如雷兮馬如龍，鬼神辟易不敢害。冠峨劍重鏘環佩，", "珍珠索得龍宮貧，膏腴刮下蒼生背。九野干戈指著心，"]'),
('yuding-11','獨鵠吟','李咸用','唐','御定全唐诗','yuding','','[]','碧玉喙長丹頂圓，亭亭危立風松間。啄萍吞鱗意已闌，',48,'御定全唐詩/json/644.json','["碧玉喙長丹頂圓，亭亭危立風松間。啄萍吞鱗意已闌，", "披霜唳月驚嬋娟，逍遙忘卻還青田。鳶寒鴉晚空相喧，"]'),
('yuding-12','煌煌京洛行','李咸用','唐','御定全唐诗','yuding','','[]','長安近甸巡遊遍，洛陽尋有黃龍見。千乘萬騎如雷轉，',48,'御定全唐詩/json/644.json','["長安近甸巡遊遍，洛陽尋有黃龍見。千乘萬騎如雷轉，", "歌鐘沸激香塵散，晨旗隱隱羅軒冕。周公舊跡生紅蘚，"]'),
('yuding-13','升天行','李鹹用','唐','御定全唐诗','yuding','','[]','堂堂削玉青蠅喧，寒鴉啄鼠愁飛鸞。梳玄洗白逡巡間，',96,'御定全唐詩/json/644.json','["堂堂削玉青蠅喧，寒鴉啄鼠愁飛鸞。梳玄洗白逡巡間，", "不如服取長流丹，潛神卻入黃庭閑。志定功成飛九關，", "雙童樹節當風翻，常娥倚桂開朱顏。河邊牛子星郎牽，", "引餘再拜歸仙班，清聲妙色視聽安。餐和飲順中腸寬，"]'),
('yuding-14','緋桃花歌','李鹹用','唐','御定全唐诗','yuding','','[]','上帝春宮思麗絕，夭桃變態求新悅。便是花中傾國容，',40,'御定全唐詩/json/644.json','["上帝春宮思麗絕，夭桃變態求新悅。便是花中傾國容，", "惆悵東風未解狂，爭教此物芳菲歇。"]'),
('yuding-15','短歌行','李鹹用','唐','御定全唐诗','yuding','','[]','一樽綠酒綠於染，拍手高歌天地險。上得青雲下不難，',48,'御定全唐詩/json/644.json','["一樽綠酒綠於染，拍手高歌天地險。上得青雲下不難，", "白日欲沈猶未沈，片月已來天半垂。坎鼓鏗鐘殺愁賊，"]'),
('yuding-16','小松歌','李鹹用','唐','御定全唐诗','yuding','','[]','幽人不喜凡草生，秋鋤劚得寒青青。庭閑土瘦根腳獰，',48,'御定全唐詩/json/644.json','["幽人不喜凡草生，秋鋤劚得寒青青。庭閑土瘦根腳獰，", "天人戲剪蒼龍髯，參差簇在瑤階側。金精水鬼欺不得，"]'),
('yuding-17','大雪歌','李鹹用','唐','御定全唐诗','yuding','','[]','同雲慘慘如天怒，寒龍振鬣飛幹雨。玉圃花飄朵不勻，',44,'御定全唐詩/json/644.json','["同雲慘慘如天怒，寒龍振鬣飛幹雨。玉圃花飄朵不勻，", "應是羲和倦曉昏，暫反元元歸太素。歸太素，"]'),
('yuding-18','塘上行','李鹹用','唐','御定全唐诗','yuding','','[]','橫塘日澹秋雲隔，浪織輕颸羅冪冪。紅綃撇水蕩舟人，',40,'御定全唐詩/json/644.json','["橫塘日澹秋雲隔，浪織輕颸羅冪冪。紅綃撇水蕩舟人，", "卻把金釵打綠荷，懊惱露珠穿不得。"]'),
('yuding-19','寓意','李鹹用','唐','御定全唐诗','yuding','','[]','直道荊棘生，斜徑紅塵起。蒼蒼杳無言，麒麟回瑞趾。',48,'御定全唐詩/json/644.json','["直道荊棘生，斜徑紅塵起。蒼蒼杳無言，麒麟回瑞趾。", "東風如未來，飛雪終不已。不知薑子牙，何處釣流水。"]'),
('yuding-20','劍喻','李鹹用','唐','御定全唐诗','yuding','','[]','黯黯秋水寒，至剛非可缺。風胡不出來，攝履人相蔑。',48,'御定全唐詩/json/644.json','["黯黯秋水寒，至剛非可缺。風胡不出來，攝履人相蔑。", "縱挺倚天形，誰是躬提挈。願將百煉身，助我王臣節。"]'),
('yuding-21','蒼頡台','李咸用','唐','御定全唐诗','yuding','','[]','先賢憂民詐，觀跡成綱紀。自有書契來，爭及結繩理。',24,'御定全唐詩/json/644.json','["先賢憂民詐，觀跡成綱紀。自有書契來，爭及結繩理。"]'),
('yuding-22','荊山','李鹹用','唐','御定全唐诗','yuding','','[]','良工指君疑，真玉卻非玉。寄言懷寶人，不須傷手足。',24,'御定全唐詩/json/644.json','["良工指君疑，真玉卻非玉。寄言懷寶人，不須傷手足。"]'),
('yuding-23','自君之出矣','李鹹用','唐','御定全唐诗','yuding','','[]','自君之出矣，鸞鏡空塵生。思君如明月，明月逐君行。',24,'御定全唐詩/json/644.json','["自君之出矣，鸞鏡空塵生。思君如明月，明月逐君行。"]'),
('yuding-24','妾薄命','李鹹用','唐','御定全唐诗','yuding','','[]','妾命何太薄，不及宮中水。時時對天顏，聲聲入君耳。',24,'御定全唐詩/json/644.json','["妾命何太薄，不及宮中水。時時對天顏，聲聲入君耳。"]'),
('yuding-25','君子行','李咸用','唐','御定全唐诗','yuding','','[]','君子慎所履，小人多所疑。尼甫至聖賢，猶為匡所縻。',24,'御定全唐詩/json/644.json','["君子慎所履，小人多所疑。尼甫至聖賢，猶為匡所縻。"]'),
('yuding-26','銅雀台','李鹹用','唐','御定全唐诗','yuding','','[]','但見西陵慘明月，女妓無因更相悅。',32,'御定全唐詩/json/644.json','["但見西陵慘明月，女妓無因更相悅。", "有虞曾不有遺言，滴盡湘妃眼中血。"]'),
('yuding-27','婕妤怨','李咸用','唐','御定全唐诗','yuding','','[]','莫恃芙蓉開滿面，更有身輕似飛燕。',32,'御定全唐詩/json/644.json','["莫恃芙蓉開滿面，更有身輕似飛燕。", "不得團圓長近君，珪月鈋時泣秋扇。"]'),
('yuding-28','悲哉行','李鹹用','唐','御定全唐诗','yuding','','[]','雲色陰沈弄秋氣，危葉高枝恨深翠。',32,'御定全唐詩/json/644.json','["雲色陰沈弄秋氣，危葉高枝恨深翠。", "用卻春風力幾多，微霜逼迫何容易。"]'),
('yuding-29','攜手曲','李鹹用','唐','御定全唐诗','yuding','','[]','攜手春複春，未嘗漸離別。夭夭風前花，纖纖日中雪。',60,'御定全唐詩/json/644.json','["攜手春複春，未嘗漸離別。夭夭風前花，纖纖日中雪。", "不敢怨於天，唯驚添歲月。不敢怨于君，只怕芳菲歇。", "芳菲若長然，君恩應不絕。"]'),
('yuding-30','空城雀','李鹹用','唐','御定全唐诗','yuding','','[]','啾啾空城雀，一啄數跳躍。寧尋覆轍餘，豈比巢危幕。',36,'御定全唐詩/json/644.json','["啾啾空城雀，一啄數跳躍。寧尋覆轍餘，豈比巢危幕。", "茫茫九萬鵬，百雉且為樂。"]'),
('yuding-31','放歌行','李鹹用','唐','御定全唐诗','yuding','','[]','蠢蠢荼蓼蟲，薨薨避葵薺。悠悠狷者心，寂寂厭清世。',60,'御定全唐詩/json/644.json','["蠢蠢荼蓼蟲，薨薨避葵薺。悠悠狷者心，寂寂厭清世。", "如何不食甘，命合苦其噬。如何不趣時，分合辱其體。", "至哉先哲言，于物不凝滯。"]'),
('yuding-32','猛虎行','李鹹用','唐','御定全唐诗','yuding','','[]','猛虎不怯敵，烈士無虛言。怯敵辱其班，虛言負其恩。',48,'御定全唐詩/json/644.json','["猛虎不怯敵，烈士無虛言。怯敵辱其班，虛言負其恩。", "爪牙欺白刃，果敢無前陣。須知易水歌，至死無悔吝。"]'),
('yuding-33','隴頭行','李咸用','唐','御定全唐诗','yuding','','[]','行人何彷徨，隴頭水嗚咽。寒沙戰鬼愁，白骨風霜切。',48,'御定全唐詩/json/644.json','["行人何彷徨，隴頭水嗚咽。寒沙戰鬼愁，白骨風霜切。", "薄日朦朧秋，怨氣陰雲結。殺成邊將名，名著生靈滅。"]'),
('yuding-34','關山月','李鹹用','唐','御定全唐诗','yuding','','[]','離離天際雲，皎皎關山月。羌笛一聲來，白盡征人發。',60,'御定全唐詩/json/644.json','["離離天際雲，皎皎關山月。羌笛一聲來，白盡征人發。", "嘹唳孤鴻高，蕭索悲風發。雪壓塞塵清，雕落沙場闊。", "何當胡無人，荷戈朝鳳闕。"]'),
('yuding-35','覽友生古風','李咸用','唐','御定全唐诗','yuding','','[]','伯牙鳴玉琴，幽音隨指發。不是鐘期聽，俗耳安能別。',133,'御定全唐詩/json/644.json','["伯牙鳴玉琴，幽音隨指發。不是鐘期聽，俗耳安能別。", "高山閑巍峨，流水聲嗚咽。一卷冰雪言，清泠冷心骨。", "分明古雅聲，諷諭成淒切。皴bq老松根，晃朗驪龍窟。", "荊璞且深藏，瑉石方如雪。金多醜女妍，木朽良工拙。", "奸宄欺雷霆，魑魅嫌日月。蝶迷桃李香，鮒惘江湖闊。", "不寐孤燈前，舒卷忘饑渴。"]'),
('yuding-36','題友生叢竹','李鹹用','唐','御定全唐诗','yuding','','[]','菊華寒露濃，蘭愁曉霜重。指佞不長生，蒲萐今無種。',84,'御定全唐詩/json/644.json','["菊華寒露濃，蘭愁曉霜重。指佞不長生，蒲萐今無種。", "安如植叢篁，他年待棲鳳。大則化龍騎，小可釣璜用。", "留煙伴獨醒，回陰冷閑夢。何妨積雪淩，但為清風動。", "乃知子猷心，不與常人共。"]'),
('yuding-37','石版','李咸用','唐','御定全唐诗','yuding','','[]','高人好自然，移得它山碧。不磨如版平，大巧非因力。',60,'御定全唐詩/json/644.json','["高人好自然，移得它山碧。不磨如版平，大巧非因力。", "古蘚小青錢，塵中看野色。冷倚砌花春，靜伴疏篁直。", "山僧若轉頭，如逢舊相識。"]'),
('yuding-38','江南曲','李鹹用','唐','御定全唐诗','yuding','','[]','江南四月熏風低，江南女兒芳步齊。晚雲接水共渺彌，',40,'御定全唐詩/json/644.json','["江南四月熏風低，江南女兒芳步齊。晚雲接水共渺彌，", "孤舟有客歸未得，鄉夢欲成山鳥啼。"]'),
('yuding-39','臨川逢陳百年','李咸用','唐','御定全唐诗','yuding','','[]','麻姑山下逢真士，玄膚碧眼方瞳子。自言混沌鑿不死，',48,'御定全唐詩/json/644.json','["麻姑山下逢真士，玄膚碧眼方瞳子。自言混沌鑿不死，", "桃花雨過春光膩，勸我一杯靈液味。教我無為禮樂拘，"]'),
('yuding-40','寄修睦上人','李鹹用','唐','御定全唐诗','yuding','','[]','衣服田方無內客，一入廬雲斷消息。應為山中勝概偏，',48,'御定全唐詩/json/644.json','["衣服田方無內客，一入廬雲斷消息。應為山中勝概偏，", "江邊月色到岩前，此際心情必相似。似不似，寄數字。"]'),
('yuding-41','讀修睦上人歌篇','李鹹用','唐','御定全唐诗','yuding','','[]','李白亡，李賀死，陳陶趙睦尋相次。須知代不乏騷人，',64,'御定全唐詩/json/644.json','["李白亡，李賀死，陳陶趙睦尋相次。須知代不乏騷人，", "意下紛紛造化機，筆頭滴滴文章髓。明月清風三十年，", "珊瑚高架五雲毫，小小不須煩藻思。"]'),
('yuding-42','遠公亭牡丹','李鹹用','唐','御定全唐诗','yuding','','[]','雁門禪客吟春亭，牡丹獨逞花中英。雙成膩臉偎雲屏，',72,'御定全唐詩/json/644.json','["雁門禪客吟春亭，牡丹獨逞花中英。雙成膩臉偎雲屏，", "蕊繁蟻腳黏不行，甜迷蜂醉飛無聲。廬山根腳含精靈，", "潺潺綠醴當風傾，平頭奴子啾銀笙。紅葩豔豔交童星，"]'),
('yuding-43','謝僧寄茶','李鹹用','唐','御定全唐诗','yuding','','[]','空門少年初志堅，摘芳為藥除睡眠。匡山茗樹朝陽偏，',72,'御定全唐詩/json/644.json','["空門少年初志堅，摘芳為藥除睡眠。匡山茗樹朝陽偏，", "傾筐短甑蒸新鮮，白紵眼細勻於研。磚排古砌春苔幹，", "林風夕和真珠泉，半匙青粉攪潺湲。綠雲輕綰湘娥鬟，"]'),
('yuding-44','送人','李鹹用','唐','御定全唐诗','yuding','','[]','少皞開宮行帝業，無刃金風剪紅葉。雁別邊沙入暖雲，',70,'御定全唐詩/json/644.json','["少皞開宮行帝業，無刃金風剪紅葉。雁別邊沙入暖雲，", "不甘長在諸生下，束書攜劍離家鄉。利爪鞲上鷹，", "荊山有玉猶在璞，未遇良工虛擲鵲。一壺清酒酌離情，"]'),
('yuding-45','古意論交','李鹹用','唐','御定全唐诗','yuding','','[]','擇友如淘金，沙盡不得寶。結交如幹銀，產竭不成道。',144,'御定全唐詩/json/644.json','["擇友如淘金，沙盡不得寶。結交如幹銀，產竭不成道。", "我生四十年，相識苦草草。多為勢利朋，少有歲寒操。", "通財能幾何，聞善寧相告。茫然同夜行，中路自不保。", "常恐管鮑情，參差忽終老。今來既見君，青天無片雲。", "語直瑟弦急，行高山桂芬。約我為交友，不覺心醺醺。", "見義必許死，臨危當指囷。無令後世士，重廣孝標文。"]'),
('yuding-0','春風','李鹹用','唐','御定全唐诗','yuding','','[]','青帝使和氣，吹噓萬國中。發生寧有異，先後自難同。',48,'御定全唐詩/json/645.json','["青帝使和氣，吹噓萬國中。發生寧有異，先後自難同。", "輦草不消力，岩花應費功。年年三十騎，飄入玉蟾宮。"]'),
('yuding-1','自愧','李鹹用','唐','御定全唐诗','yuding','','[]','多負懸弧禮，危時隱薜蘿。有心明俎豆，無力執干戈。',48,'御定全唐詩/json/645.json','["多負懸弧禮，危時隱薜蘿。有心明俎豆，無力執干戈。", "壯士難移節，貞松不改柯。纓塵徒自滿，欲濯待清波。"]'),
('yuding-2','夜吟','李鹹用','唐','御定全唐诗','yuding','','[]','白兔輪當午，儒家業敢慵。竹軒吟未已，錦帳夢應重。',48,'御定全唐詩/json/645.json','["白兔輪當午，儒家業敢慵。竹軒吟未已，錦帳夢應重。", "落筆思成虎，懸梭待化龍。景清神自爽，風遞遠樓鐘。"]'),
('yuding-3','昭君','李咸用','唐','御定全唐诗','yuding','','[]','古帝修文德，蠻夷莫敢侵。不知桃李貌，能轉虎狼心。',48,'御定全唐詩/json/645.json','["古帝修文德，蠻夷莫敢侵。不知桃李貌，能轉虎狼心。", "日暮邊風急，程遙磧雪深。千秋青塚骨，留怨在胡琴。"]'),
('yuding-4','秋夕','李鹹用','唐','御定全唐诗','yuding','','[]','寥廓秋雲薄，空庭月影微。樹寒棲鳥密，砌冷夜蛩稀。',48,'御定全唐詩/json/645.json','["寥廓秋雲薄，空庭月影微。樹寒棲鳥密，砌冷夜蛩稀。", "曉鼓軍容肅，疏鐘客夢歸。吟餘何所憶，聖主尚宵衣。"]'),
('yuding-5','秋日與友生言別','李鹹用','唐','御定全唐诗','yuding','','[]','利名心未已，離別恨難休。為個文儒業，致多岐路愁。',48,'御定全唐詩/json/645.json','["利名心未已，離別恨難休。為個文儒業，致多岐路愁。", "數花籬菊晚，片葉井梧秋。又決出門計，一尊期少留。"]'),
('yuding-6','邊城聽角','李鹹用','唐','御定全唐诗','yuding','','[]','戍樓鳴畫角，寒露滴金槍。細引雲成陣，高催雁著行。',48,'御定全唐詩/json/645.json','["戍樓鳴畫角，寒露滴金槍。細引雲成陣，高催雁著行。", "喚回邊將夢，吹薄曉蟾光。未遂終軍志，何勞思故鄉。"]'),
('yuding-7','秋日訪同人','李鹹用','唐','御定全唐诗','yuding','','[]','忽憶金蘭友，攜琴去自由。遠尋寒澗碧，深入亂山秋。',48,'御定全唐詩/json/645.json','["忽憶金蘭友，攜琴去自由。遠尋寒澗碧，深入亂山秋。", "見後卻無語，別來長獨愁。幸逢三五夕，露坐對冥搜。"]'),
('yuding-8','寄楚瓊上人','李鹹用','唐','御定全唐诗','yuding','','[]','遙知無事日，靜對五峰秋。鳥隔寒煙語，泉和夕照流。',48,'御定全唐詩/json/645.json','["遙知無事日，靜對五峰秋。鳥隔寒煙語，泉和夕照流。", "憑欄疏磬盡，瞑目遠雲收。幾句出人意，風高白雪浮。"]'),
('yuding-9','游寺','李鹹用','唐','御定全唐诗','yuding','','[]','無家自身在，時得到蓮宮。秋覺暑衣薄，老知塵世空。',48,'御定全唐詩/json/645.json','["無家自身在，時得到蓮宮。秋覺暑衣薄，老知塵世空。", "幽情憐水石，野性任萍蓬。是處堪閑坐，與僧行止同。"]'),
('yuding-10','春日','李鹹用','唐','御定全唐诗','yuding','','[]','浩蕩東風裏，裴回無所親。危城三面水，古樹一邊春。',48,'御定全唐詩/json/645.json','["浩蕩東風裏，裴回無所親。危城三面水，古樹一邊春。", "衰世難修道，花時不稱貧。滔滔天下者，何處問通津。"]'),
('yuding-11','論交','李鹹用','唐','御定全唐诗','yuding','','[]','行虧何必富，節在不妨貧。易得笑言友，難逢終始人。',48,'御定全唐詩/json/645.json','["行虧何必富，節在不妨貧。易得笑言友，難逢終始人。", "松篁貞管鮑，桃李豔張陳。少見歲寒後，免為霜雪塵。"]'),
('yuding-12','秋興','李鹹用','唐','御定全唐诗','yuding','','[]','木葉亂飛盡，故人猶未還。心雖游紫闕，時合在青山。',48,'御定全唐詩/json/645.json','["木葉亂飛盡，故人猶未還。心雖游紫闕，時合在青山。", "近寺僧鄰靜，臨池鶴對閑。兵戈如未息，名位莫相關。"]'),
('yuding-13','山居','李鹹用','唐','御定全唐诗','yuding','','[]','草堂書一架，苔徑竹千竿。難世投誰是，清貧且自安。',48,'御定全唐詩/json/645.json','["草堂書一架，苔徑竹千竿。難世投誰是，清貧且自安。", "鄰居皆學稼，客至亦無官。焦尾何人聽，涼宵對月彈。"]'),
('yuding-14','遣興','李鹹用','唐','御定全唐诗','yuding','','[]','風細酒初醒，憑欄別有情。蟬稀秋樹瘦，雨盡晚雲輕。',48,'御定全唐詩/json/645.json','["風細酒初醒，憑欄別有情。蟬稀秋樹瘦，雨盡晚雲輕。", "旅鬢一絲出，鄉心寸火生。子牟魂欲斷，何日是升平。"]'),
('yuding-15','待旦','李鹹用','唐','御定全唐诗','yuding','','[]','簷靜燕雛語，窗虛蟾影過。時情因客老，歸夢入秋多。',48,'御定全唐詩/json/645.json','["簷靜燕雛語，窗虛蟾影過。時情因客老，歸夢入秋多。", "蔽日群山霧，滔天四海波。吾皇思壯士，誰應大風歌。"]'),
('yuding-16','送從兄坤載','李鹹用','唐','御定全唐诗','yuding','','[]','忍淚不敢下，恐兄情更傷。別離當亂世，骨肉在他鄉。',48,'御定全唐詩/json/645.json','["忍淚不敢下，恐兄情更傷。別離當亂世，骨肉在他鄉。", "語盡意不盡，路長愁更長。那堪回首處，殘照滿衣裳。"]'),
('yuding-17','惜別','李咸用','唐','御定全唐诗','yuding','','[]','細雨妝行色，霏霏入戶來。須知相識喜，卻是別愁媒。',48,'御定全唐詩/json/645.json','["細雨妝行色，霏霏入戶來。須知相識喜，卻是別愁媒。", "白刃方盈國，黃金不上臺。俱為鄒魯士，何處免塵埃。"]'),
('yuding-18','早秋遊山寺','李鹹用','唐','御定全唐诗','yuding','','[]','閑臥雲岩穩，攀緣笑戲猱。靜于諸境靜，高卻眾山高。',48,'御定全唐詩/json/645.json','["閑臥雲岩穩，攀緣笑戲猱。靜于諸境靜，高卻眾山高。", "至理無言了，浮生一夢勞。清風朝複暮，四海自波濤。"]'),
('yuding-19','秋日疾中寄諸同志','李咸用','唐','御定全唐诗','yuding','','[]','閒居無勝事，公幹臥來心。門靜秋風晚，人稀古巷深。',48,'御定全唐詩/json/645.json','["閒居無勝事，公幹臥來心。門靜秋風晚，人稀古巷深。", "花疏籬菊色，葉減井梧陰。賴有斯文在，時時得強尋。"]'),
('yuding-20','贈山僧','李咸用','唐','御定全唐诗','yuding','','[]','榮枯雖在目，名利不關身。高出城隍寺，野為雲鶴鄰。',48,'御定全唐詩/json/645.json','["榮枯雖在目，名利不關身。高出城隍寺，野為雲鶴鄰。", "松聲寒後遠，潭色雨餘新。豈住空空裏，空空亦是塵。"]'),
('yuding-21','宿隱者居','李鹹用','唐','御定全唐诗','yuding','','[]','永日連清夜，因君識躁君。竹扉難掩月，岩樹易延雲。',48,'御定全唐詩/json/645.json','["永日連清夜，因君識躁君。竹扉難掩月，岩樹易延雲。", "曙鳥枕前起，寒泉夢裏聞。又須隨計吏，雞鶴迥然分。"]'),
('yuding-22','送錢契明尊師歸廬山','李鹹用','唐','御定全唐诗','yuding','','[]','瘦倚青竹杖，爐峰指欲歸。霜黏行日屨，風暖到時衣。',48,'御定全唐詩/json/645.json','["瘦倚青竹杖，爐峰指欲歸。霜黏行日屨，風暖到時衣。", "憑檻雲還在，攀松鶴不飛。何曾有別恨，楊柳自依依。"]'),
('yuding-23','送進士劉松','李鹹用','唐','御定全唐诗','yuding','','[]','滔滔皆魯客，難得是心知。到寺多同步，遊山未失期。',48,'御定全唐詩/json/645.json','["滔滔皆魯客，難得是心知。到寺多同步，遊山未失期。", "雲低春雨後，風細暮鐘時。忽別垂楊岸，遙遙望所之。"]'),
('yuding-24','贈任肅','李咸用','唐','御定全唐诗','yuding','','[]','玄發難姑息，青雲有路岐。莫言多事日，虛擲少年時。',48,'御定全唐詩/json/645.json','["玄發難姑息，青雲有路岐。莫言多事日，虛擲少年時。", "松色雪中出，人情難後知。聖朝公道在，中鵠勿差池。"]'),
('yuding-25','題陳正字山居','李鹹用','唐','御定全唐诗','yuding','','[]','怪來忘祿位，習學近瀟湘。見處雲山好，吟中歲月長。',48,'御定全唐詩/json/645.json','["怪來忘祿位，習學近瀟湘。見處雲山好，吟中歲月長。", "花光籠晚雨，樹影浸寒塘。幾日憑欄望，歸心自不忙。"]'),
('yuding-26','贈來進士鵬','李鹹用','唐','御定全唐诗','yuding','','[]','語玄人不到，星漢在靈空。若使無良遇，虛言有至公。',48,'御定全唐詩/json/645.json','["語玄人不到，星漢在靈空。若使無良遇，虛言有至公。", "月明千嶠雪，灘急五更風。此際若吟力，分將造化功。"]'),
('yuding-27','送曹稅','李鹹用','唐','御定全唐诗','yuding','','[]','摻袂向春風，何時約再逢。若教相見密，肯恨別離重。',48,'御定全唐詩/json/645.json','["摻袂向春風，何時約再逢。若教相見密，肯恨別離重。", "芳草漁家路，殘陽水寺鐘。落帆當此處，吟興不應慵。"]'),
('yuding-28','贈來鵬','李鹹用','唐','御定全唐诗','yuding','','[]','默坐非關悶，凝情只在詩。庭閑花落後，山靜月明時。',48,'御定全唐詩/json/645.json','["默坐非關悶，凝情只在詩。庭閑花落後，山靜月明時。", "答客言多簡，尋僧步稍遲。既同和氏璧，終有玉人知。"]'),
('yuding-29','途中作','李鹹用','唐','御定全唐诗','yuding','','[]','瘦馬倦行役，斜陽勸著鞭。野橋寒樹亞，山店暮雲連。',48,'御定全唐詩/json/645.json','["瘦馬倦行役，斜陽勸著鞭。野橋寒樹亞，山店暮雲連。", "退鷁風雖急，攀龍志已堅。路人休莫笑，百里有時賢。"]'),
('yuding-30','秋晚','李鹹用','唐','御定全唐诗','yuding','','[]','斜陽山雨外，秋色思無窮。柳葉飄幹翠，楓枝撼碎紅。',48,'御定全唐詩/json/645.json','["斜陽山雨外，秋色思無窮。柳葉飄幹翠，楓枝撼碎紅。", "鬢毛看似雪，生計尚如蓬。不及樵童樂，蒹葭一笛風。"]'),
('yuding-31','曉望','李鹹用','唐','御定全唐诗','yuding','','[]','露驚松上鶴，曉色動扶桑。碧浪催人老，紅輪照物忙。',48,'御定全唐詩/json/645.json','["露驚松上鶴，曉色動扶桑。碧浪催人老，紅輪照物忙。", "世情隨日變，利路與天長。好駕觥船去，陶陶入醉鄉。"]'),
('yuding-32','寄友生','李鹹用','唐','御定全唐诗','yuding','','[]','交情應不變，何事久離群。圓月思同步，寒泉憶共聞。',48,'御定全唐詩/json/645.json','["交情應不變，何事久離群。圓月思同步，寒泉憶共聞。", "雪霜松色在，風雨雁行分。每見人來說，窗前改舊文。"]'),
('yuding-33','江行','李鹹用','唐','御定全唐诗','yuding','','[]','瀟湘無事後，征棹複嘔啞。高岫留斜照，歸鴻背落霞。',48,'御定全唐詩/json/645.json','["瀟湘無事後，征棹複嘔啞。高岫留斜照，歸鴻背落霞。", "魚殘沙岸草，蝶寄洑流槎。共說干戈苦，汀洲減釣家。"]'),
('yuding-34','題王氏山居','李鹹用','唐','御定全唐诗','yuding','','[]','簷有煙嵐色，地多松竹風。自言離亂後，不到鼓鼙中。',48,'御定全唐詩/json/645.json','["簷有煙嵐色，地多松竹風。自言離亂後，不到鼓鼙中。", "徑柳拂雲綠，山櫻帶雪紅。南邊青嶂下，時見采芝翁。"]'),
('yuding-35','送別','李鹹用','唐','御定全唐诗','yuding','','[]','別意說難盡，離杯深莫辭。長歌終此席，一笑又何時。',48,'御定全唐詩/json/645.json','["別意說難盡，離杯深莫辭。長歌終此席，一笑又何時。", "棹入寒潭急，帆當落照遲。遠書如不寄，無以慰相思。"]'),
('yuding-36','覽文僧卷','李鹹用','唐','御定全唐诗','yuding','','[]','雖無先聖耳，異代得聞韶。怪石難為古，奇花不敢妖。',48,'御定全唐詩/json/645.json','["雖無先聖耳，異代得聞韶。怪石難為古，奇花不敢妖。", "調高非郢雪，思靜礙箕瓢。未可重吟過，雲山興轉饒。"]'),
('yuding-37','望仰山憶玄泰上人','李鹹用','唐','御定全唐诗','yuding','','[]','晴嵐凝片碧，知在此中禪。見面定何日，無書已一年。',48,'御定全唐詩/json/645.json','["晴嵐凝片碧，知在此中禪。見面定何日，無書已一年。", "高秋關靜夢，良夜入新篇。仰德心如是，清風不我傳。"]'),
('yuding-38','聞泉','李鹹用','唐','御定全唐诗','yuding','','[]','淅淅夢初驚，幽窗枕簟清。更無人共聽，只有月空明。',48,'御定全唐詩/json/645.json','["淅淅夢初驚，幽窗枕簟清。更無人共聽，只有月空明。", "急想穿岩曲，低應過石平。欲將琴強寫，不是自然聲。"]'),
('yuding-39','酬鄭進士九江新居見寄','李鹹用','唐','御定全唐诗','yuding','','[]','躡屐扣柴關，因成盡日閑。獨聽黃鳥語，深似白雲間。',48,'御定全唐詩/json/645.json','["躡屐扣柴關，因成盡日閑。獨聽黃鳥語，深似白雲間。", "萍沼寬于井，莎城綠當山。前期招我作，此景得吟還。"]'),
('yuding-40','九江和人贈陳生','李鹹用','唐','御定全唐诗','yuding','','[]','天畏斯文墜，憑君助素風。意深皆可補，句逸不因功。',48,'御定全唐詩/json/645.json','["天畏斯文墜，憑君助素風。意深皆可補，句逸不因功。", "暮替雲愁遠，秋驚月占空。寄家當瀑布，時得笑言同。"]'),
('yuding-41','登樓值雨二首','李鹹用','唐','御定全唐诗','yuding','','[]','共訝高樓望，匡廬色已空。白雲橫野闊，遮嶽與天同。',96,'御定全唐詩/json/645.json','["共訝高樓望，匡廬色已空。白雲橫野闊，遮嶽與天同。", "數點雨入酒，滿襟香在風。遠江吟得出，方下郡齋東。", "江徼多佳景，秋吟興未窮。送來松檻雨，半是蓼花風。", "浪猛驚翹鷺，煙昏叫斷鴻。不知今夜客，幾處臥鳴篷。"]'),
('yuding-42','送趙舒處士歸廬山','李鹹用','唐','御定全唐诗','yuding','','[]','歸岫香爐碧，行吟步益遲。諸侯師不得，樵客偶相隨。',48,'御定全唐詩/json/645.json','["歸岫香爐碧，行吟步益遲。諸侯師不得，樵客偶相隨。", "思舊江雲斷，談玄嶽月移。只應張野輩，異代作心知。"]'),
('yuding-43','僧院薔薇','李鹹用','唐','御定全唐诗','yuding','','[]','客引擎茶看，離披曬錦紅。不緣開淨域，爭忍負春風。',48,'御定全唐詩/json/645.json','["客引擎茶看，離披曬錦紅。不緣開淨域，爭忍負春風。", "小片當吟落，清香入定空。何人來此植，應固惱休公。"]'),
('yuding-44','友生攜修睦上人詩見訪','李鹹用','唐','御定全唐诗','yuding','','[]','雪中敲竹戶，袖出嶽僧詩。語盡景皆活，吟闌角獨吹。',48,'御定全唐詩/json/645.json','["雪中敲竹戶，袖出嶽僧詩。語盡景皆活，吟闌角獨吹。", "意如將俗背，業必少人知。共約冰銷日，雲邊訪所思。"]'),
('yuding-45','冬夕喜友生至','李鹹用','唐','御定全唐诗','yuding','','[]','天涯行欲遍，此夜故人情。鄉國別來久，干戈還未平。',48,'御定全唐詩/json/645.json','["天涯行欲遍，此夜故人情。鄉國別來久，干戈還未平。", "燈殘偏有焰，雪甚卻無聲。多少新聞見，應須語到明。"]'),
('yuding-46','牡丹','李鹹用','唐','御定全唐诗','yuding','','[]','少見南人識，識來嗟複驚。始知春有色，不信爾無情。',48,'御定全唐詩/json/645.json','["少見南人識，識來嗟複驚。始知春有色，不信爾無情。", "恐是天地媚，暫隨雲雨生。緣何絕尤物，更可比妍明。"]'),
('yuding-47','送春','李鹹用','唐','御定全唐诗','yuding','','[]','四時為第一，一歲一重來。好景應難勝，餘花虛自開。',48,'御定全唐詩/json/645.json','["四時為第一，一歲一重來。好景應難勝，餘花虛自開。", "相思九個月，得信數枝梅。不向東門送，還成負酒杯。"]'),
('yuding-48','送邊將','李咸用','唐','御定全唐诗','yuding','','[]','天驕頻犯塞，鐵騎又征西。臣節輕鄉土，雄心生鼓鼙。',48,'御定全唐詩/json/645.json','["天驕頻犯塞，鐵騎又征西。臣節輕鄉土，雄心生鼓鼙。", "地寒花不豔，沙遠日難低。漸喜秋弓健，雕翻白草齊。"]'),
('yuding-49','春晴','李鹹用','唐','御定全唐诗','yuding','','[]','簷滴春膏絕，憑欄晚吹生。良朋在何處，高樹忽流鶯。',48,'御定全唐詩/json/645.json','["簷滴春膏絕，憑欄晚吹生。良朋在何處，高樹忽流鶯。", "游寺期應定，尋芳步已輕。新詩吟未穩，遲日又西傾。"]'),
('yuding-50','冬夜與修睦上人宿遠公亭，寄南嶽玄泰禪師','李咸用','唐','御定全唐诗','yuding','','[]','丈室掩孤燈，更深霰雹增。相看雲夢客，共憶祝融僧。',48,'御定全唐詩/json/645.json','["丈室掩孤燈，更深霰雹增。相看雲夢客，共憶祝融僧。", "語合茶忘味，吟欹卷有棱。楚南山水秀，行止豈無憑。"]'),
('yuding-51','落花','李鹹用','唐','御定全唐诗','yuding','','[]','拾得移時看，重思造化功。如何飄麗景，不似遇春風。',48,'御定全唐詩/json/645.json','["拾得移時看，重思造化功。如何飄麗景，不似遇春風。", "滿地餘香在，繁枝一夜空。只應公子見，先憶墜樓紅。"]'),
('yuding-52','寄嵩陽隱者','李鹹用','唐','御定全唐诗','yuding','','[]','昔年江上別，初入亂離中。我住匡山北，君之少室東。',48,'御定全唐詩/json/645.json','["昔年江上別，初入亂離中。我住匡山北，君之少室東。", "信來經險道，詩半憶皇風。何事猶高臥，岩邊夢未通。"]'),
('yuding-53','早蟬','李鹹用','唐','御定全唐诗','yuding','','[]','門柳不連野，乍聞為早蟬。遊人無定處，入耳更應先。',48,'御定全唐詩/json/645.json','["門柳不連野，乍聞為早蟬。遊人無定處，入耳更應先。", "暫默斜陽雨，重吟遠岸煙。前年湘竹裏，風激繞離筵。"]'),
('yuding-54','酬蘊微','李咸用','唐','御定全唐诗','yuding','','[]','白衣經亂世，相遇一開顏。得句禪思外，論交野步間。',48,'御定全唐詩/json/645.json','["白衣經亂世，相遇一開顏。得句禪思外，論交野步間。", "舉朝無舊識，入眼只青山。幾度斜陽寺，訪君還獨還。"]'),
('yuding-55','萱草','李鹹用','唐','御定全唐诗','yuding','','[]','芳草比君子，詩人情有由。只應憐雅態，未必解忘憂。',48,'御定全唐詩/json/645.json','["芳草比君子，詩人情有由。只應憐雅態，未必解忘憂。", "積雨莎庭小，微風蘚砌幽。莫言開太晚，猶勝菊花秋。"]'),
('yuding-56','訪友人不遇','李鹹用','唐','御定全唐诗','yuding','','[]','出門無至友，動即到君家。空掩一庭竹，去看何寺花。',48,'御定全唐詩/json/645.json','["出門無至友，動即到君家。空掩一庭竹，去看何寺花。", "短僮應捧杖，稚女學擎茶。吟罷留題處，苔階日影斜。"]'),
('yuding-57','苔','李鹹用','唐','御定全唐诗','yuding','','[]','幾年風雨跡，疊在石孱顏。生處景長靜，看來情盡閑。',48,'御定全唐詩/json/645.json','["幾年風雨跡，疊在石孱顏。生處景長靜，看來情盡閑。", "吟亭侵壞壁，藥院掩空關。每憶東行徑，移筇獨自還。"]'),
('yuding-58','紅薇','李咸用','唐','御定全唐诗','yuding','','[]','春雨有五色，灑來花旋成。欲留池上景，別染草中英。',48,'御定全唐詩/json/645.json','["春雨有五色，灑來花旋成。欲留池上景，別染草中英。", "畫出看還欠，蓪為插未輕。王孫多好事，攜酒寄吟傾。"]'),
('yuding-59','別所知','李鹹用','唐','御定全唐诗','yuding','','[]','有路有西東，天涯自恨同。卻須深酌酒，況不比飄蓬。',48,'御定全唐詩/json/645.json','["有路有西東，天涯自恨同。卻須深酌酒，況不比飄蓬。", "帆冒新秋雨，鼓傳微浪風。閏牽寒氣早，何浦值賓鴻。"]'),
('yuding-60','小雪','李鹹用','唐','御定全唐诗','yuding','','[]','散漫陰風裏，天涯不可收。壓松猶未得，撲石暫能留。',48,'御定全唐詩/json/645.json','["散漫陰風裏，天涯不可收。壓松猶未得，撲石暫能留。", "閣靜縈吟思，途長拂旅愁。崆峒山北面，早想玉成丘。"]'),
('yuding-61','和修睦上人聽猿','李鹹用','唐','御定全唐诗','yuding','','[]','禪客聞猶苦，是聲應是啼。自然無穩夢，何必到巴溪。',48,'御定全唐詩/json/645.json','["禪客聞猶苦，是聲應是啼。自然無穩夢，何必到巴溪。", "疏雨灑不歇，回風吹暫低。此宵秋欲半，山在二林西。"]');
